"""
Parameterized generator for GH968_pymc_7637.

Source PR:    https://github.com/pymc-devs/pymc/pull/7637
Source Issue: https://github.com/pymc-devs/pymc/issues/7612

Seed varies: renames 'a_backward_fn' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH968_pymc_7637'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH968_pymc_7637'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('a_backward_fn', 'a_backward_fn' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH968_pymc_7637',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 7637,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/7637",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.pre-commit-config.yaml': 'ci:\n  autofix_prs: false\n\nexclude: ^(docs/logos|pymc/tests/data)/\nrepos:\n- repo: https://github.com/pre-commit/pre-commit-hooks\n  rev: v5.0.0\n  hooks:\n    -   id: check-merge-conflict\n    -   id: check-toml\n    -   id: check-yaml\n    -   id: debug-statements\n    -   id: end-of-file-fixer\n    -   id: no-commit-to-branch\n    -   id: requirements-txt-fixer\n        exclude: ^requirements-dev\\.txt$\n    -   id: trailing-whitespace\n- repo: https://github.com/pre-commit/pygrep-hooks\n  rev: v1.10.0\n  hooks:\n    - id: python-check-blanket-noqa\n    - id: python-check-blanket-type-ignore\n    - id: python-check-mock-methods\n    # - id: python-no-eval  # gets confused with all the `.eval()`\n    - id: python-no-log-warn\n    - id: python-use-type-annotations\n    - id: rst-backticks\n    - id: rst-directive-colons\n    - id: rst-inline-touching-normal\n    - id: text-unicode-replacement-char\n- repo: https://github.com/citation-file-format/cffconvert\n  rev: 054bda51dbe278b3e86f27c890e3f3ac877d616c\n  hooks:\n    - id: validate-cff\n- repo: https://github.com/sphinx-contrib/sphinx-lint\n  rev: v1.0.0\n  hooks:\n    - id: sphinx-lint\n      args: ["."]\n- repo: https://github.com/lucianopaz/head_of_apache\n  rev: "0.0.3"\n  hooks:\n    - id: head_of_apache\n      args:\n        - --author=The PyMC Developers\n        - --exclude=docs/\n        - --exclude=scripts/\n        - --exclude=binder/\n        - --exclude=versioneer.py\n- repo: https://github.com/astral-sh/ruff-pre-commit\n  rev: v0.8.4\n  hooks:\n    - id: ruff\n      args: [--fix, --show-fixes]\n    - id: ruff-format\n- repo: local\n  hooks:\n    - id: check-no-tests-are-ignored\n      additional_dependencies: [pandas,pyyaml]\n      entry: python scripts/check_all_tests_are_covered.py\n      files: ^.github/workflows/tests.yml$\n      language: python\n      name: Check no tests are ignored\n      pass_filenames: false\n    - id: pip-from-conda\n      additional_dependencies: [pyyaml]\n      entry: python scripts/generate_pip_deps_from_conda.py\n      files: ^conda-envs/environment-dev.yml$\n      language: python\n      name: Generate pip dependency from conda\n    - id: no-internal-links\n      name: Check no links that should be cross-references are in the docs\n      description: >-\n        \'A quick check for the links in the intersphinx \'\n        \'mapping inside `docs/source/`\'\n        \'See docs/source/conf.py for more information.\'\n      files: ^docs/source/\n      # Files that should be ignored:\n      # - index.md\n      # - 404.md\n      # - contributing/release_checklist.md\n      # The other files are under development and should be\n      # removed from the list once they are revised.\n      exclude: >\n          (?x)(index.md|\n               404.md|\n               contributing/release_checklist.md|\n               contributing/versioning_schemes_explanation.md|\n               learn/examples.md)\n      entry: >\n          (?x)(arviz-devs.github.io|\n               python.arviz.org|\n               pytensor.readthedocs.io|\n               pymc-experimental.readthedocs.io|\n               docs.pymc.io|\n               www.pymc.io|\n               numpy.org/doc|\n               pymc-examples.readthedocs.io|\n               myst-parser.readthedocs.io|\n               myst-nb.readthedocs.io|\n               docs.python.org|\n               xarray.pydata.org)\n      language: pygrep\n      types_or: [markdown, rst, jupyter]\n',
            'pymc/sampling/mcmc.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\n"""Functions for MCMC sampling."""\n\nimport contextlib\nimport logging\nimport pickle\nimport sys\nimport time\nimport warnings\n\nfrom collections.abc import Callable, Iterator, Mapping, Sequence\nfrom typing import (\n    Any,\n    Literal,\n    TypeAlias,\n    overload,\n)\n\nimport numpy as np\nimport pytensor.gradient as tg\n\nfrom arviz import InferenceData, dict_to_dataset\nfrom arviz.data.base import make_attrs\nfrom pytensor.graph.basic import Variable\nfrom rich.console import Console\nfrom rich.progress import BarColumn, TextColumn, TimeElapsedColumn, TimeRemainingColumn\nfrom rich.theme import Theme\nfrom threadpoolctl import threadpool_limits\nfrom typing_extensions import Protocol\n\nimport pymc as pm\n\nfrom pymc.backends import RunType, TraceOrBackend, init_traces\nfrom pymc.backends.arviz import (\n    coords_and_dims_for_inferencedata,\n    find_constants,\n    find_observations,\n)\nfrom pymc.backends.base import IBaseTrace, MultiTrace, _choose_chains\nfrom pymc.blocking import DictToArrayBijection\nfrom pymc.exceptions import SamplingError\nfrom pymc.initial_point import PointType, StartDict, make_initial_point_fns_per_chain\nfrom pymc.model import Model, modelcontext\nfrom pymc.sampling.parallel import Draw, _cpu_count\nfrom pymc.sampling.population import _sample_population\nfrom pymc.stats.convergence import (\n    log_warning_stats,\n    log_warnings,\n    run_convergence_checks,\n)\nfrom pymc.step_methods import NUTS, CompoundStep\nfrom pymc.step_methods.arraystep import BlockedStep, PopulationArrayStepShared\nfrom pymc.step_methods.hmc import quadpotential\nfrom pymc.util import (\n    CustomProgress,\n    RandomSeed,\n    RandomState,\n    _get_seeds_per_chain,\n    default_progress_theme,\n    drop_warning_stat,\n    get_random_generator,\n    get_untransformed_name,\n    is_transformed_name,\n)\nfrom pymc.vartypes import discrete_types\n\nsys.setrecursionlimit(10000)\n\n__all__ = [\n    "init_nuts",\n    "sample",\n]\n\nStep: TypeAlias = BlockedStep | CompoundStep\n\n\nclass SamplingIteratorCallback(Protocol):\n    """Signature of the callable that may be passed to `pm.sample(callable=...)`."""\n\n    def __call__(self, trace: IBaseTrace, draw: Draw):\n        pass\n\n\n_log = logging.getLogger(__name__)\n\n\ndef instantiate_steppers(\n    model: Model,\n    steps: list[Step],\n    selected_steps: Mapping[type[BlockedStep], list[Any]],\n    *,\n    step_kwargs: dict[str, dict] | None = None,\n    initial_point: PointType | None = None,\n    compile_kwargs: dict | None = None,\n) -> Step | list[Step]:\n    """Instantiate steppers assigned to the model variables.\n\n    This function is intended to be called automatically from ``sample()``, but\n    may be called manually.\n\n    Parameters\n    ----------\n    model : Model object\n        A fully-specified model object.\n    steps : list, array_like of shape (selected_steps, )\n        A list of zero or more step function instances that have been assigned to some subset of\n        the model\'s parameters.\n    selected_steps : dict\n        A dictionary that maps a step method class to a list of zero or more model variables.\n    step_kwargs : dict, default=None\n        Parameters for the samplers. Keys are the lower case names of\n        the step method, values a dict of arguments. Defaults to None.\n\n    Returns\n    -------\n    methods : list or step\n        List of step methods associated with the model\'s variables, or step method\n        if there is only one.\n    """\n    if step_kwargs is None:\n        step_kwargs = {}\n\n    used_keys = set()\n    if selected_steps:\n        if initial_point is None:\n            initial_point = model.initial_point()\n\n        for step_class, vars in selected_steps.items():\n            if vars:\n                name = getattr(step_class, "name")\n                kwargs = step_kwargs.get(name, {})\n                used_keys.add(name)\n                step = step_class(\n                    vars=vars,\n                    model=model,\n                    initial_point=initial_point,\n                    compile_kwargs=compile_kwargs,\n                    **kwargs,\n                )\n                steps.append(step)\n\n    unused_args = set(step_kwargs).difference(used_keys)\n    if unused_args:\n        s = "s" if len(unused_args) > 1 else ""\n        example_arg = sorted(unused_args)[0]\n        example_step = (list(selected_steps.keys()) or pm.STEP_METHODS)[0]\n        example_step_name = getattr(example_step, "name")\n        raise ValueError(\n            f"Invalid key{s} found in step_kwargs: {unused_args}. "\n            "Keys must be step names and values valid kwargs for that stepper. "\n            f\'Did you mean {{"{example_step_name}": {{"{example_arg}": ...}}}}?\'\n        )\n\n    if len(steps) == 1:\n        return steps[0]\n\n    return steps\n\n\ndef assign_step_methods(\n    model: Model,\n    step: Step | Sequence[Step] | None = None,\n    methods: Sequence[type[BlockedStep]] | None = None,\n) -> tuple[list[Step], dict[type[BlockedStep], list[Variable]]]:\n    """Assign model variables to appropriate step methods.\n\n    Passing a specified model will auto-assign its constituent value\n    variables to step methods based on the characteristics of the respective\n    random variables, and whether the logp can be differentiated with respect to it.\n\n    This function is intended to be called automatically from ``sample()``, but\n    may be called manually. Each step method passed should have a\n    ``competence()`` method that returns an ordinal competence value\n    corresponding to the variable passed to it. This value quantifies the\n    appropriateness of the step method for sampling the variable.\n\n    The outputs of this function can then be passed to `instantiate_steppers()`\n    to initialize the assigned step samplers.\n\n    Parameters\n    ----------\n    model : Model object\n        A fully-specified model object.\n    step : step function or iterable of step functions, optional\n        One or more step functions that have been assigned to some subset of\n        the model\'s parameters. Defaults to ``None`` (no assigned variables).\n    methods : iterable of step method classes, optional\n        The set of step methods from which the function may choose. Defaults\n        to the main step methods provided by PyMC.\n\n    Returns\n    -------\n    provided_steps: list of Step instances\n        List of user provided instantiated step(s)\n    assigned_steps: dict of Step class to Variable\n        Dictionary with automatically selected step classes as keys and associated value variables as values\n    """\n    provided_steps: list[Step] = []\n    assigned_vars: set[Variable] = set()\n\n    if step is not None:\n        if isinstance(step, BlockedStep | CompoundStep):\n            provided_steps = [step]\n        elif isinstance(step, Sequence):\n            provided_steps = list(step)\n        else:\n            raise ValueError(f"Step should be a Step or a sequence of Steps, got {step}")\n\n        for step in provided_steps:\n            if not isinstance(step, BlockedStep | CompoundStep):\n                if issubclass(step, BlockedStep | CompoundStep):\n                    raise ValueError(f"Provided {step} was not initialized")\n                else:\n                    raise ValueError(f"{step} is not a Step instance")\n\n            for var in step.vars:\n                if var not in model.value_vars:\n                    raise ValueError(\n                        f"{var} assigned to {step} sampler is not a value variable in the model. "\n                        "You can use `util.get_value_vars_from_user_vars` to parse user provided variables."\n                    )\n            assigned_vars = assigned_vars.union(set(step.vars))\n\n    # Use competence classmethods to select step methods for remaining\n    # variables\n    methods_list: list[type[BlockedStep]] = list(methods or pm.STEP_METHODS)\n    selected_steps: dict[type[BlockedStep], list] = {}\n    model_logp = model.logp()\n\n    for var in model.value_vars:\n        if var not in assigned_vars:\n            # determine if a gradient can be computed\n            has_gradient = getattr(var, "dtype") not in discrete_types\n            if has_gradient:\n                try:\n                    tg.grad(model_logp, var)  # type: ignore[arg-type]\n                except (NotImplementedError, tg.NullTypeGradError):\n                    has_gradient = False\n\n            # select the best method\n            rv_var = model.values_to_rvs[var]\n            selected = max(\n                methods_list,\n                key=lambda method, var=rv_var, has_gradient=has_gradient: method._competence(  # type: ignore[misc]\n                    var, has_gradient\n                ),\n            )\n            selected_steps.setdefault(selected, []).append(var)\n\n    return provided_steps, selected_steps\n\n\ndef _print_step_hierarchy(s: Step, level: int = 0) -> None:\n    if isinstance(s, CompoundStep):\n        _log.info(">" * level + "CompoundStep")\n        for i in s.methods:\n            _print_step_hierarchy(i, level + 1)\n    else:\n        varnames = ", ".join(\n            [\n                get_untransformed_name(v.name) if is_transformed_name(v.name) else v.name\n                for v in s.vars\n            ]\n        )\n        _log.info(">" * level + f"{s.__class__.__name__}: [{varnames}]")\n\n\ndef all_continuous(vars):\n    """Check that vars not include discrete variables."""\n    if any((var.dtype in discrete_types) for var in vars):\n        return False\n    else:\n        return True\n\n\ndef _sample_external_nuts(\n    sampler: Literal["nutpie", "numpyro", "blackjax"],\n    draws: int,\n    tune: int,\n    chains: int,\n    target_accept: float,\n    random_seed: RandomState | None,\n    initvals: StartDict | Sequence[StartDict | None] | None,\n    model: Model,\n    var_names: Sequence[str] | None,\n    progressbar: bool,\n    idata_kwargs: dict | None,\n    compute_convergence_checks: bool,\n    nuts_sampler_kwargs: dict | None,\n    **kwargs,\n):\n    if nuts_sampler_kwargs is None:\n        nuts_sampler_kwargs = {}\n\n    if sampler == "nutpie":\n        try:\n            import nutpie\n        except ImportError as err:\n            raise ImportError(\n                "nutpie not found. Install it with conda install -c conda-forge nutpie"\n            ) from err\n\n        if initvals is not None:\n            warnings.warn(\n                "`initvals` are currently not passed to nutpie sampler. "\n                "Use `init_mean` kwarg following nutpie specification instead.",\n                UserWarning,\n            )\n\n        if idata_kwargs is not None:\n            warnings.warn(\n                "`idata_kwargs` are currently ignored by the nutpie sampler",\n                UserWarning,\n            )\n        if var_names is not None:\n            warnings.warn(\n                "`var_names` are currently ignored by the nutpie sampler",\n                UserWarning,\n            )\n        compile_kwargs = {}\n        for kwarg in ("backend", "gradient_backend"):\n            if kwarg in nuts_sampler_kwargs:\n                compile_kwargs[kwarg] = nuts_sampler_kwargs.pop(kwarg)\n        compiled_model = nutpie.compile_pymc_model(\n            model,\n            **compile_kwargs,\n        )\n        t_start = time.time()\n        idata = nutpie.sample(\n            compiled_model,\n            draws=draws,\n            tune=tune,\n            chains=chains,\n            target_accept=target_accept,\n            seed=_get_seeds_per_chain(random_seed, 1)[0],\n            progress_bar=progressbar,\n            **nuts_sampler_kwargs,\n        )\n        t_sample = time.time() - t_start\n        # Temporary work-around. Revert once https://github.com/pymc-devs/nutpie/issues/74 is fixed\n        # gather observed and constant data as nutpie.sample() has no access to the PyMC model\n        coords, dims = coords_and_dims_for_inferencedata(model)\n        constant_data = dict_to_dataset(\n            find_constants(model),\n            library=pm,\n            coords=coords,\n            dims=dims,\n            default_dims=[],\n        )\n        observed_data = dict_to_dataset(\n            find_observations(model),\n            library=pm,\n            coords=coords,\n            dims=dims,\n            default_dims=[],\n        )\n        attrs = make_attrs(\n            {\n                "sampling_time": t_sample,\n                "tuning_steps": tune,\n            },\n            library=nutpie,\n        )\n        for k, v in attrs.items():\n            idata.posterior.attrs[k] = v\n        idata.add_groups(\n            {"constant_data": constant_data, "observed_data": observed_data},\n            coords=coords,\n            dims=dims,\n        )\n        return idata\n\n    elif sampler in ("numpyro", "blackjax"):\n        import pymc.sampling.jax as pymc_jax\n\n        idata = pymc_jax.sample_jax_nuts(\n            draws=draws,\n            tune=tune,\n            chains=chains,\n            target_accept=target_accept,\n            random_seed=random_seed,\n            initvals=initvals,\n            model=model,\n            var_names=var_names,\n            progressbar=progressbar,\n            nuts_sampler=sampler,\n            idata_kwargs=idata_kwargs,\n            compute_convergence_checks=compute_convergence_checks,\n            **nuts_sampler_kwargs,\n        )\n        return idata\n\n    else:\n        raise ValueError(\n            f"Sampler {sampler} not found. Choose one of [\'nutpie\', \'numpyro\', \'blackjax\', \'pymc\']."\n        )\n\n\n@overload\ndef sample(\n    draws: int = 1000,\n    *,\n    tune: int = 1000,\n    chains: int | None = None,\n    cores: int | None = None,\n    random_seed: RandomState = None,\n    progressbar: bool = True,\n    progressbar_theme: Theme | None = default_progress_theme,\n    step=None,\n    var_names: Sequence[str] | None = None,\n    nuts_sampler: Literal["pymc", "nutpie", "numpyro", "blackjax"] = "pymc",\n    initvals: StartDict | Sequence[StartDict | None] | None = None,\n    init: str = "auto",\n    jitter_max_retries: int = 10,\n    n_init: int = 200_000,\n    trace: TraceOrBackend | None = None,\n    discard_tuned_samples: bool = True,\n    compute_convergence_checks: bool = True,\n    keep_warning_stat: bool = False,\n    return_inferencedata: Literal[True] = True,\n    idata_kwargs: dict[str, Any] | None = None,\n    nuts_sampler_kwargs: dict[str, Any] | None = None,\n    callback=None,\n    mp_ctx=None,\n    blas_cores: int | None | Literal["auto"] = "auto",\n    compile_kwargs: dict | None = None,\n    **kwargs,\n) -> InferenceData: ...\n\n\n@overload\ndef sample(\n    draws: int = 1000,\n    *,\n    tune: int = 1000,\n    chains: int | None = None,\n    cores: int | None = None,\n    random_seed: RandomState = None,\n    progressbar: bool = True,\n    progressbar_theme: Theme | None = default_progress_theme,\n    step=None,\n    var_names: Sequence[str] | None = None,\n    nuts_sampler: Literal["pymc", "nutpie", "numpyro", "blackjax"] = "pymc",\n    initvals: StartDict | Sequence[StartDict | None] | None = None,\n    init: str = "auto",\n    jitter_max_retries: int = 10,\n    n_init: int = 200_000,\n    trace: TraceOrBackend | None = None,\n    discard_tuned_samples: bool = True,\n    compute_convergence_checks: bool = True,\n    keep_warning_stat: bool = False,\n    return_inferencedata: Literal[False],\n    idata_kwargs: dict[str, Any] | None = None,\n    nuts_sampler_kwargs: dict[str, Any] | None = None,\n    callback=None,\n    mp_ctx=None,\n    model: Model | None = None,\n    blas_cores: int | None | Literal["auto"] = "auto",\n    compile_kwargs: dict | None = None,\n    **kwargs,\n) -> MultiTrace: ...\n\n\ndef sample(\n    draws: int = 1000,\n    *,\n    tune: int = 1000,\n    chains: int | None = None,\n    cores: int | None = None,\n    random_seed: RandomState = None,\n    progressbar: bool = True,\n    progressbar_theme: Theme | None = default_progress_theme,\n    step=None,\n    var_names: Sequence[str] | None = None,\n    nuts_sampler: Literal["pymc", "nutpie", "numpyro", "blackjax"] = "pymc",\n    initvals: StartDict | Sequence[StartDict | None] | None = None,\n    init: str = "auto",\n    jitter_max_retries: int = 10,\n    n_init: int = 200_000,\n    trace: TraceOrBackend | None = None,\n    discard_tuned_samples: bool = True,\n    compute_convergence_checks: bool = True,\n    keep_warning_stat: bool = False,\n    return_inferencedata: bool = True,\n    idata_kwargs: dict[str, Any] | None = None,\n    nuts_sampler_kwargs: dict[str, Any] | None = None,\n    callback=None,\n    mp_ctx=None,\n    blas_cores: int | None | Literal["auto"] = "auto",\n    model: Model | None = None,\n    compile_kwargs: dict | None = None,\n    **kwargs,\n) -> InferenceData | MultiTrace:\n    r"""Draw samples from the posterior using the given step methods.\n\n    Multiple step methods are supported via compound step methods.\n\n    Parameters\n    ----------\n    draws : int\n        The number of samples to draw. Defaults to 1000. The number of tuned samples are discarded\n        by default. See ``discard_tuned_samples``.\n    tune : int\n        Number of iterations to tune, defaults to 1000. Samplers adjust the step sizes, scalings or\n        similar during tuning. Tuning samples will be drawn in addition to the number specified in\n        the ``draws`` argument, and will be discarded unless ``discard_tuned_samples`` is set to\n        False.\n    chains : int\n        The number of chains to sample. Running independent chains is important for some\n        convergence statistics and can also reveal multiple modes in the posterior. If ``None``,\n        then set to either ``cores`` or 2, whichever is larger.\n    cores : int\n        The number of chains to run in parallel. If ``None``, set to the number of CPUs in the\n        system, but at most 4.\n    random_seed : int, array-like of int, or Generator, optional\n        Random seed(s) used by the sampling steps. Each step will create its own\n        :py:class:`~numpy.random.Generator` object to make its random draws in a way that is\n        indepedent from all other steppers and all other chains.\n        A ``TypeError`` will be raised if a legacy :py:class:`~numpy.random.RandomState` object is passed.\n        We no longer support ``RandomState`` objects because their seeding mechanism does not allow\n        easy spawning of new independent random streams that are needed by the step methods.\n    progressbar : bool, optional default=True\n        Whether or not to display a progress bar in the command line. The bar shows the percentage\n        of completion, the sampling speed in samples per second (SPS), and the estimated remaining\n        time until completion ("expected time of arrival"; ETA).\n        Only applicable to the pymc nuts sampler.\n    step : function or iterable of functions\n        A step function or collection of functions. If there are variables without step methods,\n        step methods for those variables will be assigned automatically. By default the NUTS step\n        method will be used, if appropriate to the model.\n    var_names : list of str, optional\n        Names of variables to be stored in the trace. Defaults to all free variables and deterministics.\n    nuts_sampler : str\n        Which NUTS implementation to run. One of ["pymc", "nutpie", "blackjax", "numpyro"].\n        This requires the chosen sampler to be installed.\n        All samplers, except "pymc", require the full model to be continuous.\n    blas_cores: int or "auto" or None, default = "auto"\n        The total number of threads blas and openmp functions should use during sampling.\n        Setting it to "auto" will ensure that the total number of active blas threads is the\n        same as the `cores` argument. If set to an integer, the sampler will try to use that total\n        number of blas threads. If `blas_cores` is not divisible by `cores`, it might get rounded\n        down. If set to None, this will keep the default behavior of whatever blas implementation\n        is used at runtime.\n    initvals : optional, dict, array of dict\n        Dict or list of dicts with initial value strategies to use instead of the defaults from\n        `Model.initial_values`. The keys should be names of transformed random variables.\n        Initialization methods for NUTS (see ``init`` keyword) can overwrite the default.\n    init : str\n        Initialization method to use for auto-assigned NUTS samplers. See `pm.init_nuts` for a list\n        of all options. This argument is ignored when manually passing the NUTS step method.\n        Only applicable to the pymc nuts sampler.\n    jitter_max_retries : int\n        Maximum number of repeated attempts (per chain) at creating an initial matrix with uniform\n        jitter that yields a finite probability. This applies to ``jitter+adapt_diag`` and\n        ``jitter+adapt_full`` init methods.\n    n_init : int\n        Number of iterations of initializer. Only works for \'ADVI\' init methods.\n    trace : backend, optional\n        A backend instance or None.\n        If None, the NDArray backend is used.\n    discard_tuned_samples : bool\n        Whether to discard posterior samples of the tune interval.\n    compute_convergence_checks : bool, default=True\n        Whether to compute sampler statistics like Gelman-Rubin and ``effective_n``.\n    keep_warning_stat : bool\n        If ``True`` the "warning" stat emitted by, for example, HMC samplers will be kept\n        in the returned ``idata.sample_stats`` group.\n        This leads to the ``idata`` not supporting ``.to_netcdf()`` or ``.to_zarr()`` and\n        should only be set to ``True`` if you intend to use the "warning" objects right away.\n        Defaults to ``False`` such that ``pm.drop_warning_stat`` is applied automatically,\n        making the ``InferenceData`` compatible with saving.\n    return_inferencedata : bool\n        Whether to return the trace as an :class:`arviz:arviz.InferenceData` (True) object or a\n        `MultiTrace` (False). Defaults to `True`.\n    idata_kwargs : dict, optional\n        Keyword arguments for :func:`pymc.to_inference_data`\n    nuts_sampler_kwargs : dict, optional\n        Keyword arguments for the sampling library that implements nuts.\n        Only used when an external sampler is specified via the `nuts_sampler` kwarg.\n    callback : function, default=None\n        A function which gets called for every sample from the trace of a chain. The function is\n        called with the trace and the current draw and will contain all samples for a single trace.\n        the ``draw.chain`` argument can be used to determine which of the active chains the sample\n        is drawn from.\n        Sampling can be interrupted by throwing a ``KeyboardInterrupt`` in the callback.\n    mp_ctx : multiprocessing.context.BaseContent\n        A multiprocessing context for parallel sampling.\n        See multiprocessing documentation for details.\n    model : Model (optional if in ``with`` context)\n        Model to sample from. The model needs to have free random variables.\n    compile_kwargs: dict, optional\n        Dictionary with keyword argument to pass to the functions compiled by the step methods.\n\n\n    Returns\n    -------\n    trace : pymc.backends.base.MultiTrace or arviz.InferenceData\n        A ``MultiTrace`` or ArviZ ``InferenceData`` object that contains the samples.\n\n    Notes\n    -----\n    Optional keyword arguments can be passed to ``sample`` to be delivered to the\n    ``step_method``\\ s used during sampling.\n\n    For example:\n\n       1. ``target_accept`` to NUTS: nuts={\'target_accept\':0.9}\n       2. ``transit_p`` to BinaryGibbsMetropolis: binary_gibbs_metropolis={\'transit_p\':.7}\n\n    Note that available step names are:\n\n    ``nuts``, ``hmc``, ``metropolis``, ``binary_metropolis``,\n    ``binary_gibbs_metropolis``, ``categorical_gibbs_metropolis``,\n    ``DEMetropolis``, ``DEMetropolisZ``, ``slice``\n\n    The NUTS step method has several options including:\n\n        * target_accept : float in [0, 1]. The step size is tuned such that we\n          approximate this acceptance rate. Higher values like 0.9 or 0.95 often\n          work better for problematic posteriors. This argument can be passed directly to sample.\n        * max_treedepth : The maximum depth of the trajectory tree\n        * step_scale : float, default 0.25\n          The initial guess for the step size scaled down by :math:`1/n**(1/4)`,\n          where n is the dimensionality of the parameter space\n\n    Alternatively, if you manually declare the ``step_method``\\ s, within the ``step``\n       kwarg, then you can address the ``step_method`` kwargs directly.\n       e.g. for a CompoundStep comprising NUTS and BinaryGibbsMetropolis,\n       you could send ::\n\n        step = [\n            pm.NUTS([freeRV1, freeRV2], target_accept=0.9),\n            pm.BinaryGibbsMetropolis([freeRV3], transit_p=0.7),\n        ]\n\n    You can find a full list of arguments in the docstring of the step methods.\n\n    Examples\n    --------\n    .. code:: ipython\n\n        In [1]: import pymc as pm\n           ...: n = 100\n           ...: h = 61\n           ...: alpha = 2\n           ...: beta = 2\n\n        In [2]: with pm.Model() as model: # context management\n           ...:     p = pm.Beta("p", alpha=alpha, beta=beta)\n           ...:     y = pm.Binomial("y", n=n, p=p, observed=h)\n           ...:     idata = pm.sample()\n\n        In [3]: az.summary(idata, kind="stats")\n\n        Out[3]:\n            mean     sd  hdi_3%  hdi_97%\n        p  0.609  0.047   0.528    0.699\n    """\n    if "start" in kwargs:\n        if initvals is not None:\n            raise ValueError("Passing both `start` and `initvals` is not supported.")\n        warnings.warn(\n            "The `start` kwarg was renamed to `initvals` and can now do more. Please check the docstring.",\n            FutureWarning,\n            stacklevel=2,\n        )\n        initvals = kwargs.pop("start")\n    if nuts_sampler_kwargs is None:\n        nuts_sampler_kwargs = {}\n    if "target_accept" in kwargs:\n        if "nuts" in kwargs and "target_accept" in kwargs["nuts"]:\n            raise ValueError(\n                "`target_accept` was defined twice. Please specify it either as a direct keyword argument or in the `nuts` kwarg."\n            )\n        if "nuts" in kwargs:\n            kwargs["nuts"]["target_accept"] = kwargs.pop("target_accept")\n        else:\n            kwargs["nuts"] = {"target_accept": kwargs.pop("target_accept")}\n    if isinstance(trace, list):\n        raise ValueError("Please use `var_names` keyword argument for partial traces.")\n\n    model = modelcontext(model)\n    if not model.free_RVs:\n        raise SamplingError(\n            "Cannot sample from the model, since the model does not contain any free variables."\n        )\n\n    if cores is None:\n        cores = min(4, _cpu_count())\n\n    if chains is None:\n        chains = max(2, cores)\n\n    if blas_cores == "auto":\n        blas_cores = cores\n\n    cores = min(cores, chains)\n\n    num_blas_cores_per_chain: int | None\n    joined_blas_limiter: Callable[[], Any]\n\n    if blas_cores is None:\n        joined_blas_limiter = contextlib.nullcontext\n        num_blas_cores_per_chain = None\n    elif isinstance(blas_cores, int):\n\n        def joined_blas_limiter():\n            return threadpool_limits(limits=blas_cores)\n\n        num_blas_cores_per_chain = blas_cores // cores\n    else:\n        raise ValueError(\n            f"Invalid argument `blas_cores`, must be int, \'auto\' or None: {blas_cores}"\n        )\n\n    if random_seed == -1:\n        warnings.warn(\n            "Setting random_seed = -1 is deprecated. Pass `None` to not specify a seed.",\n            FutureWarning,\n        )\n        random_seed = None\n    elif isinstance(random_seed, tuple | list):\n        warnings.warn(\n            "A list or tuple of random_seed no longer specifies the specific random_seed of each chain. "\n            "Use a single seed instead.",\n            UserWarning,\n        )\n    rngs = get_random_generator(random_seed).spawn(chains)\n    random_seed_list = [rng.integers(2**30) for rng in rngs]\n\n    if not discard_tuned_samples and not return_inferencedata:\n        warnings.warn(\n            "Tuning samples will be included in the returned `MultiTrace` object, which can lead to"\n            " complications in your downstream analysis. Please consider to switch to `InferenceData`:\\n"\n            "`pm.sample(..., return_inferencedata=True)`",\n            UserWarning,\n            stacklevel=2,\n        )\n\n    # small trace warning\n    if draws == 0:\n        msg = "Tuning was enabled throughout the whole trace."\n        _log.warning(msg)\n    elif draws < 100:\n        msg = f"Only {draws} samples per chain. Reliable r-hat and ESS diagnostics require longer chains for accurate estimate."\n        _log.warning(msg)\n\n    provided_steps, selected_steps = assign_step_methods(model, step, methods=pm.STEP_METHODS)\n    exclusive_nuts = (\n        # User provided an instantiated NUTS step, and nothing else is needed\n        (not selected_steps and len(provided_steps) == 1 and isinstance(provided_steps[0], NUTS))\n        or\n        # Only automatically selected NUTS step is needed\n        (\n            not provided_steps\n            and len(selected_steps) == 1\n            and issubclass(next(iter(selected_steps)), NUTS)\n        )\n    )\n\n    if nuts_sampler != "pymc":\n        if not exclusive_nuts:\n            raise ValueError(\n                "Model can not be sampled with NUTS alone. It either has discrete variables or a non-differentiable log-probability."\n            )\n\n        with joined_blas_limiter():\n            return _sample_external_nuts(\n                sampler=nuts_sampler,\n                draws=draws,\n                tune=tune,\n                chains=chains,\n                target_accept=kwargs.pop("nuts", {}).get("target_accept", 0.8),\n                random_seed=random_seed,\n                initvals=initvals,\n                model=model,\n                var_names=var_names,\n                progressbar=progressbar,\n                idata_kwargs=idata_kwargs,\n                compute_convergence_checks=compute_convergence_checks,\n                nuts_sampler_kwargs=nuts_sampler_kwargs,\n                **kwargs,\n            )\n\n    if exclusive_nuts and not provided_steps:\n        # Special path for NUTS initialization\n        if "nuts" in kwargs:\n            nuts_kwargs = kwargs.pop("nuts")\n            [kwargs.setdefault(k, v) for k, v in nuts_kwargs.items()]\n        with joined_blas_limiter():\n            initial_points, step = init_nuts(\n                init=init,\n                chains=chains,\n                n_init=n_init,\n                model=model,\n                random_seed=random_seed_list,\n                progressbar=progressbar,\n                jitter_max_retries=jitter_max_retries,\n                tune=tune,\n                initvals=initvals,\n                compile_kwargs=compile_kwargs,\n                **kwargs,\n            )\n    else:\n        # Get initial points\n        ipfns = make_initial_point_fns_per_chain(\n            model=model,\n            overrides=initvals,\n            jitter_rvs=set(),\n            chains=chains,\n        )\n        initial_points = [ipfn(seed) for ipfn, seed in zip(ipfns, random_seed_list)]\n\n        # Instantiate automatically selected steps\n        step = instantiate_steppers(\n            model,\n            steps=provided_steps,\n            selected_steps=selected_steps,\n            step_kwargs=kwargs,\n            initial_point=initial_points[0],\n            compile_kwargs=compile_kwargs,\n        )\n        if isinstance(step, list):\n            step = CompoundStep(step)\n\n    if var_names is not None:\n        trace_vars = [v for v in model.unobserved_RVs if v.name in var_names]\n        trace_vars = model.replace_rvs_by_values(trace_vars)\n        assert len(trace_vars) == len(var_names), "Not all var_names were found in the model"\n    else:\n        trace_vars = None\n\n    # Create trace backends for each chain\n    run, traces = init_traces(\n        backend=trace,\n        chains=chains,\n        expected_length=draws + tune,\n        step=step,\n        trace_vars=trace_vars,\n        initial_point=initial_points[0],\n        model=model,\n    )\n\n    sample_args = {\n        # draws is now the total number of draws, including tuning\n        "draws": draws + tune,\n        "step": step,\n        "start": initial_points,\n        "traces": traces,\n        "chains": chains,\n        "tune": tune,\n        "var_names": var_names,\n        "progressbar": progressbar,\n        "progressbar_theme": progressbar_theme,\n        "model": model,\n        "cores": cores,\n        "callback": callback,\n        "discard_tuned_samples": discard_tuned_samples,\n    }\n    parallel_args = {\n        "mp_ctx": mp_ctx,\n        "blas_cores": num_blas_cores_per_chain,\n    }\n\n    sample_args.update(kwargs)\n\n    has_population_samplers = np.any(\n        [\n            isinstance(m, PopulationArrayStepShared)\n            for m in (step.methods if isinstance(step, CompoundStep) else [step])\n        ]\n    )\n\n    parallel = cores > 1 and chains > 1 and not has_population_samplers\n    # At some point it was decided that PyMC should not set a global seed by default,\n    # unless the user specified a seed. This is a symptom of the fact that PyMC samplers\n    # are built around global seeding. This branch makes sure we maintain this unspoken\n    # rule. See https://github.com/pymc-devs/pymc/pull/1395.\n    if parallel:\n        # For parallel sampling we can pass the list of random seeds directly, as\n        # global seeding will only be called inside each process\n        sample_args["rngs"] = rngs\n    else:\n        # We pass None if the original random seed was None. The single core sampler\n        # methods will only set a global seed when it is not None.\n        sample_args["rngs"] = rngs\n\n    t_start = time.time()\n    if parallel:\n        _log.info(f"Multiprocess sampling ({chains} chains in {cores} jobs)")\n        _print_step_hierarchy(step)\n        try:\n            _mp_sample(**sample_args, **parallel_args)\n        except pickle.PickleError:\n            _log.warning("Could not pickle model, sampling singlethreaded.")\n            _log.debug("Pickling error:", exc_info=True)\n            parallel = False\n        except AttributeError as e:\n            if not str(e).startswith("AttributeError: Can\'t pickle"):\n                raise\n            _log.warning("Could not pickle model, sampling singlethreaded.")\n            _log.debug("Pickling error:", exc_info=True)\n            parallel = False\n    if not parallel:\n        if has_population_samplers:\n            _log.info(f"Population sampling ({chains} chains)")\n            _print_step_hierarchy(step)\n            with joined_blas_limiter():\n                _sample_population(\n                    initial_points=initial_points, parallelize=cores > 1, **sample_args\n                )\n        else:\n            _log.info(f"Sequential sampling ({chains} chains in 1 job)")\n            _print_step_hierarchy(step)\n            with joined_blas_limiter():\n                _sample_many(**sample_args)\n\n    t_sampling = time.time() - t_start\n\n    # Packaging, validating and returning the result was extracted\n    # into a function to make it easier to test and refactor.\n    return _sample_return(\n        run=run,\n        traces=traces,\n        tune=tune,\n        t_sampling=t_sampling,\n        discard_tuned_samples=discard_tuned_samples,\n        compute_convergence_checks=compute_convergence_checks,\n        return_inferencedata=return_inferencedata,\n        keep_warning_stat=keep_warning_stat,\n        idata_kwargs=idata_kwargs or {},\n        model=model,\n    )\n\n\ndef _sample_return(\n    *,\n    run: RunType | None,\n    traces: Sequence[IBaseTrace],\n    tune: int,\n    t_sampling: float,\n    discard_tuned_samples: bool,\n    compute_convergence_checks: bool,\n    return_inferencedata: bool,\n    keep_warning_stat: bool,\n    idata_kwargs: dict[str, Any],\n    model: Model,\n) -> InferenceData | MultiTrace:\n    """Pick/slice chains, run diagnostics and convert to the desired return type.\n\n    Final step of `pm.sampler`.\n    """\n    # Pick and slice chains to keep the maximum number of samples\n    if discard_tuned_samples:\n        traces, length = _choose_chains(traces, tune)\n    else:\n        traces, length = _choose_chains(traces, 0)\n    mtrace = MultiTrace(traces)[:length]\n\n    # count the number of tune/draw iterations that happened\n    # ideally via the "tune" statistic, but not all samplers record it!\n    if "tune" in mtrace.stat_names:\n        # Get the tune stat directly from chain 0, sampler 0\n        stat = mtrace._straces[0].get_sampler_stats("tune", sampler_idx=0)\n        stat = tuple(stat)\n        n_tune = stat.count(True)\n        n_draws = stat.count(False)\n    else:\n        # these may be wrong when KeyboardInterrupt happened, but they\'re better than nothing\n        n_tune = min(tune, len(mtrace))\n        n_draws = max(0, len(mtrace) - n_tune)\n\n    if discard_tuned_samples:\n        mtrace = mtrace[n_tune:]\n\n    # save metadata in SamplerReport\n    mtrace.report._n_tune = n_tune\n    mtrace.report._n_draws = n_draws\n    mtrace.report._t_sampling = t_sampling\n\n    n_chains = len(mtrace.chains)\n    _log.info(\n        f\'Sampling {n_chains} chain{"s" if n_chains > 1 else ""} for {n_tune:_d} tune and {n_draws:_d} draw iterations \'\n        f"({n_tune*n_chains:_d} + {n_draws*n_chains:_d} draws total) "\n        f"took {t_sampling:.0f} seconds."\n    )\n\n    if compute_convergence_checks or return_inferencedata:\n        ikwargs: dict[str, Any] = {"model": model, "save_warmup": not discard_tuned_samples}\n        ikwargs.update(idata_kwargs)\n        idata = pm.to_inference_data(mtrace, **ikwargs)\n\n        if compute_convergence_checks:\n            warns = run_convergence_checks(idata, model)\n            mtrace.report._add_warnings(warns)\n            log_warnings(warns)\n\n        if return_inferencedata:\n            # By default we drop the "warning" stat which contains `SamplerWarning`\n            # objects that can not be stored with `.to_netcdf()`.\n            if not keep_warning_stat:\n                return drop_warning_stat(idata)\n            return idata\n    return mtrace\n\n\ndef _check_start_shape(model, start: PointType):\n    """Check that the prior evaluations and initial points have identical shapes.\n\n    Parameters\n    ----------\n    model : pm.Model\n        The current model on context.\n    start : dict\n        The complete dictionary mapping (transformed) variable names to numeric initial values.\n    """\n    e = ""\n    try:\n        actual_shapes = model.eval_rv_shapes()\n    except NotImplementedError as ex:\n        warnings.warn(f"Unable to validate shapes: {ex.args[0]}", UserWarning)\n        return\n    for name, sval in start.items():\n        ashape = actual_shapes.get(name)\n        sshape = np.shape(sval)\n        if ashape != tuple(sshape):\n            e += f"\\nExpected shape {ashape} for var \'{name}\', got: {sshape}"\n    if e != "":\n        raise ValueError(f"Bad shape in start point:{e}")\n\n\ndef _sample_many(\n    *,\n    draws: int,\n    chains: int,\n    traces: Sequence[IBaseTrace],\n    start: Sequence[PointType],\n    rngs: Sequence[np.random.Generator],\n    step: Step,\n    callback: SamplingIteratorCallback | None = None,\n    **kwargs,\n):\n    """Sample all chains sequentially.\n\n    Parameters\n    ----------\n    draws: int\n        The number of samples to draw\n    chains: int\n        Total number of chains to sample.\n    start: list\n        Starting points for each chain\n    rngs: list of random Generators\n        A list of :py:class:`~numpy.random.Generator` objects, one for each chain\n    step: function\n        Step function\n    """\n    for i in range(chains):\n        _sample(\n            draws=draws,\n            chain=i,\n            start=start[i],\n            step=step,\n            trace=traces[i],\n            rng=rngs[i],\n            callback=callback,\n            **kwargs,\n        )\n    return\n\n\ndef _sample(\n    *,\n    chain: int,\n    progressbar: bool,\n    rng: np.random.Generator,\n    start: PointType,\n    draws: int,\n    step: Step,\n    trace: IBaseTrace,\n    tune: int,\n    model: Model | None = None,\n    progressbar_theme: Theme | None = default_progress_theme,\n    callback=None,\n    **kwargs,\n) -> None:\n    """Sample one chain (singleprocess).\n\n    Multiple step methods are supported via compound step methods.\n\n    Parameters\n    ----------\n    chain : int\n        Number of the chain that the samples will belong to.\n    progressbar : bool\n        Whether or not to display a progress bar in the command line. The bar shows the percentage\n        of completion, the sampling speed in samples per second (SPS), and the estimated remaining\n        time until completion ("expected time of arrival"; ETA).\n    random_seed : single random seed\n    start : dict\n        Starting point in parameter space (or partial point)\n    draws : int\n        The number of samples to draw\n    step : function\n        Step function\n    trace\n        A chain backend to record draws and stats.\n    tune : int\n        Number of iterations to tune.\n    model : Model (optional if in ``with`` context)\n    progressbar_theme : Theme\n        Optional custom theme for the progress bar.\n    """\n    skip_first = kwargs.get("skip_first", 0)\n\n    sampling_gen = _iter_sample(\n        draws=draws,\n        step=step,\n        start=start,\n        trace=trace,\n        chain=chain,\n        tune=tune,\n        model=model,\n        rng=rng,\n        callback=callback,\n    )\n    _pbar_data = {"chain": chain, "divergences": 0}\n    _desc = "Sampling chain {chain:d}, {divergences:,d} divergences"\n\n    progress = CustomProgress(\n        "[progress.description]{task.description}",\n        BarColumn(),\n        "[progress.percentage]{task.percentage:>3.0f}%",\n        TimeRemainingColumn(),\n        TextColumn("/"),\n        TimeElapsedColumn(),\n        console=Console(theme=progressbar_theme),\n        disable=not progressbar,\n    )\n\n    with progress:\n        try:\n            task = progress.add_task(_desc.format(**_pbar_data), completed=0, total=draws)\n            for it, diverging in enumerate(sampling_gen):\n                if it >= skip_first and diverging:\n                    _pbar_data["divergences"] += 1\n                progress.update(task, description=_desc.format(**_pbar_data), completed=it)\n            progress.update(\n                task, description=_desc.format(**_pbar_data), completed=draws, refresh=True\n            )\n        except KeyboardInterrupt:\n            pass\n\n\ndef _iter_sample(\n    *,\n    draws: int,\n    step: Step,\n    start: PointType,\n    trace: IBaseTrace,\n    chain: int = 0,\n    tune: int = 0,\n    rng: np.random.Generator,\n    model: Model | None = None,\n    callback: SamplingIteratorCallback | None = None,\n) -> Iterator[bool]:\n    """Sample one chain with a generator (singleprocess).\n\n    Parameters\n    ----------\n    draws : int\n        The number of samples to draw\n    step : function\n        Step function\n    start : dict\n        Starting point in parameter space (or partial point).\n        Must contain numeric (transformed) initial values for all (transformed) free variables.\n    trace\n        A chain backend to record draws and stats.\n    chain : int, optional\n        Chain number used to store sample in backend.\n    tune : int, optional\n        Number of iterations to tune (defaults to 0).\n    model : Model (optional if in ``with`` context)\n    random_seed : single random seed, optional\n\n    Yields\n    ------\n    diverging : bool\n        Indicates if the draw is divergent. Only available with some samplers.\n    """\n    draws = int(draws)\n\n    if draws < 1:\n        raise ValueError("Argument `draws` must be greater than 0.")\n\n    step.set_rng(rng)\n\n    point = start\n\n    try:\n        step.tune = bool(tune)\n        if hasattr(step, "reset_tuning"):\n            step.reset_tuning()\n        for i in range(draws):\n            if i == 0 and hasattr(step, "iter_count"):\n                step.iter_count = 0\n            if i == tune:\n                step.stop_tuning()\n            point, stats = step.step(point)\n            trace.record(point, stats)\n            log_warning_stats(stats)\n            diverging = i > tune and len(stats) > 0 and (stats[0].get("diverging") is True)\n            if callback is not None:\n                callback(\n                    trace=trace,\n                    draw=Draw(chain, i == draws, i, i < tune, stats, point),\n                )\n\n            yield diverging\n    except KeyboardInterrupt:\n        trace.close()\n        raise\n    except BaseException:\n        trace.close()\n        raise\n    else:\n        trace.close()\n\n\ndef _mp_sample(\n    *,\n    draws: int,\n    tune: int,\n    step,\n    chains: int,\n    cores: int,\n    rngs: Sequence[np.random.Generator],\n    start: Sequence[PointType],\n    progressbar: bool = True,\n    progressbar_theme: Theme | None = default_progress_theme,\n    traces: Sequence[IBaseTrace],\n    model: Model | None = None,\n    callback: SamplingIteratorCallback | None = None,\n    blas_cores: int | None = None,\n    mp_ctx=None,\n    **kwargs,\n) -> None:\n    """Sample all chains (multiprocess).\n\n    Parameters\n    ----------\n    draws : int\n        The number of samples to draw\n    tune : int\n        Number of iterations to tune.\n    step : function\n        Step function\n    chains : int\n        The number of chains to sample.\n    cores : int\n        The number of chains to run in parallel.\n    rngs: list of random Generators\n        A list of :py:class:`~numpy.random.Generator` objects, one for each chain\n    start : list\n        Starting points for each chain.\n        Dicts must contain numeric (transformed) initial values for all (transformed) free variables.\n    progressbar : bool\n        Whether or not to display a progress bar in the command line.\n    progressbar_theme : Theme\n        Optional custom theme for the progress bar.\n    traces\n        Recording backends for each chain.\n    model : Model (optional if in ``with`` context)\n    callback\n        A function which gets called for every sample from the trace of a chain. The function is\n        called with the trace and the current draw and will contain all samples for a single trace.\n        the ``draw.chain`` argument can be used to determine which of the active chains the sample\n        is drawn from.\n        Sampling can be interrupted by throwing a ``KeyboardInterrupt`` in the callback.\n    """\n    import pymc.sampling.parallel as ps\n\n    # We did draws += tune in pm.sample\n    draws -= tune\n\n    sampler = ps.ParallelSampler(\n        draws=draws,\n        tune=tune,\n        chains=chains,\n        cores=cores,\n        rngs=rngs,\n        start_points=start,\n        step_method=step,\n        progressbar=progressbar,\n        progressbar_theme=progressbar_theme,\n        blas_cores=blas_cores,\n        mp_ctx=mp_ctx,\n    )\n    try:\n        try:\n            with sampler:\n                for draw in sampler:\n                    strace = traces[draw.chain]\n                    strace.record(draw.point, draw.stats)\n                    log_warning_stats(draw.stats)\n\n                    if callback is not None:\n                        callback(trace=strace, draw=draw)\n\n        except ps.ParallelSamplingError as error:\n            for strace in traces:\n                strace.close()\n            raise\n    except KeyboardInterrupt:\n        pass\n    finally:\n        for strace in traces:\n            strace.close()\n\n\ndef _init_jitter(\n    model: Model,\n    initvals: StartDict | Sequence[StartDict | None] | None,\n    seeds: Sequence[int] | np.ndarray,\n    jitter: bool,\n    jitter_max_retries: int,\n    logp_dlogp_func=None,\n) -> list[PointType]:\n    """Apply a uniform jitter in [-1, 1] to the test value as starting point in each chain.\n\n    ``model.check_start_vals`` is used to test whether the jittered starting\n    values produce a finite log probability. Invalid values are resampled\n    unless `jitter_max_retries` is achieved, in which case the last sampled\n    values are returned.\n\n    Parameters\n    ----------\n    jitter: bool\n        Whether to apply jitter or not.\n    jitter_max_retries : int\n        Maximum number of repeated attempts at initializing values (per chain).\n\n    Returns\n    -------\n    start : ``pymc.model.Point``\n        Starting point for sampler\n    """\n    ipfns = make_initial_point_fns_per_chain(\n        model=model,\n        overrides=initvals,\n        jitter_rvs=set(model.free_RVs) if jitter else set(),\n        chains=len(seeds),\n    )\n\n    if not jitter:\n        return [ipfn(seed) for ipfn, seed in zip(ipfns, seeds)]\n\n    model_logp_fn: Callable\n    if logp_dlogp_func is None:\n        model_logp_fn = model.compile_logp()\n    else:\n\n        def model_logp_fn(ip):\n            q, _ = DictToArrayBijection.map(ip)\n            return logp_dlogp_func([q], extra_vars={})[0]\n\n    initial_points = []\n    for ipfn, seed in zip(ipfns, seeds):\n        rng = np.random.default_rng(seed)\n        for i in range(jitter_max_retries + 1):\n            point = ipfn(seed)\n            point_logp = model_logp_fn(point)\n            if not np.isfinite(point_logp):\n                if i == jitter_max_retries:\n                    # Print informative message on last attempted point\n                    model.check_start_vals(point)\n                # Retry with a new seed\n                seed = rng.integers(2**30, dtype=np.int64)\n            else:\n                break\n\n        initial_points.append(point)\n    return initial_points\n\n\ndef init_nuts(\n    *,\n    init: str = "auto",\n    chains: int = 1,\n    n_init: int = 500_000,\n    model: Model | None = None,\n    random_seed: RandomSeed = None,\n    progressbar=True,\n    jitter_max_retries: int = 10,\n    tune: int | None = None,\n    initvals: StartDict | Sequence[StartDict | None] | None = None,\n    compile_kwargs: dict | None = None,\n    **kwargs,\n) -> tuple[Sequence[PointType], NUTS]:\n    """Set up the mass matrix initialization for NUTS.\n\n    NUTS convergence and sampling speed is extremely dependent on the\n    choice of mass/scaling matrix. This function implements different\n    methods for choosing or adapting the mass matrix.\n\n    Parameters\n    ----------\n    init : str\n        Initialization method to use.\n\n        * auto: Choose a default initialization method automatically.\n          Currently, this is ``jitter+adapt_diag``, but this can change in the future. If you\n          depend on the exact behaviour, choose an initialization method explicitly.\n        * adapt_diag: Start with a identity mass matrix and then adapt a diagonal based on the\n          variance of the tuning samples. All chains use the test value (usually the prior mean)\n          as starting point.\n        * jitter+adapt_diag: Same as ``adapt_diag``, but use test value plus a uniform jitter in\n          [-1, 1] as starting point in each chain.\n        * jitter+adapt_diag_grad:\n          An experimental initialization method that uses information from gradients and samples\n          during tuning.\n        * advi+adapt_diag: Run ADVI and then adapt the resulting diagonal mass matrix based on the\n          sample variance of the tuning samples.\n        * advi: Run ADVI to estimate posterior mean and diagonal mass matrix.\n        * advi_map: Initialize ADVI with MAP and use MAP as starting point.\n        * map: Use the MAP as starting point. This is discouraged.\n        * adapt_full: Adapt a dense mass matrix using the sample covariances. All chains use the\n          test value (usually the prior mean) as starting point.\n        * jitter+adapt_full: Same as ``adapt_full``, but use test value plus a uniform jitter in\n          [-1, 1] as starting point in each chain.\n\n    chains : int\n        Number of jobs to start.\n    initvals : optional, dict or list of dicts\n        Dict or list of dicts with initial values to use instead of the defaults from `Model.initial_values`.\n        The keys should be names of transformed random variables.\n    n_init : int\n        Number of iterations of initializer. Only works for \'ADVI\' init methods.\n    model : Model (optional if in ``with`` context)\n    random_seed : int, array-like of int, RandomState or Generator, optional\n        Seed for the random number generator.\n    progressbar : bool\n        Whether or not to display a progressbar for advi sampling.\n    jitter_max_retries : int\n        Maximum number of repeated attempts (per chain) at creating an initial matrix with uniform jitter\n        that yields a finite probability. This applies to ``jitter+adapt_diag`` and ``jitter+adapt_full``\n        init methods.\n    **kwargs : keyword arguments\n        Extra keyword arguments are forwarded to pymc.NUTS.\n\n    Returns\n    -------\n    initial_points : list\n        Starting points for each chain.\n    nuts_sampler : ``pymc.step_methods.NUTS``\n        Instantiated and initialized NUTS sampler object\n    """\n    model = modelcontext(model)\n\n    vars = kwargs.get("vars", model.value_vars)\n    if set(vars) != set(model.value_vars):\n        raise ValueError("Must use init_nuts on all variables of a model.")\n    if not all_continuous(vars):\n        raise ValueError("init_nuts can only be used for models with continuous variables.")\n\n    if not isinstance(init, str):\n        raise TypeError("init must be a string.")\n\n    init = init.lower()\n\n    if init == "auto":\n        init = "jitter+adapt_diag"\n\n    if compile_kwargs is None:\n        compile_kwargs = {}\n\n    random_seed_list = _get_seeds_per_chain(random_seed, chains)\n\n    _log.info(f"Initializing NUTS using {init}...")\n\n    cb = []\n    if "advi" in init:\n        cb = [\n            pm.callbacks.CheckParametersConvergence(tolerance=1e-2, diff="absolute"),\n            pm.callbacks.CheckParametersConvergence(tolerance=1e-2, diff="relative"),\n        ]\n\n    logp_dlogp_func = model.logp_dlogp_function(ravel_inputs=True, **compile_kwargs)\n    logp_dlogp_func.trust_input = True\n    initial_points = _init_jitter(\n        model,\n        initvals,\n        seeds=random_seed_list,\n        jitter="jitter" in init,\n        jitter_max_retries=jitter_max_retries,\n        logp_dlogp_func=logp_dlogp_func,\n    )\n\n    apoints = [DictToArrayBijection.map(point) for point in initial_points]\n    apoints_data = [apoint.data for apoint in apoints]\n    potential: quadpotential.QuadPotential\n\n    if init == "adapt_diag":\n        mean = np.mean(apoints_data, axis=0)\n        var = np.ones_like(mean)\n        n = len(var)\n        potential = quadpotential.QuadPotentialDiagAdapt(n, mean, var, 10, rng=random_seed_list[0])\n    elif init == "jitter+adapt_diag":\n        mean = np.mean(apoints_data, axis=0)\n        var = np.ones_like(mean)\n        n = len(var)\n        potential = quadpotential.QuadPotentialDiagAdapt(n, mean, var, 10, rng=random_seed_list[0])\n    elif init == "jitter+adapt_diag_grad":\n        mean = np.mean(apoints_data, axis=0)\n        var = np.ones_like(mean)\n        n = len(var)\n\n        if tune is not None and tune > 250:\n            stop_adaptation = tune - 50\n        else:\n            stop_adaptation = None\n\n        potential = quadpotential.QuadPotentialDiagAdaptExp(\n            n,\n            mean,\n            alpha=0.02,\n            use_grads=True,\n            stop_adaptation=stop_adaptation,\n            rng=random_seed_list[0],\n        )\n    elif init == "advi+adapt_diag":\n        approx = pm.fit(\n            random_seed=random_seed_list[0],\n            n=n_init,\n            method="advi",\n            model=model,\n            callbacks=cb,\n            progressbar=progressbar,\n            obj_optimizer=pm.adagrad_window,\n        )\n        approx_sample = approx.sample(\n            draws=chains, random_seed=random_seed_list[0], return_inferencedata=False\n        )\n        initial_points = [approx_sample[i] for i in range(chains)]\n        std_apoint = approx.std.eval()\n        cov = std_apoint**2\n        mean = approx.mean.get_value()\n        weight = 50\n        n = len(cov)\n        potential = quadpotential.QuadPotentialDiagAdapt(\n            n, mean, cov, weight, rng=random_seed_list[0]\n        )\n    elif init == "advi":\n        approx = pm.fit(\n            random_seed=random_seed_list[0],\n            n=n_init,\n            method="advi",\n            model=model,\n            callbacks=cb,\n            progressbar=progressbar,\n            obj_optimizer=pm.adagrad_window,\n        )\n        approx_sample = approx.sample(\n            draws=chains, random_seed=random_seed_list[0], return_inferencedata=False\n        )\n        initial_points = [approx_sample[i] for i in range(chains)]\n        cov = approx.std.eval() ** 2\n        potential = quadpotential.QuadPotentialDiag(cov, rng=random_seed_list[0])\n    elif init == "advi_map":\n        start = pm.find_MAP(include_transformed=True, seed=random_seed_list[0])\n        approx = pm.MeanField(model=model, start=start)\n        pm.fit(\n            random_seed=random_seed_list[0],\n            n=n_init,\n            method=pm.KLqp(approx),\n            callbacks=cb,\n            progressbar=progressbar,\n            obj_optimizer=pm.adagrad_window,\n        )\n        approx_sample = approx.sample(\n            draws=chains, random_seed=random_seed_list[0], return_inferencedata=False\n        )\n        initial_points = [approx_sample[i] for i in range(chains)]\n        cov = approx.std.eval() ** 2\n        potential = quadpotential.QuadPotentialDiag(cov, rng=random_seed_list[0])\n    elif init == "map":\n        start = pm.find_MAP(include_transformed=True, seed=random_seed_list[0])\n        cov = -pm.find_hessian(point=start, negate_output=False)\n        initial_points = [start] * chains\n        potential = quadpotential.QuadPotentialFull(cov, rng=random_seed_list[0])\n    elif init == "adapt_full":\n        mean = np.mean(apoints_data * chains, axis=0)\n        initial_point = initial_points[0]\n        initial_point_model_size = sum(initial_point[n.name].size for n in model.value_vars)\n        cov = np.eye(initial_point_model_size)\n        potential = quadpotential.QuadPotentialFullAdapt(\n            initial_point_model_size, mean, cov, 10, rng=random_seed_list[0]\n        )\n    elif init == "jitter+adapt_full":\n        mean = np.mean(apoints_data, axis=0)\n        initial_point = initial_points[0]\n        initial_point_model_size = sum(initial_point[n.name].size for n in model.value_vars)\n        cov = np.eye(initial_point_model_size)\n        potential = quadpotential.QuadPotentialFullAdapt(\n            initial_point_model_size, mean, cov, 10, rng=random_seed_list[0]\n        )\n    else:\n        raise ValueError(f"Unknown initializer: {init}.")\n\n    step = pm.NUTS(\n        potential=potential,\n        model=model,\n        rng=random_seed_list[0],\n        initial_point=initial_points[0],\n        logp_dlogp_func=logp_dlogp_func,\n        **kwargs,\n    )\n\n    # Filter deterministics from initial_points\n    value_var_names = [var.name for var in model.value_vars]\n    initial_points = [\n        {k: v for k, v in initial_point.items() if k in value_var_names}\n        for initial_point in initial_points\n    ]\n\n    return initial_points, step\n',
            'pymc/sampling/parallel.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nimport ctypes\nimport logging\nimport multiprocessing\nimport multiprocessing.sharedctypes\nimport platform\nimport time\nimport traceback\n\nfrom collections import namedtuple\nfrom collections.abc import Sequence\n\nimport cloudpickle\nimport numpy as np\n\nfrom rich.console import Console\nfrom rich.progress import BarColumn, TextColumn, TimeElapsedColumn, TimeRemainingColumn\nfrom rich.theme import Theme\nfrom threadpoolctl import threadpool_limits\n\nfrom pymc.blocking import DictToArrayBijection\nfrom pymc.exceptions import SamplingError\nfrom pymc.util import CustomProgress, default_progress_theme\n\nlogger = logging.getLogger(__name__)\n\n\nclass ParallelSamplingError(Exception):\n    def __init__(self, message, chain):\n        super().__init__(message)\n        self._chain = chain\n\n\n# Taken from https://hg.python.org/cpython/rev/c4f92b597074\nclass RemoteTraceback(Exception):\n    def __init__(self, tb):\n        self.tb = tb\n\n    def __str__(self):\n        """Return a string representation of the object."""\n        return self.tb\n\n\nclass ExceptionWithTraceback:\n    def __init__(self, exc, tb):\n        tb = traceback.format_exception(type(exc), exc, tb)\n        tb = "".join(tb)\n        self.exc = exc\n        self.tb = f\'\\n"""\\n{tb}"""\'\n\n    def __reduce__(self):\n        """Return a tuple to pickle."""\n        return rebuild_exc, (self.exc, self.tb)\n\n\ndef rebuild_exc(exc, tb):\n    exc.__cause__ = RemoteTraceback(tb)\n    return exc\n\n\n# Messages\n# (\'writing_done\', is_last, sample_idx, tuning, stats)\n# (\'error\', *exception_info)\n\n# (\'abort\', reason)\n# (\'write_next\',)\n# (\'start\',)\n\n\nclass _Process:\n    """Separate process for each chain.\n\n    We communicate with the main process using a pipe,\n    and send finished samples using shared memory.\n    """\n\n    def __init__(\n        self,\n        name: str,\n        msg_pipe,\n        step_method,\n        step_method_is_pickled,\n        shared_point,\n        draws: int,\n        tune: int,\n        rng: np.random.Generator,\n        seed_seq: np.random.SeedSequence,\n        blas_cores,\n    ):\n        # For some strange reason, spawn multiprocessing doesn\'t copy the rng\n        # seed sequence, so we have to rebuild it from scratch\n        rng = np.random.Generator(type(rng.bit_generator)(seed_seq))\n        self._msg_pipe = msg_pipe\n        self._step_method = step_method\n        self._step_method_is_pickled = step_method_is_pickled\n        self._shared_point = shared_point\n        self._rng = rng\n        self._draws = draws\n        self._tune = tune\n        self._blas_cores = blas_cores\n\n    def _unpickle_step_method(self):\n        unpickle_error = (\n            "The model could not be unpickled. This is required for sampling "\n            "with more than one core and multiprocessing context spawn "\n            "or forkserver."\n        )\n        if self._step_method_is_pickled:\n            try:\n                self._step_method = cloudpickle.loads(self._step_method)\n            except Exception:\n                raise ValueError(unpickle_error)\n\n    def run(self):\n        with threadpool_limits(limits=self._blas_cores):\n            try:\n                # We do not create this in __init__, as pickling this\n                # would destroy the shared memory.\n                self._unpickle_step_method()\n                self._point = self._make_numpy_refs()\n                self._start_loop()\n            except KeyboardInterrupt:\n                pass\n            except BaseException as e:\n                e = ExceptionWithTraceback(e, e.__traceback__)\n                # Send is not blocking so we have to force a wait for the abort\n                # message\n                self._msg_pipe.send(("error", e))\n                self._wait_for_abortion()\n            finally:\n                self._msg_pipe.close()\n\n    def _wait_for_abortion(self):\n        while True:\n            msg = self._recv_msg()\n            if msg[0] == "abort":\n                break\n\n    def _make_numpy_refs(self):\n        point = {}\n        # XXX: I\'m assuming that the processes are properly synchronized...\n        for name, (array, shape, dtype) in self._shared_point.items():\n            point[name] = np.frombuffer(array, dtype).reshape(shape)\n        return point\n\n    def _write_point(self, point):\n        # XXX: What do we do when the underlying points change shape?\n        for name, vals in point.items():\n            self._point[name][...] = vals\n\n    def _recv_msg(self):\n        return self._msg_pipe.recv()\n\n    def _start_loop(self):\n        self._step_method.set_rng(self._rng)\n\n        draw = 0\n        tuning = True\n\n        msg = self._recv_msg()\n        if msg[0] == "abort":\n            raise KeyboardInterrupt()\n        if msg[0] != "start":\n            raise ValueError("Unexpected msg " + msg[0])\n\n        while True:\n            if draw == self._tune:\n                self._step_method.stop_tuning()\n                tuning = False\n\n            if draw < self._draws + self._tune:\n                try:\n                    point, stats = self._step_method.step(self._point)\n                except SamplingError as e:\n                    e = ExceptionWithTraceback(e, e.__traceback__)\n                    self._msg_pipe.send(("error", e))\n            else:\n                return\n\n            msg = self._recv_msg()\n            if msg[0] == "abort":\n                raise KeyboardInterrupt()\n            elif msg[0] == "write_next":\n                self._write_point(point)\n                is_last = draw + 1 == self._draws + self._tune\n                self._msg_pipe.send(("writing_done", is_last, draw, tuning, stats))\n                draw += 1\n            else:\n                raise ValueError("Unknown message " + msg[0])\n\n\ndef _run_process(*args):\n    _Process(*args).run()\n\n\nclass ProcessAdapter:\n    """Control a Chain process from the main thread."""\n\n    def __init__(\n        self,\n        draws: int,\n        tune: int,\n        step_method,\n        step_method_pickled,\n        chain: int,\n        rng: np.random.Generator,\n        start: dict[str, np.ndarray],\n        blas_cores,\n        mp_ctx,\n    ):\n        self.chain = chain\n        process_name = f"worker_chain_{chain}"\n        self._msg_pipe, remote_conn = multiprocessing.Pipe()\n\n        self._shared_point = {}\n        self._point = {}\n\n        for name, shape, size, dtype in DictToArrayBijection.map(start).point_map_info:\n            byte_size = size * dtype.itemsize\n            if byte_size != ctypes.c_size_t(byte_size).value:\n                raise ValueError(f"Variable {name} is too large")\n\n            array = mp_ctx.RawArray("c", byte_size)\n            self._shared_point[name] = (array, shape, dtype)\n            array_np = np.frombuffer(array, dtype).reshape(shape)\n            array_np[...] = start[name]\n            self._point[name] = array_np\n\n        self._readable = True\n        self._num_samples = 0\n\n        if step_method_pickled is not None:\n            step_method_send = step_method_pickled\n        else:\n            if mp_ctx.get_start_method() == "spawn":\n                raise ValueError(\n                    "please provide a pre-pickled step method when multiprocessing start method is \'spawn\'"\n                )\n            step_method_send = step_method\n\n        self._process = mp_ctx.Process(\n            daemon=True,\n            name=process_name,\n            target=_run_process,\n            args=(\n                process_name,\n                remote_conn,\n                step_method_send,\n                step_method_pickled is not None,\n                self._shared_point,\n                draws,\n                tune,\n                rng,\n                rng.bit_generator.seed_seq,\n                blas_cores,\n            ),\n        )\n        self._process.start()\n        # Close the remote pipe, so that we get notified if the other\n        # end is closed.\n        remote_conn.close()\n\n    @property\n    def shared_point_view(self):\n        """May only be written to or read between a `recv_draw` call from the process and a `write_next` or `abort` call."""\n        if not self._readable:\n            raise RuntimeError()\n        return self._point\n\n    def _send(self, msg, *args):\n        try:\n            self._msg_pipe.send((msg, *args))\n        except Exception:\n            # try to receive an error message\n            message = None\n            try:\n                message = self._msg_pipe.recv()\n            except Exception:\n                pass\n            if message is not None and message[0] == "error":\n                old_error = message[1]\n                if old_error is not None:\n                    error = ParallelSamplingError(\n                        f"Chain {self.chain} failed with: {old_error}", self.chain\n                    )\n                else:\n                    error = RuntimeError(f"Chain {self.chain} failed.")\n                raise error from old_error\n            raise\n\n    def start(self):\n        self._send("start")\n\n    def write_next(self):\n        self._readable = False\n        self._send("write_next")\n\n    def abort(self):\n        self._send("abort")\n\n    def join(self, timeout=None):\n        self._process.join(timeout)\n\n    def terminate(self):\n        self._process.terminate()\n\n    @staticmethod\n    def recv_draw(processes, timeout=3600):\n        if not processes:\n            raise ValueError("No processes.")\n        pipes = [proc._msg_pipe for proc in processes]\n        ready = multiprocessing.connection.wait(pipes)\n        if not ready:\n            raise multiprocessing.TimeoutError("No message from samplers.")\n        idxs = {id(proc._msg_pipe): proc for proc in processes}\n        proc = idxs[id(ready[0])]\n        msg = ready[0].recv()\n\n        if msg[0] == "error":\n            old_error = msg[1]\n            if old_error is not None:\n                error = ParallelSamplingError(\n                    f"Chain {proc.chain} failed with: {old_error}", proc.chain\n                )\n            else:\n                error = RuntimeError(f"Chain {proc.chain} failed.")\n            raise error from old_error\n        elif msg[0] == "writing_done":\n            proc._readable = True\n            proc._num_samples += 1\n            return (proc,) + msg[1:]\n        else:\n            raise ValueError("Sampler sent bad message.")\n\n    @staticmethod\n    def terminate_all(processes, patience=2):\n        for process in processes:\n            try:\n                process.abort()\n            except Exception:\n                pass\n\n        start_time = time.time()\n        try:\n            for process in processes:\n                timeout = time.time() + patience - start_time\n                if timeout < 0:\n                    raise multiprocessing.TimeoutError()\n                process.join(timeout)\n        except multiprocessing.TimeoutError:\n            logger.warning(\n                "Chain processes did not terminate as expected. Terminating forcefully..."\n            )\n            for process in processes:\n                process.terminate()\n            for process in processes:\n                process.join()\n\n\nDraw = namedtuple("Draw", ["chain", "is_last", "draw_idx", "tuning", "stats", "point"])\n\n\nclass ParallelSampler:\n    def __init__(\n        self,\n        *,\n        draws: int,\n        tune: int,\n        chains: int,\n        cores: int,\n        rngs: Sequence[np.random.Generator],\n        start_points: Sequence[dict[str, np.ndarray]],\n        step_method,\n        progressbar: bool = True,\n        progressbar_theme: Theme | None = default_progress_theme,\n        blas_cores: int | None = None,\n        mp_ctx=None,\n    ):\n        if any(len(arg) != chains for arg in [rngs, start_points]):\n            raise ValueError(f"Number of rngs and start_points must be {chains}.")\n\n        if mp_ctx is None or isinstance(mp_ctx, str):\n            # Closes issue https://github.com/pymc-devs/pymc/issues/3849\n            # Related issue https://github.com/pymc-devs/pymc/issues/5339\n            if mp_ctx is None and platform.system() == "Darwin":\n                if platform.processor() == "arm":\n                    mp_ctx = "fork"\n                    logger.debug(\n                        "mp_ctx is set to \'fork\' for MacOS with ARM architecture. "\n                        + "This might cause unexpected behavior with JAX, which is inherently multithreaded."\n                    )\n                else:\n                    mp_ctx = "forkserver"\n\n            mp_ctx = multiprocessing.get_context(mp_ctx)\n\n        step_method_pickled = None\n        if mp_ctx.get_start_method() != "fork":\n            step_method_pickled = cloudpickle.dumps(step_method, protocol=-1)\n\n        self._samplers = [\n            ProcessAdapter(\n                draws,\n                tune,\n                step_method,\n                step_method_pickled,\n                chain,\n                rng,\n                start,\n                blas_cores,\n                mp_ctx,\n            )\n            for chain, rng, start in zip(range(chains), rngs, start_points)\n        ]\n\n        self._inactive = self._samplers.copy()\n        self._finished: list[ProcessAdapter] = []\n        self._active: list[ProcessAdapter] = []\n        self._max_active = cores\n\n        self._in_context = False\n\n        self._progress = CustomProgress(\n            "[progress.description]{task.description}",\n            BarColumn(),\n            "[progress.percentage]{task.percentage:>3.0f}%",\n            TimeRemainingColumn(),\n            TextColumn("/"),\n            TimeElapsedColumn(),\n            console=Console(theme=progressbar_theme),\n            disable=not progressbar,\n        )\n        self._show_progress = progressbar\n        self._divergences = 0\n        self._completed_draws = 0\n        self._total_draws = chains * (draws + tune)\n        self._desc = "Sampling {0._chains:d} chains, {0._divergences:,d} divergences"\n        self._chains = chains\n\n    def _make_active(self):\n        while self._inactive and len(self._active) < self._max_active:\n            proc = self._inactive.pop(0)\n            proc.start()\n            proc.write_next()\n            self._active.append(proc)\n\n    def __iter__(self):\n        """Return an iterator over draws."""\n        if not self._in_context:\n            raise ValueError("Use ParallelSampler as context manager.")\n        self._make_active()\n\n        with self._progress as progress:\n            task = progress.add_task(\n                self._desc.format(self),\n                completed=self._completed_draws,\n                total=self._total_draws,\n            )\n\n            while self._active:\n                draw = ProcessAdapter.recv_draw(self._active)\n                proc, is_last, draw, tuning, stats = draw\n                self._completed_draws += 1\n                if not tuning and stats and stats[0].get("diverging"):\n                    self._divergences += 1\n                progress.update(\n                    task,\n                    completed=self._completed_draws,\n                    total=self._total_draws,\n                    description=self._desc.format(self),\n                )\n\n                if is_last:\n                    proc.join()\n                    self._active.remove(proc)\n                    self._finished.append(proc)\n                    self._make_active()\n                    progress.update(task, description=self._desc.format(self), refresh=True)\n\n                # We could also yield proc.shared_point_view directly,\n                # and only call proc.write_next() after the yield returns.\n                # This seems to be faster overally though, as the worker\n                # loses less time waiting.\n                point = {name: val.copy() for name, val in proc.shared_point_view.items()}\n\n                # Already called for new proc in _make_active\n                if not is_last:\n                    proc.write_next()\n\n                yield Draw(proc.chain, is_last, draw, tuning, stats, point)\n\n    def __enter__(self):\n        """Enter the context manager."""\n        self._in_context = True\n        return self\n\n    def __exit__(self, *args):\n        """Exit the context manager."""\n        ProcessAdapter.terminate_all(self._samplers)\n\n\ndef _cpu_count():\n    """Try to guess the number of CPUs in the system.\n\n    We use the number provided by psutil if that is installed.\n    If not, we use the number provided by multiprocessing, but assume\n    that half of the cpus are only hardware threads and ignore those.\n    """\n    try:\n        cpus = multiprocessing.cpu_count() // 2\n    except NotImplementedError:\n        cpus = 1\n    return cpus\n',
            'pymc/step_methods/compound.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\n"""\nCreated on Mar 7, 2011.\n\n@author: johnsalvatier\n"""\n\nimport warnings\n\nfrom abc import ABC, abstractmethod\nfrom collections.abc import Iterable, Mapping, Sequence\nfrom enum import IntEnum, unique\nfrom typing import Any\n\nimport numpy as np\n\nfrom pytensor.graph.basic import Variable\n\nfrom pymc.blocking import PointType, StatDtype, StatsDict, StatShape, StatsType\nfrom pymc.model import modelcontext\nfrom pymc.step_methods.state import DataClassState, WithSamplingState, dataclass_state\nfrom pymc.util import RandomGenerator, get_random_generator\n\n__all__ = ("Competence", "CompoundStep")\n\n\n@unique\nclass Competence(IntEnum):\n    """Enum for characterizing competence classes of step methods.\n\n    Values include:\n    0: INCOMPATIBLE\n    1: COMPATIBLE\n    2: PREFERRED\n    3: IDEAL\n    """\n\n    INCOMPATIBLE = 0\n    COMPATIBLE = 1\n    PREFERRED = 2\n    IDEAL = 3\n\n\ndef infer_warn_stats_info(\n    stats_dtypes: list[dict[str, StatDtype]],\n    sds: dict[str, tuple[StatDtype, StatShape]],\n    stepname: str,\n) -> tuple[list[dict[str, StatDtype]], dict[str, tuple[StatDtype, StatShape]]]:\n    """Get `stats_dtypes` and `stats_dtypes_shapes` from either of them."""\n    # Avoid side-effects on the original lists/dicts\n    stats_dtypes = [d.copy() for d in stats_dtypes]\n    sds = sds.copy()\n    # Disallow specification of both attributes\n    if stats_dtypes and sds:\n        raise TypeError(\n            "Only one of `stats_dtypes_shapes` or `stats_dtypes` must be specified."\n            f" `{stepname}.stats_dtypes` should be removed."\n        )\n\n    # Infer one from the other\n    if not sds and stats_dtypes:\n        warnings.warn(\n            f"`{stepname}.stats_dtypes` is deprecated."\n            " Please update it to specify `stats_dtypes_shapes` instead.",\n            DeprecationWarning,\n        )\n        if len(stats_dtypes) > 1:\n            raise TypeError(\n                f"`{stepname}.stats_dtypes` must be a list containing at most one dict."\n            )\n        for sd in stats_dtypes:\n            for sname, dtype in sd.items():\n                sds[sname] = (dtype, None)\n    elif sds:\n        stats_dtypes.append({sname: dtype for sname, (dtype, _) in sds.items()})\n    return stats_dtypes, sds\n\n\n@dataclass_state\nclass StepMethodState(DataClassState):\n    rng: np.random.Generator\n\n\nclass BlockedStep(ABC, WithSamplingState):\n    stats_dtypes: list[dict[str, type]] = []\n    """A list containing <=1 dictionary that maps stat names to dtypes.\n\n    This attribute is deprecated.\n    Use `stats_dtypes_shapes` instead.\n    """\n\n    stats_dtypes_shapes: dict[str, tuple[StatDtype, StatShape]] = {}\n    """Maps stat names to dtypes and shapes.\n\n    Shapes are interpreted in the following ways:\n    - `[]` is a scalar.\n    - `[3,]` is a length-3 vector.\n    - `[4, None]` is a matrix with 4 rows and a dynamic number of columns.\n    - `None` is a sparse stat (i.e. not always present) or a NumPy array with varying `ndim`.\n    """\n\n    vars: list[Variable] = []\n    """Variables that the step method is assigned to."""\n\n    def __new__(cls, *args, **kwargs):\n        blocked = kwargs.get("blocked")\n        if blocked is None:\n            # Try to look up default value from class\n            blocked = getattr(cls, "default_blocked", True)\n            kwargs["blocked"] = blocked\n\n        model = modelcontext(kwargs.get("model"))\n        kwargs.update({"model": model})\n\n        # vars can either be first arg or a kwarg\n        if "vars" not in kwargs and len(args) >= 1:\n            vars = args[0]\n            args = args[1:]\n        elif "vars" in kwargs:\n            vars = kwargs.pop("vars")\n        else:  # Assume all model variables\n            vars = model.value_vars\n\n        if not isinstance(vars, tuple | list):\n            vars = [vars]\n\n        if len(vars) == 0:\n            raise ValueError("No free random variables to sample.")\n\n        # Auto-fill stats metadata attributes from whichever was given.\n        stats_dtypes, stats_dtypes_shapes = infer_warn_stats_info(\n            cls.stats_dtypes,\n            cls.stats_dtypes_shapes,\n            cls.__name__,\n        )\n\n        if not blocked and len(vars) > 1:\n            # In this case we create a separate sampler for each var\n            # and append them to a CompoundStep\n            steps = []\n            rngs = get_random_generator(kwargs.pop("rng", None)).spawn(len(vars))\n            for var, rng in zip(vars, rngs):\n                step = super().__new__(cls)\n                step.stats_dtypes = stats_dtypes\n                step.stats_dtypes_shapes = stats_dtypes_shapes\n                # If we don\'t return the instance we have to manually\n                # call __init__\n                _kwargs = kwargs.copy()\n                _kwargs["rng"] = rng\n                step.__init__([var], *args, **_kwargs)\n                # Hack for creating the class correctly when unpickling.\n                step.__newargs = ([var], *args), _kwargs\n                steps.append(step)\n\n            return CompoundStep(steps)\n        else:\n            step = super().__new__(cls)\n            step.stats_dtypes = stats_dtypes\n            step.stats_dtypes_shapes = stats_dtypes_shapes\n            # Hack for creating the class correctly when unpickling.\n            step.__newargs = (vars, *args), kwargs\n            return step\n\n    # Hack for creating the class correctly when unpickling.\n    def __getnewargs_ex__(self):\n        return self.__newargs\n\n    @abstractmethod\n    def step(self, point: PointType) -> tuple[PointType, StatsType]:\n        """Perform a single step of the sampler."""\n\n    @staticmethod\n    def competence(var, has_grad):\n        return Competence.INCOMPATIBLE\n\n    @classmethod\n    def _competence(cls, vars, have_grad):\n        vars = np.atleast_1d(vars)\n        have_grad = np.atleast_1d(have_grad)\n        competences = []\n        for var, has_grad in zip(vars, have_grad):\n            try:\n                competences.append(cls.competence(var, has_grad))\n            except TypeError:\n                competences.append(cls.competence(var))\n        return competences\n\n    def stop_tuning(self):\n        if hasattr(self, "tune"):\n            self.tune = False\n\n    def set_rng(self, rng: RandomGenerator):\n        self.rng = get_random_generator(rng, copy=False)\n\n\ndef flat_statname(sampler_idx: int, sname: str) -> str:\n    """Get the flat-stats name for a samplers stat."""\n    return f"sampler_{sampler_idx}__{sname}"\n\n\ndef get_stats_dtypes_shapes_from_steps(\n    steps: Iterable[BlockedStep],\n) -> dict[str, tuple[StatDtype, StatShape]]:\n    """Combine stats dtype shape dictionaries from multiple step methods.\n\n    In the resulting stats dict, each sampler stat is prefixed by `sampler_#__`.\n    """\n    result = {}\n    for s, step in enumerate(steps):\n        for sname, (dtype, shape) in step.stats_dtypes_shapes.items():\n            result[flat_statname(s, sname)] = (dtype, shape)\n    return result\n\n\n@dataclass_state\nclass CompoundStepState(DataClassState):\n    methods: list[StepMethodState]\n\n    def __init__(self, methods: list[StepMethodState]):\n        self.methods = methods\n\n\nclass CompoundStep(WithSamplingState):\n    """Step method composed of a list of several other step methods applied in sequence."""\n\n    _state_class = CompoundStepState\n\n    def __init__(self, methods):\n        self.methods = list(methods)\n        self.stats_dtypes = []\n        for method in self.methods:\n            self.stats_dtypes.extend(method.stats_dtypes)\n        self.stats_dtypes_shapes = get_stats_dtypes_shapes_from_steps(methods)\n        self.name = (\n            f"Compound[{\', \'.join(getattr(m, \'name\', \'UNNAMED_STEP\') for m in self.methods)}]"\n        )\n        self.tune = True\n\n    def step(self, point) -> tuple[PointType, StatsType]:\n        stats = []\n        for method in self.methods:\n            point, sts = method.step(point)\n            stats.extend(sts)\n        # Model logp can only be the logp of the _last_ stats,\n        # if there is one. Pop all others.\n        for sts in stats[:-1]:\n            sts.pop("model_logp", None)\n        return point, stats\n\n    def stop_tuning(self):\n        for method in self.methods:\n            method.stop_tuning()\n\n    def reset_tuning(self):\n        for method in self.methods:\n            if hasattr(method, "reset_tuning"):\n                method.reset_tuning()\n\n    @property\n    def sampling_state(self) -> DataClassState:\n        return CompoundStepState(methods=[method.sampling_state for method in self.methods])\n\n    @sampling_state.setter\n    def sampling_state(self, state: DataClassState):\n        assert isinstance(\n            state, self._state_class\n        ), f"Invalid sampling state class {type(state)}. Expected {self._state_class}"\n        for method, state_method in zip(self.methods, state.methods):\n            method.sampling_state = state_method\n\n    @property\n    def vars(self) -> list[Variable]:\n        return [var for method in self.methods for var in method.vars]\n\n    def set_rng(self, rng: RandomGenerator):\n        _rngs = get_random_generator(rng, copy=False).spawn(len(self.methods))\n        for method, _rng in zip(self.methods, _rngs):\n            method.set_rng(_rng)\n\n\ndef flatten_steps(step: BlockedStep | CompoundStep) -> list[BlockedStep]:\n    """Flatten a hierarchy of step methods to a list."""\n    if isinstance(step, BlockedStep):\n        return [step]\n    steps = []\n    if not isinstance(step, CompoundStep):\n        raise ValueError(f"Unexpected type of step method: {step}")\n    for sm in step.methods:\n        steps += flatten_steps(sm)\n    return steps\n\n\ndef check_step_emits_tune(step: CompoundStep | BlockedStep):\n    if isinstance(step, BlockedStep) and "tune" not in step.stats_dtypes_shapes:\n        raise TypeError(f"{type(step)} does not emit the required \'tune\' stat.")\n    elif isinstance(step, CompoundStep):\n        for sstep in step.methods:\n            if "tune" not in sstep.stats_dtypes_shapes:\n                raise TypeError(f"{type(sstep)} does not emit the required \'tune\' stat.")\n    return\n\n\nclass StatsBijection:\n    """Map between a `list` of stats to `dict` of stats."""\n\n    def __init__(self, sampler_stats_dtypes: Sequence[Mapping[str, type]]) -> None:\n        # Keep a list of flat vs. original stat names\n        stat_groups = []\n        for s, names_dtypes in enumerate(sampler_stats_dtypes):\n            group = []\n            for statname, dtype in names_dtypes.items():\n                flatname = flat_statname(s, statname)\n                is_obj = np.dtype(dtype) == np.dtype(object)\n                group.append((flatname, statname, is_obj))\n            stat_groups.append(group)\n        self._stat_groups: list[list[tuple[str, str, bool]]] = stat_groups\n        self.object_stats = {\n            fname: (s, sname)\n            for s, group in enumerate(self._stat_groups)\n            for fname, sname, is_obj in group\n            if is_obj\n        }\n\n    @property\n    def n_samplers(self) -> int:\n        return len(self._stat_groups)\n\n    def map(self, stats_list: Sequence[Mapping[str, Any]]) -> StatsDict:\n        """Combine stats dicts of multiple samplers into one dict."""\n        stats_dict = {}\n        for s, sts in enumerate(stats_list):\n            for fname, sname, is_obj in self._stat_groups[s]:\n                if sname not in sts:\n                    continue\n                stats_dict[fname] = sts[sname]\n        return stats_dict\n\n    def rmap(self, stats_dict: Mapping[str, Any]) -> StatsType:\n        """Split a global stats dict into a list of sampler-wise stats dicts.\n\n        The ``stats_dict`` can be a subset of all sampler stats.\n        """\n        stats_list = []\n        for group in self._stat_groups:\n            d = {}\n            for fname, sname, is_obj in group:\n                if fname not in stats_dict:\n                    continue\n                d[sname] = stats_dict[fname]\n            stats_list.append(d)\n        return stats_list\n',
            'pymc/step_methods/hmc/quadpotential.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nfrom __future__ import annotations\n\nimport warnings\n\nfrom dataclasses import field\nfrom typing import Any, overload\n\nimport numpy as np\nimport pytensor\nimport scipy.linalg\n\nfrom scipy.sparse import issparse\n\nfrom pymc.pytensorf import floatX\nfrom pymc.step_methods.state import DataClassState, WithSamplingState, dataclass_state\nfrom pymc.util import RandomGenerator, get_random_generator\n\n__all__ = [\n    "QuadPotentialDiag",\n    "QuadPotentialDiagAdapt",\n    "QuadPotentialFull",\n    "QuadPotentialFullAdapt",\n    "QuadPotentialFullInv",\n    "isquadpotential",\n    "quad_potential",\n]\n\n\ndef quad_potential(C, is_cov, rng=None):\n    """\n    Compute a QuadPotential object from a scaling matrix.\n\n    Parameters\n    ----------\n    C: arraylike, 0 <= ndim <= 2\n        scaling matrix for the potential\n        vector treated as diagonal matrix.\n    is_cov: Boolean\n        whether C is provided as a covariance matrix or hessian\n    rng: RandomGenerator\n        An object that can produce be used to produce the step method\'s\n        :py:class:`~numpy.random.Generator` object. Refer to\n        :py:func:`pymc.util.get_random_generator` for more information.\n\n    Returns\n    -------\n    q: Quadpotential\n    """\n    if issparse(C):\n        if not chol_available:\n            raise ImportError("Sparse mass matrices require scikits.sparse")\n        elif is_cov:\n            return QuadPotentialSparse(C, rng=rng)\n        else:\n            raise ValueError("Sparse precision matrices are not supported")\n\n    partial_check_positive_definite(C)\n    if C.ndim == 1:\n        if is_cov:\n            return QuadPotentialDiag(C, rng=rng)\n        else:\n            return QuadPotentialDiag(1.0 / C, rng=rng)\n    else:\n        if is_cov:\n            return QuadPotentialFull(C, rng=rng)\n        else:\n            return QuadPotentialFullInv(C, rng=rng)\n\n\ndef partial_check_positive_definite(C):\n    """Make a simple but partial check for Positive Definiteness."""\n    if C.ndim == 1:\n        d = C\n    else:\n        d = np.diag(C)\n    (i,) = np.nonzero(np.logical_or(np.isnan(d), d <= 0))\n\n    if len(i):\n        raise PositiveDefiniteError("Simple check failed. Diagonal contains negatives", i)\n\n\nclass PositiveDefiniteError(ValueError):\n    def __init__(self, msg, idx):\n        super().__init__(msg)\n        self.idx = idx\n        self.msg = msg\n\n    def __str__(self):\n        return f"Scaling is not positive definite: {self.msg}. Check indexes {self.idx}."\n\n\n@dataclass_state\nclass PotentialState(DataClassState):\n    rng: np.random.Generator\n\n\nclass QuadPotential(WithSamplingState):\n    dtype: np.dtype\n\n    _state_class = PotentialState\n\n    def __init__(self, rng=None):\n        self.rng = get_random_generator(rng)\n\n    @overload\n    def velocity(self, x: np.ndarray, out: None) -> np.ndarray: ...\n\n    @overload\n    def velocity(self, x: np.ndarray, out: np.ndarray) -> None: ...\n\n    def velocity(self, x: np.ndarray, out: np.ndarray | None = None) -> np.ndarray | None:\n        """Compute the current velocity at a position in parameter space."""\n        raise NotImplementedError("Abstract method")\n\n    def energy(self, x, velocity=None):\n        raise NotImplementedError("Abstract method")\n\n    def random(self, x):\n        raise NotImplementedError("Abstract method")\n\n    def velocity_energy(self, x, v_out):\n        raise NotImplementedError("Abstract method")\n\n    def update(self, sample, grad, tune):\n        """Inform the potential about a new sample during tuning.\n\n        This can be used by adaptive potentials to change the\n        mass matrix.\n        """\n        pass\n\n    def raise_ok(self, map_info=None):\n        """Check if the mass matrix is ok, and raise ValueError if not.\n\n        Parameters\n        ----------\n        map_info: List of (name, shape, dtype)\n            List tuples with variable name, shape, and dtype.\n\n        Raises\n        ------\n        ValueError if any standard deviations are 0 or infinite\n\n        Returns\n        -------\n        None\n        """\n        return None\n\n    def reset(self):\n        pass\n\n    def stats(self):\n        return {"largest_eigval": np.nan, "smallest_eigval": np.nan}\n\n    def set_rng(self, rng: RandomGenerator):\n        self.rng = get_random_generator(rng, copy=False)\n\n\ndef isquadpotential(value):\n    """Check whether an object might be a QuadPotential object."""\n    return isinstance(value, QuadPotential)\n\n\n@dataclass_state\nclass QuadPotentialDiagAdaptState(PotentialState):\n    _var: np.ndarray\n    _stds: np.ndarray\n    _inv_stds: np.ndarray\n    _foreground_var: WeightedVarianceState\n    _background_var: WeightedVarianceState\n    _n_samples: int\n    adaptation_window: int\n    _mass_trace: list[np.ndarray] | None\n\n    dtype: Any = field(metadata={"frozen": True})\n    _n: int = field(metadata={"frozen": True})\n    _discard_window: int = field(metadata={"frozen": True})\n    _early_update: int = field(metadata={"frozen": True})\n    _initial_mean: np.ndarray = field(metadata={"frozen": True})\n    _initial_diag: np.ndarray = field(metadata={"frozen": True})\n    _initial_weight: np.ndarray = field(metadata={"frozen": True})\n    adaptation_window_multiplier: float = field(metadata={"frozen": True})\n    _store_mass_matrix_trace: bool = field(metadata={"frozen": True})\n\n\nclass QuadPotentialDiagAdapt(QuadPotential):\n    """Adapt a diagonal mass matrix from the sample variances."""\n\n    _state_class = QuadPotentialDiagAdaptState\n\n    def __init__(\n        self,\n        n,\n        initial_mean,\n        initial_diag=None,\n        initial_weight=0,\n        adaptation_window=101,\n        adaptation_window_multiplier=1,\n        dtype=None,\n        discard_window=50,\n        early_update=False,\n        store_mass_matrix_trace=False,\n        rng=None,\n    ):\n        """Set up a diagonal mass matrix.\n\n        Parameters\n        ----------\n        n : int\n            The number of parameters.\n        initial_mean : np.ndarray\n            An initial guess for the posterior mean of each parameter.\n        initial_diag : np.ndarray\n            An estimate of the posterior variance of each parameter.\n        initial_weight : int\n            How much weight the initial guess has compared to new samples during tuning.\n            Measured in equivalent number of samples.\n        adaptation_window : int\n            The size of the adaptation window during tuning. It specifies how many samples\n            are used to estimate the mass matrix in each section of the adaptation.\n        adaptation_window_multiplier : float\n            The factor with which we increase the adaptation window after each adaptation\n            window.\n        dtype : np.dtype\n            The dtype used to store the mass matrix\n        discard_window : int\n            The number of initial samples that are just discarded and not used to estimate\n            the mass matrix.\n        early_update : bool\n            Whether to update the mass matrix live during the first adaptation window.\n        store_mass_matrix_trace : bool\n            If true, store the mass matrix at each step of the adaptation. Only for debugging\n            purposes.\n        rng : Generator | int | None\n            Numpy random number generator\n        """\n        if initial_diag is not None and initial_diag.ndim != 1:\n            raise ValueError("Initial diagonal must be one-dimensional.")\n        if initial_mean.ndim != 1:\n            raise ValueError("Initial mean must be one-dimensional.")\n        if initial_diag is not None and len(initial_diag) != n:\n            raise ValueError(f"Wrong shape for initial_diag: expected {n} got {len(initial_diag)}")\n        if len(initial_mean) != n:\n            raise ValueError(f"Wrong shape for initial_mean: expected {n} got {len(initial_mean)}")\n\n        if dtype is None:\n            dtype = pytensor.config.floatX\n\n        if initial_diag is None:\n            initial_diag = np.ones(n, dtype=dtype)\n            initial_weight = 1\n\n        self.dtype = dtype\n        self._n = n\n\n        self._discard_window = discard_window\n        self._early_update = early_update\n\n        self._initial_mean = initial_mean\n        self._initial_diag = initial_diag\n        self._initial_weight = initial_weight\n        self.adaptation_window = adaptation_window\n        self.adaptation_window_multiplier = float(adaptation_window_multiplier)\n\n        self._store_mass_matrix_trace = store_mass_matrix_trace\n        self._mass_trace = []\n\n        super().__init__(rng=rng)\n\n        self.reset()\n\n    def reset(self):\n        self._var = np.array(self._initial_diag, dtype=self.dtype, copy=True)\n        self._var_pytensor = pytensor.shared(self._var)\n        self._stds = np.sqrt(self._initial_diag)\n        self._inv_stds = floatX(1.0) / self._stds\n        self._foreground_var = _WeightedVariance(\n            self._n, self._initial_mean, self._initial_diag, self._initial_weight, self.dtype\n        )\n        self._background_var = _WeightedVariance(self._n, dtype=self.dtype)\n        self._n_samples = 0\n\n    def velocity(self, x, out=None):\n        """Compute the current velocity at a position in parameter space."""\n        return np.multiply(self._var, x, out=out)\n\n    def energy(self, x, velocity=None):\n        """Compute kinetic energy at a position in parameter space."""\n        if velocity is not None:\n            return 0.5 * x.dot(velocity)\n        return 0.5 * x.dot(self._var * x)\n\n    def velocity_energy(self, x, v_out):\n        """Compute velocity and return kinetic energy at a position in parameter space."""\n        self.velocity(x, out=v_out)\n        return 0.5 * np.dot(x, v_out)\n\n    def random(self):\n        """Draw random value from QuadPotential."""\n        vals = self.rng.normal(size=self._n).astype(self.dtype)\n        return self._inv_stds * vals\n\n    def _update_from_weightvar(self, weightvar):\n        weightvar.current_variance(out=self._var)\n        self._var = np.clip(self._var, 1e-12, 1e12)\n        np.sqrt(self._var, out=self._stds)\n        np.divide(1, self._stds, out=self._inv_stds)\n        self._var_pytensor.set_value(self._var)\n\n    def update(self, sample, grad, tune):\n        """Inform the potential about a new sample during tuning."""\n        if self._store_mass_matrix_trace:\n            self._mass_trace.append(self._stds.copy())\n\n        if not tune:\n            return\n\n        if self._n_samples > self._discard_window:\n            self._foreground_var.add_sample(sample)\n            self._background_var.add_sample(sample)\n\n        if self._early_update or self._n_samples > self.adaptation_window:\n            self._update_from_weightvar(self._foreground_var)\n\n        if self._n_samples > 0 and self._n_samples % self.adaptation_window == 0:\n            self._foreground_var = self._background_var\n            self._background_var = _WeightedVariance(self._n, dtype=self.dtype)\n            self.adaptation_window = int(self.adaptation_window * self.adaptation_window_multiplier)\n\n        self._n_samples += 1\n\n    def raise_ok(self, map_info):\n        """Check if the mass matrix is ok, and raise ValueError if not.\n\n        Parameters\n        ----------\n        map_info: List of (name, shape, dtype)\n            List tuples with variable name, shape, and dtype.\n\n        Raises\n        ------\n        ValueError if any standard deviations are 0 or infinite\n\n        Returns\n        -------\n        None\n        """\n        if np.any(self._stds == 0):\n            errmsg = ["Mass matrix contains zeros on the diagonal. "]\n            last_idx = 0\n            for name, shape, size, dtype in map_info:\n                end = last_idx + size\n                index = np.where(self._stds[last_idx:end] == 0)[0]\n                errmsg.append(f"The derivative of RV `{name}`.ravel()[{index}] is zero.")\n                last_idx += end\n\n            raise ValueError("\\n".join(errmsg))\n\n        if np.any(~np.isfinite(self._stds)):\n            errmsg = ["Mass matrix contains non-finite values on the diagonal. "]\n\n            last_idx = 0\n            for name, shape, size, dtype in map_info:\n                end = last_idx + size\n                index = np.where(~np.isfinite(self._stds[last_idx:end]))[0]\n                errmsg.append(f"The derivative of RV `{name}`.ravel()[{index}] is non-finite.")\n                last_idx = end\n            raise ValueError("\\n".join(errmsg))\n\n\n@dataclass_state\nclass WeightedVarianceState(DataClassState):\n    n_samples: int\n    mean: np.ndarray\n    raw_var: np.ndarray\n\n    _dtype: Any = field(metadata={"frozen": True})\n\n\nclass _WeightedVariance(WithSamplingState):\n    """Online algorithm for computing mean of variance."""\n\n    _state_class = WeightedVarianceState\n\n    def __init__(\n        self, nelem, initial_mean=None, initial_variance=None, initial_weight=0, dtype="d"\n    ):\n        self._dtype = dtype\n        self.n_samples = float(initial_weight)\n        if initial_mean is None:\n            self.mean = np.zeros(nelem, dtype="d")\n        else:\n            self.mean = np.array(initial_mean, dtype="d", copy=True)\n        if initial_variance is None:\n            self.raw_var = np.zeros(nelem, dtype="d")\n        else:\n            self.raw_var = np.array(initial_variance, dtype="d", copy=True)\n\n        self.raw_var[:] *= self.n_samples\n\n        if self.raw_var.shape != (nelem,):\n            raise ValueError("Invalid shape for initial variance.")\n        if self.mean.shape != (nelem,):\n            raise ValueError("Invalid shape for initial mean.")\n\n    def add_sample(self, x):\n        x = np.asarray(x)\n        self.n_samples += 1\n        old_diff = x - self.mean\n        self.mean[:] += old_diff / self.n_samples\n        new_diff = x - self.mean\n        self.raw_var[:] += old_diff * new_diff\n\n    def current_variance(self, out=None):\n        if self.n_samples == 0:\n            raise ValueError("Can not compute variance without samples.")\n        if out is not None:\n            return np.divide(self.raw_var, self.n_samples, out=out)\n        else:\n            return (self.raw_var / self.n_samples).astype(self._dtype)\n\n    def current_mean(self):\n        return self.mean.copy(dtype=self._dtype)\n\n\n@dataclass_state\nclass ExpWeightedVarianceState(DataClassState):\n    _alpha: float\n    _mean: np.ndarray\n    _var: np.ndarray\n\n\nclass _ExpWeightedVariance(WithSamplingState):\n    _state_class = ExpWeightedVarianceState\n\n    def __init__(self, n_vars, *, init_mean, init_var, alpha):\n        self._variance = init_var\n        self._mean = init_mean\n        self._alpha = alpha\n\n    def add_sample(self, value):\n        alpha = self._alpha\n        delta = value - self._mean\n        self._mean[...] += alpha * delta\n        self._variance[...] = (1 - alpha) * (self._variance + alpha * delta**2)\n\n    def current_variance(self, out=None):\n        if out is None:\n            out = np.empty_like(self._variance)\n        np.copyto(out, self._variance)\n        return out\n\n    def current_mean(self, out=None):\n        if out is None:\n            out = np.empty_like(self._mean)\n        np.copyto(out, self._mean)\n        return out\n\n\n@dataclass_state\nclass QuadPotentialDiagAdaptExpState(QuadPotentialDiagAdaptState):\n    _alpha: float\n    _stop_adaptation: float\n    _variance_estimator: ExpWeightedVarianceState\n\n    _variance_estimator_grad: ExpWeightedVarianceState | None = None\n\n\nclass QuadPotentialDiagAdaptExp(QuadPotentialDiagAdapt):\n    _state_class = QuadPotentialDiagAdaptExpState\n\n    def __init__(self, *args, alpha, use_grads=False, stop_adaptation=None, rng=None, **kwargs):\n        """Set up a diagonal mass matrix.\n\n        Parameters\n        ----------\n        n : int\n            The number of parameters.\n        initial_mean : np.ndarray\n            An initial guess for the posterior mean of each parameter.\n        initial_diag : np.ndarray\n            An estimate of the posterior variance of each parameter.\n        alpha : float\n            Decay rate of the exponential weighted variance.\n        use_grads : bool\n            Use gradients, not only samples to estimate the mass matrix.\n        stop_adaptation : int\n            Stop the mass matrix adaptation after this many samples.\n        dtype : np.dtype\n            The dtype used to store the mass matrix\n        discard_window : int\n            The number of initial samples that are just discarded and not used to estimate\n            the mass matrix.\n        store_mass_matrix_trace : bool\n            If true, store the mass matrix at each step of the adaptation. Only for debugging\n            purposes.\n        rng: RandomGenerator\n            An object that can produce be used to produce the step method\'s\n            :py:class:`~numpy.random.Generator` object. Refer to\n            :py:func:`pymc.util.get_random_generator` for more information.\n        """\n        if len(args) > 3:\n            raise ValueError("Unsupported arguments to QuadPotentialDiagAdaptExp")\n\n        super().__init__(*args, rng=rng, **kwargs)\n        self._alpha = alpha\n        self._use_grads = use_grads\n\n        if stop_adaptation is None:\n            stop_adaptation = np.inf\n        self._stop_adaptation = stop_adaptation\n\n    def update(self, sample, grad, tune):\n        if tune and self._n_samples < self._stop_adaptation:\n            if self._n_samples > self._discard_window:\n                self._variance_estimator.add_sample(sample)\n                if self._use_grads:\n                    self._variance_estimator_grad.add_sample(grad)\n            elif self._n_samples == self._discard_window:\n                self._variance_estimator = _ExpWeightedVariance(\n                    self._n,\n                    init_mean=sample.copy(),\n                    init_var=np.zeros_like(sample),\n                    alpha=self._alpha,\n                )\n                if self._use_grads:\n                    self._variance_estimator_grad = _ExpWeightedVariance(\n                        self._n,\n                        init_mean=grad.copy(),\n                        init_var=np.zeros_like(grad),\n                        alpha=self._alpha,\n                    )\n\n            if self._n_samples > 2 * self._discard_window:\n                if self._use_grads:\n                    self._update_from_variances(\n                        self._variance_estimator, self._variance_estimator_grad\n                    )\n                else:\n                    self._update_from_weightvar(self._variance_estimator)\n\n            self._n_samples += 1\n\n        if self._store_mass_matrix_trace:\n            self._mass_trace.append(self._stds.copy())\n\n    def _update_from_variances(self, var_estimator, inv_var_estimator):\n        var = var_estimator.current_variance()\n        inv_var = inv_var_estimator.current_variance()\n        updated = np.sqrt(var / inv_var)\n        self._var[:] = updated\n        np.sqrt(updated, out=self._stds)\n        np.divide(1, self._stds, out=self._inv_stds)\n\n\nclass QuadPotentialDiag(QuadPotential):\n    """Quad potential using a diagonal covariance matrix."""\n\n    def __init__(self, v, dtype=None, rng=None):\n        """Use a vector to represent a diagonal matrix for a covariance matrix.\n\n        Parameters\n        ----------\n        v: vector, 0 <= ndim <= 1\n           Diagonal of covariance matrix for the potential vector\n        dtype :\n            The dtype to assign to the resulting momentum\n        rng : RandomGenerator\n            An object that can produce be used to produce the step method\'s\n            :py:class:`~numpy.random.Generator` object. Refer to\n            :py:func:`pymc.util.get_random_generator` for more information.\n        """\n        if dtype is None:\n            dtype = pytensor.config.floatX\n        self.dtype = dtype\n        v = v.astype(self.dtype)\n        s = v**0.5\n\n        self.s = s\n        self.inv_s = 1.0 / s\n        self.v = v\n        self.rng = get_random_generator(rng)\n\n    def velocity(self, x, out=None):\n        """Compute the current velocity at a position in parameter space."""\n        if out is not None:\n            np.multiply(x, self.v, out=out)\n            return\n        return self.v * x\n\n    def random(self):\n        """Draw random value from QuadPotential."""\n        return floatX(self.rng.normal(size=self.s.shape)) * self.inv_s\n\n    def energy(self, x, velocity=None):\n        """Compute kinetic energy at a position in parameter space."""\n        if velocity is not None:\n            return 0.5 * np.dot(x, velocity)\n        return 0.5 * x.dot(self.v * x)\n\n    def velocity_energy(self, x, v_out):\n        """Compute velocity and return kinetic energy at a position in parameter space."""\n        np.multiply(x, self.v, out=v_out)\n        return 0.5 * np.dot(x, v_out)\n\n\nclass QuadPotentialFullInv(QuadPotential):\n    """QuadPotential object for Hamiltonian calculations using inverse of covariance matrix."""\n\n    def __init__(self, A, dtype=None, rng=None):\n        """Compute the lower cholesky decomposition of the potential.\n\n        Parameters\n        ----------\n        A: matrix, ndim = 2\n           Inverse of covariance matrix for the potential vector\n        dtype :\n            The dtype to assign to the resulting momentum\n        rng : RandomGenerator\n            An object that can produce be used to produce the step method\'s\n            :py:class:`~numpy.random.Generator` object. Refer to\n            :py:func:`pymc.util.get_random_generator` for more information.\n        """\n        if dtype is None:\n            dtype = pytensor.config.floatX\n        self.dtype = dtype\n        self.L = floatX(scipy.linalg.cholesky(A, lower=True))\n        self.rng = get_random_generator(rng)\n\n    def velocity(self, x, out=None):\n        """Compute the current velocity at a position in parameter space."""\n        vel = scipy.linalg.cho_solve((self.L, True), x)\n        if out is None:\n            return vel\n        out[:] = vel\n\n    def random(self):\n        """Draw random value from QuadPotential."""\n        n = floatX(self.rng.normal(size=self.L.shape[0]))\n        return np.dot(self.L, n)\n\n    def energy(self, x, velocity=None):\n        """Compute kinetic energy at a position in parameter space."""\n        if velocity is None:\n            velocity = self.velocity(x)\n        return 0.5 * x.dot(velocity)\n\n    def velocity_energy(self, x, v_out):\n        """Compute velocity and return kinetic energy at a position in parameter space."""\n        self.velocity(x, out=v_out)\n        return 0.5 * np.dot(x, v_out)\n\n\nclass QuadPotentialFull(QuadPotential):\n    """Basic QuadPotential object for Hamiltonian calculations."""\n\n    def __init__(self, cov, dtype=None, rng=None):\n        """Compute the lower cholesky decomposition of the potential.\n\n        Parameters\n        ----------\n        A: matrix, ndim = 2\n            scaling matrix for the potential vector\n        dtype :\n            The dtype to assign to the resulting momentum\n        rng : RandomGenerator\n            An object that can produce be used to produce the step method\'s\n            :py:class:`~numpy.random.Generator` object. Refer to\n            :py:func:`pymc.util.get_random_generator` for more information.\n        """\n        if dtype is None:\n            dtype = pytensor.config.floatX\n        self.dtype = dtype\n        self._cov = np.array(cov, dtype=self.dtype, copy=True)\n        self._chol = scipy.linalg.cholesky(self._cov, lower=True)\n        self._n = len(self._cov)\n        self.rng = get_random_generator(rng)\n\n    def velocity(self, x, out=None):\n        """Compute the current velocity at a position in parameter space."""\n        return np.dot(self._cov, x, out=out)\n\n    def random(self):\n        """Draw random value from QuadPotential."""\n        vals = self.rng.normal(size=self._n).astype(self.dtype)\n        return scipy.linalg.solve_triangular(self._chol.T, vals, overwrite_b=True)\n\n    def energy(self, x, velocity=None):\n        """Compute kinetic energy at a position in parameter space."""\n        if velocity is None:\n            velocity = self.velocity(x)\n        return 0.5 * np.dot(x, velocity)\n\n    def velocity_energy(self, x, v_out):\n        """Compute velocity and return kinetic energy at a position in parameter space."""\n        self.velocity(x, out=v_out)\n        return self.energy(x, v_out)\n\n    __call__ = random\n\n\n@dataclass_state\nclass QuadPotentialFullAdaptState(PotentialState):\n    _previous_update: int\n    _cov: np.ndarray\n    _chol: np.ndarray\n    _chol_error: scipy.linalg.LinAlgError | ValueError | None = None\n    _foreground_cov: WeightedCovarianceState\n    _background_cov: WeightedCovarianceState\n    _n_samples: int\n    adaptation_window: int\n\n    dtype: Any = field(metadata={"frozen": True})\n    _n: int = field(metadata={"frozen": True})\n    _update_window: int = field(metadata={"frozen": True})\n    _initial_mean: np.ndarray = field(metadata={"frozen": True})\n    _initial_cov: np.ndarray = field(metadata={"frozen": True})\n    _initial_weight: np.ndarray = field(metadata={"frozen": True})\n    adaptation_window_multiplier: float = field(metadata={"frozen": True})\n\n\nclass QuadPotentialFullAdapt(QuadPotentialFull):\n    """Adapt a dense mass matrix using the sample covariances."""\n\n    _state_class = QuadPotentialFullAdaptState\n\n    def __init__(\n        self,\n        n,\n        initial_mean,\n        initial_cov=None,\n        initial_weight=0,\n        adaptation_window=101,\n        adaptation_window_multiplier=2,\n        update_window=1,\n        dtype=None,\n        rng=None,\n    ):\n        warnings.warn("QuadPotentialFullAdapt is an experimental feature")\n\n        if initial_cov is not None and initial_cov.ndim != 2:\n            raise ValueError("Initial covariance must be two-dimensional.")\n        if initial_mean.ndim != 1:\n            raise ValueError("Initial mean must be one-dimensional.")\n        if initial_cov is not None and initial_cov.shape != (n, n):\n            raise ValueError(f"Wrong shape for initial_cov: expected {n} got {initial_cov.shape}")\n        if len(initial_mean) != n:\n            raise ValueError(f"Wrong shape for initial_mean: expected {n} got {len(initial_mean)}")\n\n        if dtype is None:\n            dtype = pytensor.config.floatX\n\n        if initial_cov is None:\n            initial_cov = np.eye(n, dtype=dtype)\n            initial_weight = 1\n\n        self.dtype = dtype\n        self._n = n\n        self._initial_mean = initial_mean\n        self._initial_cov = initial_cov\n        self._initial_weight = initial_weight\n\n        self.adaptation_window = int(adaptation_window)\n        self.adaptation_window_multiplier = float(adaptation_window_multiplier)\n        self._update_window = int(update_window)\n\n        self.rng = get_random_generator(rng)\n\n        self.reset()\n\n    def reset(self):\n        self._previous_update = 0\n        self._cov = np.array(self._initial_cov, dtype=self.dtype, copy=True)\n        self._chol = scipy.linalg.cholesky(self._cov, lower=True)\n        self._chol_error = None\n        self._foreground_cov = _WeightedCovariance(\n            self._n, self._initial_mean, self._initial_cov, self._initial_weight, self.dtype\n        )\n        self._background_cov = _WeightedCovariance(self._n, dtype=self.dtype)\n        self._n_samples = 0\n\n    def _update_from_weightvar(self, weightvar):\n        weightvar.current_covariance(out=self._cov)\n        try:\n            self._chol = scipy.linalg.cholesky(self._cov, lower=True)\n        except (scipy.linalg.LinAlgError, ValueError) as error:\n            self._chol_error = error\n\n    def update(self, sample, grad, tune):\n        if not tune:\n            return\n\n        # Steps since previous update\n        delta = self._n_samples - self._previous_update\n\n        self._foreground_cov.add_sample(sample)\n        self._background_cov.add_sample(sample)\n\n        # Update the covariance matrix and recompute the Cholesky factorization\n        # every "update_window" steps\n        if (delta + 1) % self._update_window == 0:\n            self._update_from_weightvar(self._foreground_cov)\n\n        # Reset the background covariance if we are at the end of the adaptation\n        # window.\n        if delta >= self.adaptation_window:\n            self._foreground_cov = self._background_cov\n            self._background_cov = _WeightedCovariance(self._n, dtype=self.dtype)\n\n            self._previous_update = self._n_samples\n            self.adaptation_window = int(self.adaptation_window * self.adaptation_window_multiplier)\n\n        self._n_samples += 1\n\n    def raise_ok(self, vmap):\n        if self._chol_error is not None:\n            raise ValueError(str(self._chol_error))\n\n\n@dataclass_state\nclass WeightedCovarianceState(DataClassState):\n    n_samples: float\n    mean: np.ndarray\n    raw_cov: np.ndarray\n\n    _dtype: Any = field(metadata={"frozen": True})\n\n\nclass _WeightedCovariance(WithSamplingState):\n    """Online algorithm for computing mean and covariance.\n\n    This implements the `Welford\'s algorithm\n    <https://en.wikipedia.org/wiki/Algorithms_for_calculating_variance>`_ based\n    on the implementation in `the Stan math library\n    <https://github.com/stan-dev/math>`_.\n\n    """\n\n    _state_class = WeightedCovarianceState\n\n    def __init__(\n        self,\n        nelem,\n        initial_mean=None,\n        initial_covariance=None,\n        initial_weight=0,\n        dtype="d",\n    ):\n        self._dtype = dtype\n        self.n_samples = float(initial_weight)\n        if initial_mean is None:\n            self.mean = np.zeros(nelem, dtype="d")\n        else:\n            self.mean = np.array(initial_mean, dtype="d", copy=True)\n        if initial_covariance is None:\n            self.raw_cov = np.eye(nelem, dtype="d")\n        else:\n            self.raw_cov = np.array(initial_covariance, dtype="d", copy=True)\n\n        self.raw_cov[:] *= self.n_samples\n\n        if self.raw_cov.shape != (nelem, nelem):\n            raise ValueError("Invalid shape for initial covariance.")\n        if self.mean.shape != (nelem,):\n            raise ValueError("Invalid shape for initial mean.")\n\n    def add_sample(self, x):\n        x = np.asarray(x)\n        self.n_samples += 1\n        old_diff = x - self.mean\n        self.mean[:] += old_diff / self.n_samples\n        new_diff = x - self.mean\n        self.raw_cov[:] += new_diff[:, None] * old_diff[None, :]\n\n    def current_covariance(self, out=None):\n        if self.n_samples == 0:\n            raise ValueError("Can not compute covariance without samples.")\n        if out is not None:\n            return np.divide(self.raw_cov, self.n_samples - 1, out=out)\n        else:\n            return (self.raw_cov / (self.n_samples - 1)).astype(self._dtype)\n\n    def current_mean(self):\n        return np.array(self.mean, dtype=self._dtype)\n\n\ntry:\n    import sksparse.cholmod as cholmod\n\n    chol_available = True\nexcept ImportError:\n    chol_available = False\n\nif chol_available:\n    __all__ += ["QuadPotentialSparse"]\n\n    import pytensor.sparse\n\n    class QuadPotentialSparse(QuadPotential):\n        def __init__(self, A, rng=None):\n            """Compute a sparse cholesky decomposition of the potential.\n\n            Parameters\n            ----------\n            A: matrix, ndim = 2\n                scaling matrix for the potential vector\n            rng : RandomGenerator\n                An object that can produce be used to produce the step method\'s\n                :py:class:`~numpy.random.Generator` object. Refer to\n                :py:func:`pymc.util.get_random_generator` for more information.\n            """\n            self.A = A\n            self.size = A.shape[0]\n            self.factor = factor = cholmod.cholesky(A)\n            self.d_sqrt = np.sqrt(factor.D())\n            self.rng = get_random_generator(rng)\n\n        def velocity(self, x):\n            """Compute the current velocity at a position in parameter space."""\n            A = pytensor.sparse.as_sparse(self.A)\n            return pytensor.sparse.dot(A, x)\n\n        def random(self):\n            """Draw random value from QuadPotential."""\n            n = floatX(self.rng.normal(size=self.size))\n            n /= self.d_sqrt\n            n = self.factor.solve_Lt(n)\n            n = self.factor.apply_Pt(n)\n            return n\n\n        def energy(self, x):\n            """Compute kinetic energy at a position in parameter space."""\n            return 0.5 * x.T.dot(self.velocity(x))\n',
            'pymc/step_methods/state.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nfrom copy import deepcopy\nfrom dataclasses import Field, dataclass, fields\nfrom typing import Any, ClassVar\n\nimport numpy as np\n\ndataclass_state = dataclass(kw_only=True)\n\n\n@dataclass_state\nclass DataClassState:\n    __dataclass_fields__: ClassVar[dict[str, Field[Any]]] = {}\n\n\ndef equal_dataclass_values(v1, v2):\n    if v1.__class__ != v2.__class__:\n        return False\n    if isinstance(v1, (list, tuple)):  # noqa: UP038\n        return len(v1) == len(v2) and all(\n            equal_dataclass_values(v1i, v2i) for v1i, v2i in zip(v1, v2, strict=True)\n        )\n    elif isinstance(v1, dict):\n        if set(v1) != set(v2):\n            return False\n        return all(equal_dataclass_values(v1[k], v2[k]) for k in v1)\n    elif isinstance(v1, np.ndarray):\n        return bool(np.array_equal(v1, v2, equal_nan=True))\n    elif isinstance(v1, np.random.Generator):\n        return equal_dataclass_values(v1.bit_generator.state, v2.bit_generator.state)\n    elif isinstance(v1, DataClassState):\n        return set(fields(v1)) == set(fields(v2)) and all(\n            equal_dataclass_values(getattr(v1, f1.name), getattr(v2, f2.name))\n            for f1, f2 in zip(fields(v1), fields(v2), strict=True)\n        )\n    else:\n        return v1 == v2\n\n\nclass WithSamplingState:\n    """Mixin class that adds the ``sampling_state`` property to an object.\n\n    The object\'s type must define the ``_state_class`` as a valid\n    :py:class:`~pymc.step_method.DataClassState`. Once that happens, the\n    object\'s ``sampling_state`` property can be read or set to get\n    the state represented as objects of the ``_state_class`` type.\n    """\n\n    _state_class: type[DataClassState] = DataClassState\n\n    @property\n    def sampling_state(self) -> DataClassState:\n        state_class = self._state_class\n        kwargs = {}\n        for field in fields(state_class):\n            val = getattr(self, field.name)\n            if isinstance(val, WithSamplingState):\n                _val = val.sampling_state\n            else:\n                _val = val\n            kwargs[field.name] = deepcopy(_val)\n        return state_class(**kwargs)\n\n    @sampling_state.setter\n    def sampling_state(self, state: DataClassState):\n        state_class = self._state_class\n        assert isinstance(\n            state, state_class\n        ), f"Encountered invalid state class \'{state.__class__}\'. State must be \'{state_class}\'"\n        for field in fields(state_class):\n            state_val = deepcopy(getattr(state, field.name))\n            self_val = getattr(self, field.name)\n            is_frozen = field.metadata.get("frozen", False)\n            if is_frozen:\n                if not equal_dataclass_values(state_val, self_val):\n                    raise ValueError(\n                        "The received sampling state must have the same values for the "\n                        f"frozen fields. Field {field.name!r} has different values. "\n                        f"Expected {self_val} but got {state_val}"\n                    )\n            else:\n                if isinstance(state_val, DataClassState):\n                    assert isinstance(self_val, WithSamplingState)\n                    self_val.sampling_state = state_val\n                    setattr(self, field.name, self_val)\n                else:\n                    setattr(self, field.name, state_val)\n',
            'pymc/util.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nimport functools\nimport warnings\n\nfrom collections.abc import Sequence\nfrom copy import deepcopy\nfrom typing import NewType, cast\n\nimport arviz\nimport cloudpickle\nimport numpy as np\nimport xarray\n\nfrom cachetools import LRUCache, cachedmethod\nfrom pytensor import Variable\nfrom pytensor.compile import SharedVariable\nfrom pytensor.graph.utils import ValidatingScratchpad\nfrom rich.progress import Progress\nfrom rich.theme import Theme\n\nfrom pymc.exceptions import BlockModelAccessError\n\n\ndef __getattr__(name):\n    if name == "dataset_to_point_list":\n        warnings.warn(\n            f"{name} has been moved to backends.arviz. Importing from util will fail in a future release.",\n            FutureWarning,\n        )\n        from pymc.backends.arviz import dataset_to_point_list\n\n        return dataset_to_point_list\n\n    raise AttributeError(f"module {__name__} has no attribute {name}")\n\n\nVarName = NewType("VarName", str)\n\ndefault_progress_theme = Theme(\n    {\n        "bar.complete": "#1764f4",\n        "bar.finished": "green",\n    }\n)\n\n\nclass _UnsetType:\n    """Type for the `UNSET` object to make it look nice in `help(...)` outputs."""\n\n    def __str__(self):\n        return "UNSET"\n\n    def __repr__(self):\n        return str(self)\n\n\nUNSET = _UnsetType()\n\n\ndef withparent(meth):\n    """Pass calls to parent\'s instance."""\n\n    def wrapped(self, *args, **kwargs):\n        res = meth(self, *args, **kwargs)\n        if getattr(self, "parent", None) is not None:\n            getattr(self.parent, meth.__name__)(*args, **kwargs)\n        return res\n\n    # Unfortunately functools wrapper fails\n    # when decorating built-in methods so we\n    # need to fix that improper behaviour\n    wrapped.__name__ = meth.__name__\n    return wrapped\n\n\nclass treelist(list):\n    """A list that passes mutable extending operations used in Model to parent list instance.\n\n    Extending treelist you will also extend its parent.\n    """\n\n    def __init__(self, iterable=(), parent=None):\n        super().__init__(iterable)\n        assert isinstance(parent, list) or parent is None\n        self.parent = parent\n        if self.parent is not None:\n            self.parent.extend(self)\n\n    # here typechecking works bad\n    append = withparent(list.append)\n    __iadd__ = withparent(list.__iadd__)\n    extend = withparent(list.extend)\n\n    def tree_contains(self, item):\n        if isinstance(self.parent, treedict):\n            return list.__contains__(self, item) or self.parent.tree_contains(item)\n        elif isinstance(self.parent, list):\n            return list.__contains__(self, item) or self.parent.__contains__(item)\n        else:\n            return list.__contains__(self, item)\n\n    def __setitem__(self, key, value):\n        """Set value at index `key` with value `value`."""\n        raise NotImplementedError(\n            "Method is removed as we are not able to determine appropriate logic for it"\n        )\n\n    # Added this because mypy didn\'t like having __imul__ without __mul__\n    # This is my best guess about what this should do.  I might be happier\n    # to kill both of these if they are not used.\n    def __mul__(self, other) -> "treelist":\n        """Multiplication."""\n        return cast("treelist", super().__mul__(other))\n\n    def __imul__(self, other) -> "treelist":\n        """Inplace multiplication."""\n        t0 = len(self)\n        super().__imul__(other)\n        if self.parent is not None:\n            self.parent.extend(self[t0:])\n        return self  # python spec says should return the result.\n\n\nclass treedict(dict):\n    """A dict that passes mutable extending operations used in Model to parent dict instance.\n\n    Extending treedict you will also extend its parent.\n    """\n\n    def __init__(self, iterable=(), parent=None, **kwargs):\n        super().__init__(iterable, **kwargs)\n        assert isinstance(parent, dict) or parent is None\n        self.parent = parent\n        if self.parent is not None:\n            self.parent.update(self)\n\n    # here typechecking works bad\n    __setitem__ = withparent(dict.__setitem__)\n    update = withparent(dict.update)\n\n    def tree_contains(self, item):\n        # needed for `add_named_variable` method\n        if isinstance(self.parent, treedict):\n            return dict.__contains__(self, item) or self.parent.tree_contains(item)\n        elif isinstance(self.parent, dict):\n            return dict.__contains__(self, item) or self.parent.__contains__(item)\n        else:\n            return dict.__contains__(self, item)\n\n\ndef get_transformed_name(name, transform):\n    r"""\n    Consistent way of transforming names.\n\n    Parameters\n    ----------\n    name: str\n        Name to transform\n    transform: transforms.Transform\n        Should be a subclass of `transforms.Transform`\n\n    Returns\n    -------\n    str\n        A string to use for the transformed variable\n    """\n    return f"{name}_{transform.name}__"\n\n\ndef is_transformed_name(name):\n    r"""\n    Quickly check if a name was transformed with `get_transformed_name`.\n\n    Parameters\n    ----------\n    name: str\n        Name to check\n\n    Returns\n    -------\n    bool\n        Boolean, whether the string could have been produced by `get_transformed_name`\n    """\n    return name.endswith("__") and name.count("_") >= 3\n\n\ndef get_untransformed_name(name):\n    r"""\n    Undo transformation in `get_transformed_name`. Throws ValueError if name wasn\'t transformed.\n\n    Parameters\n    ----------\n    name: str\n        Name to untransform\n\n    Returns\n    -------\n    str\n        String with untransformed version of the name.\n    """\n    if not is_transformed_name(name):\n        raise ValueError(f"{name} does not appear to be a transformed name")\n    return "_".join(name.split("_")[:-3])\n\n\ndef get_default_varnames(var_iterator, include_transformed):\n    r"""Extract default varnames from a trace.\n\n    Parameters\n    ----------\n    varname_iterator: iterator\n        Elements will be cast to string to check whether it is transformed, and optionally filtered\n    include_transformed: boolean\n        Should transformed variable names be included in return value\n\n    Returns\n    -------\n    list\n        List of variables, possibly filtered\n    """\n    if include_transformed:\n        return list(var_iterator)\n    else:\n        return [var for var in var_iterator if not is_transformed_name(get_var_name(var))]\n\n\ndef get_var_name(var) -> VarName:\n    """Get an appropriate, plain variable name for a variable."""\n    return VarName(str(getattr(var, "name", var)))\n\n\ndef get_transformed(z):\n    if hasattr(z, "transformed"):\n        z = z.transformed\n    return z\n\n\ndef biwrap(wrapper):\n    @functools.wraps(wrapper)\n    def enhanced(*args, **kwargs):\n        is_bound_method = hasattr(args[0], wrapper.__name__) if args else False\n        if is_bound_method:\n            count = 1\n        else:\n            count = 0\n        if len(args) > count:\n            newfn = wrapper(*args, **kwargs)\n            return newfn\n        else:\n            newwrapper = functools.partial(wrapper, *args, **kwargs)\n            return newwrapper\n\n    return enhanced\n\n\ndef drop_warning_stat(idata: arviz.InferenceData) -> arviz.InferenceData:\n    """Return a new ``InferenceData`` object with the "warning" stat removed from sample stats groups.\n\n    This function should be applied to an ``InferenceData`` object obtained with\n    ``pm.sample(keep_warning_stat=True)`` before trying to ``.to_netcdf()`` or ``.to_zarr()`` it.\n    """\n    nidata = arviz.InferenceData(attrs=idata.attrs)\n    for gname, group in idata.items():\n        if "sample_stat" in gname:\n            group = group.drop_vars(names=["warning", "warning_dim_0"], errors="ignore")\n        nidata.add_groups({gname: group}, coords=group.coords, dims=group.dims)\n    return nidata\n\n\ndef chains_and_samples(data: xarray.Dataset | arviz.InferenceData) -> tuple[int, int]:\n    """Extract and return number of chains and samples in xarray or arviz traces."""\n    dataset: xarray.Dataset\n    if isinstance(data, xarray.Dataset):\n        dataset = data\n    elif isinstance(data, arviz.InferenceData):\n        dataset = data["posterior"]\n    else:\n        raise ValueError(\n            "Argument must be xarray Dataset or arviz InferenceData. Got %s",\n            data.__class__,\n        )\n\n    coords = dataset.coords\n    nchains = coords["chain"].sizes["chain"]\n    nsamples = coords["draw"].sizes["draw"]\n    return nchains, nsamples\n\n\ndef hashable(a=None) -> int:\n    """\n    Hash many kinds of objects, including some that are unhashable through the builtin `hash` function.\n\n    Lists and tuples are hashed based on their elements.\n    """\n    if isinstance(a, dict):\n        # first hash the keys and values with hashable\n        # then hash the tuple of int-tuples with the builtin\n        return hash(tuple((hashable(k), hashable(v)) for k, v in a.items()))\n    if isinstance(a, tuple | list):\n        # lists are mutable and not hashable by default\n        # for memoization, we need the hash to depend on the items\n        return hash(tuple(hashable(i) for i in a))\n    try:\n        return hash(a)\n    except TypeError:\n        pass\n    # Not hashable >>>\n    try:\n        return hash(cloudpickle.dumps(a))\n    except Exception:\n        if hasattr(a, "__dict__"):\n            return hashable(a.__dict__)\n        else:\n            return id(a)\n\n\ndef hash_key(*args, **kwargs):\n    return tuple(HashableWrapper(a) for a in args + tuple(kwargs.items()))\n\n\nclass HashableWrapper:\n    __slots__ = ("obj",)\n\n    def __init__(self, obj):\n        self.obj = obj\n\n    def __hash__(self):\n        """Return a hash of the object."""\n        return hashable(self.obj)\n\n    def __eq__(self, other):\n        """Compare this object with `other`."""\n        return self.obj == other\n\n    def __repr__(self):\n        """Return a string representation of the object."""\n        return f"{type(self).__name__}({self.obj})"\n\n\nclass WithMemoization:\n    def __hash__(self):\n        """Return a hash of the object."""\n        return hash(id(self))\n\n    def __getstate__(self):\n        """Return an object to pickle."""\n        state = self.__dict__.copy()\n        state.pop("_cache", None)\n        return state\n\n    def __setstate__(self, state):\n        """Set the object from a pickled object."""\n        self.__dict__.update(state)\n\n\ndef locally_cachedmethod(f):\n    from collections import defaultdict\n\n    def self_cache_fn(f_name):\n        def cf(self):\n            return self.__dict__.setdefault("_cache", defaultdict(lambda: LRUCache(128)))[f_name]\n\n        return cf\n\n    return cachedmethod(self_cache_fn(f.__name__), key=hash_key)(f)\n\n\ndef check_dist_not_registered(dist, model=None):\n    """Check that a dist is not registered in the model already."""\n    from pymc.model import modelcontext\n\n    try:\n        model = modelcontext(None)\n    except (TypeError, BlockModelAccessError):\n        pass\n    else:\n        if dist in model.basic_RVs:\n            raise ValueError(\n                f"The dist {dist} was already registered in the current model.\\n"\n                f"You should use an unregistered (unnamed) distribution created via "\n                f"the `.dist()` API instead, such as:\\n`dist=pm.Normal.dist(0, 1)`"\n            )\n\n\ndef point_wrapper(core_function):\n    """\n    Wrap a pytensor compiled function to ingest point dictionaries.\n\n    It ignores the keys that are not valid inputs to the core function.\n    """\n    ins = [i.name for i in core_function.maker.fgraph.inputs if not isinstance(i, SharedVariable)]\n\n    def wrapped(**kwargs):\n        input_point = {k: v for k, v in kwargs.items() if k in ins}\n        return core_function(**input_point)\n\n    return wrapped\n\n\nRandomSeed = None | int | Sequence[int] | np.ndarray\nRandomState = RandomSeed | np.random.RandomState | np.random.Generator\nRandomGenerator = RandomSeed | np.random.Generator | np.random.BitGenerator\n\n\ndef _get_seeds_per_chain(\n    random_state: RandomState,\n    chains: int,\n) -> Sequence[int] | np.ndarray:\n    """Obtain or validate specified integer seeds per chain.\n\n    This function process different possible sources of seeding and returns one integer\n    seed per chain:\n    1. If the input is an integer and a single chain is requested, the input is\n        returned inside a tuple.\n    2. If the input is a sequence or NumPy array with as many entries as chains,\n        the input is returned.\n    3. If the input is an integer and multiple chains are requested, new unique seeds\n        are generated from NumPy default Generator seeded with that integer.\n    4. If the input is None new unique seeds are generated from an unseeded NumPy default\n        Generator.\n    5. If a RandomState or Generator is provided, new unique seeds are generated from it.\n\n    Raises\n    ------\n    ValueError\n        If none of the conditions above are met\n    """\n\n    def _get_unique_seeds_per_chain(integers_fn):\n        seeds = []\n        while len(set(seeds)) != chains:\n            seeds = [int(seed) for seed in integers_fn(2**30, dtype=np.int64, size=chains)]\n        return seeds\n\n    try:\n        int_random_state = int(random_state)  # type: ignore[arg-type]\n    except Exception:\n        int_random_state = None\n\n    if random_state is None or int_random_state is not None:\n        if chains == 1 and int_random_state is not None:\n            return (int_random_state,)\n        return _get_unique_seeds_per_chain(np.random.default_rng(int_random_state).integers)\n    if isinstance(random_state, np.random.Generator):\n        return _get_unique_seeds_per_chain(random_state.integers)\n    if isinstance(random_state, np.random.RandomState):\n        return _get_unique_seeds_per_chain(random_state.randint)\n\n    if not isinstance(random_state, list | tuple | np.ndarray):\n        raise ValueError(f"The `seeds` must be array-like. Got {type(random_state)} instead.")\n\n    if len(random_state) != chains:\n        raise ValueError(\n            f"Number of seeds ({len(random_state)}) does not match the number of chains ({chains})."\n        )\n\n    return random_state\n\n\ndef get_value_vars_from_user_vars(vars: Variable | Sequence[Variable], model) -> list[Variable]:\n    """Convert user "vars" input into value variables.\n\n    More often than not, users will pass random variables, and we will extract the\n    respective value variables, but we also allow for the input to already be value\n    variables, in case the function is called internally or by a "super-user"\n\n    Returns\n    -------\n    value_vars: list of TensorVariable\n        List of model value variables that correspond to the input vars\n\n    Raises\n    ------\n    ValueError:\n        If any of the provided variables do not correspond to any model value variable\n    """\n    if not isinstance(vars, Sequence):\n        # Single var was passed\n        value_vars = [model.rvs_to_values.get(vars, vars)]\n    else:\n        value_vars = [model.rvs_to_values.get(var, var) for var in vars]\n\n    # Check that we only have value vars from the model\n    model_value_vars = model.value_vars\n    notin = [v for v in value_vars if v not in model_value_vars]\n    if notin:\n        notin = list(map(get_var_name, notin))\n        # We mention random variables, even though the input may be a wrong value variable\n        # because most users don\'t know about that duality\n        raise ValueError(\n            "The following variables are not random variables in the model: " + str(notin)\n        )\n\n    return value_vars\n\n\nclass _FutureWarningValidatingScratchpad(ValidatingScratchpad):\n    def __getattribute__(self, name):\n        for deprecated_names, alternative in (\n            (("value_var", "observations"), "model.rvs_to_values[rv]"),\n            (("transform",), "model.rvs_to_transforms[rv]"),\n        ):\n            if name in deprecated_names:\n                try:\n                    super().__getattribute__(name)\n                except AttributeError:\n                    pass\n                else:\n                    warnings.warn(\n                        f"The tag attribute {name} is deprecated. Use {alternative} instead",\n                        FutureWarning,\n                    )\n        return super().__getattribute__(name)\n\n\ndef _add_future_warning_tag(var) -> None:\n    old_tag = var.tag\n    if not isinstance(old_tag, _FutureWarningValidatingScratchpad):\n        new_tag = _FutureWarningValidatingScratchpad("test_value", var.type.filter)\n        for k, v in old_tag.__dict__.items():\n            new_tag.__dict__.setdefault(k, v)\n        var.tag = new_tag\n\n\ndef makeiter(a):\n    if isinstance(a, tuple | list):\n        return a\n    else:\n        return [a]\n\n\nclass CustomProgress(Progress):\n    """A child of Progress that allows to disable progress bars and its container.\n\n    The implementation simply checks an `is_enabled` flag and generates the progress bar only if\n    it\'s `True`.\n    """\n\n    def __init__(self, *args, **kwargs):\n        self.is_enabled = kwargs.get("disable", None) is not True\n        if self.is_enabled:\n            super().__init__(*args, **kwargs)\n\n    def __enter__(self):\n        """Enter the context manager."""\n        if self.is_enabled:\n            self.start()\n        return self\n\n    def __exit__(self, exc_type, exc_val, exc_tb):\n        """Exit the context manager."""\n        if self.is_enabled:\n            super().__exit__(exc_type, exc_val, exc_tb)\n\n    def add_task(self, *args, **kwargs):\n        if self.is_enabled:\n            return super().add_task(*args, **kwargs)\n        return None\n\n    def advance(self, task_id, advance=1) -> None:\n        if self.is_enabled:\n            super().advance(task_id, advance)\n        return None\n\n    def update(\n        self,\n        task_id,\n        *,\n        total=None,\n        completed=None,\n        advance=None,\n        description=None,\n        visible=None,\n        refresh=False,\n        **fields,\n    ):\n        if self.is_enabled:\n            super().update(\n                task_id,\n                total=total,\n                completed=completed,\n                advance=advance,\n                description=description,\n                visible=visible,\n                refresh=refresh,\n                **fields,\n            )\n        return None\n\n\ndef get_random_generator(\n    seed: RandomGenerator | np.random.RandomState = None, copy: bool = True\n) -> np.random.Generator:\n    """Build a :py:class:`~numpy.random.Generator` object from a suitable seed.\n\n    Parameters\n    ----------\n    seed : None | int | Sequence[int] | numpy.random.Generator | numpy.random.BitGenerator | numpy.random.RandomState\n        A suitable seed to use to generate the :py:class:`~numpy.random.Generator` object.\n        For more details on suitable seeds, refer to :py:func:`numpy.random.default_rng`.\n    copy : bool\n        Boolean flag that indicates whether to copy the seed object before feeding\n        it to :py:func:`numpy.random.default_rng`. If `copy` is `False`, and the seed\n        object is a ``BitGenerator`` or ``Generator`` object, the returned\n        ``Generator`` will use the ``seed`` object where possible. This means that it\n        will return the ``seed`` input object if it is a ``Generator`` or that it\n        will return a new ``Generator`` whose ``bit_generator`` attribute will be the\n        input ``seed`` object. To avoid this potential object sharing, you must set\n        ``copy`` to ``True``.\n\n    Returns\n    -------\n    rng : numpy.random.Generator\n        The result of passing the input ``seed`` (or a copy of it) through\n        :py:func:`numpy.random.default_rng`.\n\n    Raises\n    ------\n    TypeError:\n        If the supplied ``seed`` is a :py:class:`~numpy.random.RandomState` object. We\n        do not support using these legacy objects because their seeding strategy is not\n        amenable to spawning new independent random streams.\n    """\n    if isinstance(seed, np.random.RandomState):\n        raise TypeError(\n            "Cannot create a random Generator from a RandomStream object. "\n            "Please provide a random seed, BitGenerator or Generator instead."\n        )\n    if copy:\n        # If seed is a numpy.random.Generator or numpy.random.BitGenerator,\n        # numpy.random.default_rng will use the exact same object to return.\n        # In the former case, it will return seed, in the latter it will return\n        # a new Generator object that has the same BitGenerator. This would potentially\n        # make the new generator be shared across many users. To avoid this, we\n        # deepcopy by default.\n        seed = deepcopy(seed)\n    return np.random.default_rng(seed)\n',
            'tests/logprob/test_transform_value.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport gc\nimport operator\n\nimport numpy as np\nimport pytensor\nimport pytest\nimport scipy as sp\n\nfrom numdifftools import Jacobian\nfrom pytensor import scan\nfrom pytensor import tensor as pt\nfrom pytensor.compile.builders import OpFromGraph\nfrom pytensor.graph import FunctionGraph\nfrom pytensor.graph.basic import equal_computations\n\nimport pymc as pm\n\nfrom pymc.distributions.transforms import _default_transform, log, logodds\nfrom pymc.logprob import conditional_logp\nfrom pymc.logprob.abstract import MeasurableOp, _logprob\nfrom pymc.logprob.transform_value import TransformValuesMapping, TransformValuesRewrite\nfrom pymc.logprob.transforms import ExpTransform, LogOddsTransform, LogTransform\nfrom pymc.testing import assert_no_rvs\nfrom tests.logprob.test_transforms import DirichletScipyDist\n\n\n@pytest.fixture(scope="module")\ndef multiout_measurable_op():\n    # Create a dummy Op that just returns the two inputs\n    mu1, mu2 = pt.scalars("mu1", "mu2")\n\n    class TestOpFromGraph(MeasurableOp, OpFromGraph):\n        def do_constant_folding(self, fgraph, node):\n            False\n\n    multiout_op = TestOpFromGraph([mu1, mu2], [mu1 + 0.0, mu2 + 0.0])\n\n    @_logprob.register(TestOpFromGraph)\n    def logp_multiout(op, values, mu1, mu2):\n        value1, value2 = values\n        return value1 + mu1, value2 + mu2\n\n    return multiout_op\n\n\ndef test_TransformValuesMapping():\n    x = pt.vector()\n    fg = FunctionGraph(outputs=[x])\n\n    tvm = TransformValuesMapping({})\n    fg.attach_feature(tvm)\n\n    tvm2 = TransformValuesMapping({})\n    fg.attach_feature(tvm2)\n\n    assert fg._features[-1] is tvm\n\n\ndef test_original_values_output_dict():\n    """\n    Test that the original unconstrained value variable appears an the key of\n    the logprob factor\n    """\n    p_rv = pt.random.beta(1, 1, name="p")\n    p_vv = p_rv.clone()\n\n    tr = TransformValuesRewrite({p_vv: logodds})\n    logp_dict = conditional_logp({p_rv: p_vv}, extra_rewrites=tr)\n\n    assert p_vv in logp_dict\n\n\n@pytest.mark.parametrize(\n    "pt_dist, dist_params, sp_dist, size",\n    [\n        (pt.random.uniform, (0, 1), sp.stats.uniform, ()),\n        (\n            pt.random.pareto,\n            (1.5, 10.5),\n            lambda b, scale: sp.stats.pareto(b, scale=scale),\n            (),\n        ),\n        (\n            pt.random.triangular,\n            (1.5, 3.0, 10.5),\n            lambda lower, mode, upper: sp.stats.triang(\n                (mode - lower) / (upper - lower), loc=lower, scale=upper - lower\n            ),\n            (),\n        ),\n        (\n            pt.random.halfnormal,\n            (0, 1),\n            sp.stats.halfnorm,\n            (),\n        ),\n        pytest.param(\n            pt.random.wald,\n            (1.5, 10.5),\n            lambda mean, scale: sp.stats.invgauss(mean / scale, scale=scale),\n            (),\n            marks=pytest.mark.xfail(\n                reason="We don\'t use PyTensor\'s Wald operator",\n                raises=NotImplementedError,\n            ),\n        ),\n        (\n            pt.random.exponential,\n            (1.5,),\n            lambda mu: sp.stats.expon(scale=mu),\n            (),\n        ),\n        pytest.param(\n            pt.random.lognormal,\n            (-1.5, 10.5),\n            lambda mu, sigma: sp.stats.lognorm(s=sigma, loc=0, scale=np.exp(mu)),\n            (),\n        ),\n        (\n            pt.random.lognormal,\n            (-1.5, 1.5),\n            lambda mu, sigma: sp.stats.lognorm(s=sigma, scale=np.exp(mu)),\n            (),\n        ),\n        (\n            pt.random.halfcauchy,\n            (1.5, 10.5),\n            lambda alpha, beta: sp.stats.halfcauchy(loc=alpha, scale=beta),\n            (),\n        ),\n        (\n            pt.random.gamma,\n            (1.5, 10.5),\n            lambda alpha, inv_beta: sp.stats.gamma(alpha, scale=1.0 / inv_beta),\n            (),\n        ),\n        (\n            pt.random.invgamma,\n            (1.5, 10.5),\n            lambda alpha, beta: sp.stats.invgamma(alpha, scale=beta),\n            (),\n        ),\n        (\n            pm.ChiSquared.dist,\n            (1.5,),\n            lambda df: sp.stats.chi2(df),\n            (),\n        ),\n        pytest.param(\n            pt.random.weibull,\n            (1.5,),\n            lambda c: sp.stats.weibull_min(c),\n            (),\n            marks=pytest.mark.xfail(\n                reason="We don\'t use PyTensor\'s Weibull operator",\n                raises=NotImplementedError,\n            ),\n        ),\n        (\n            pt.random.beta,\n            (1.5, 1.5),\n            lambda alpha, beta: sp.stats.beta(alpha, beta),\n            (),\n        ),\n        (\n            pt.random.vonmises,\n            (1.5, 10.5),\n            lambda mu, kappa: sp.stats.vonmises(kappa, loc=mu),\n            (),\n        ),\n        (\n            pt.random.dirichlet,\n            (np.array([0.7, 0.3]),),\n            lambda alpha: sp.stats.dirichlet(alpha),\n            (),\n        ),\n        (\n            pt.random.dirichlet,\n            (np.array([[0.7, 0.3], [0.9, 0.1]]),),\n            lambda alpha: DirichletScipyDist(alpha),\n            None,\n        ),\n        pytest.param(\n            pt.random.dirichlet,\n            (np.array([0.3, 0.7]),),\n            lambda alpha: DirichletScipyDist(alpha),\n            (3, 2),\n        ),\n    ],\n)\ndef test_default_value_transform_logprob(pt_dist, dist_params, sp_dist, size):\n    """\n    This test takes a `RandomVariable` type, plus parameters, and uses it to\n    construct a variable ``a`` that\'s used in the graph ``b =\n    pt.random.normal(a, 1.0)``.  The transformed log-probability is then\n    computed for ``b``.  We then test that the log-probability of ``a`` is\n    properly transformed, as well as any instances of ``a`` that are used\n    elsewhere in the graph (i.e. in ``b``), by comparing the graph for the\n    transformed log-probability with the SciPy-derived log-probability--using a\n    numeric approximation to the Jacobian term.\n\n    TODO: This test is rather redundant with those in tess/distributions/test_transform.py\n    """\n\n    a = pt_dist(*dist_params, size=size)\n    a.name = "a"\n    a_value_var = pt.tensor(dtype=a.dtype, shape=(None,) * a.ndim)\n    a_value_var.name = "a_value"\n\n    b = pt.random.normal(a, 1.0)\n    b.name = "b"\n    b_value_var = b.clone()\n    b_value_var.name = "b_value"\n\n    transform = _default_transform(a.owner.op, a)\n    transform_rewrite = TransformValuesRewrite({a_value_var: transform})\n    res = conditional_logp({a: a_value_var, b: b_value_var}, extra_rewrites=transform_rewrite)\n    res_combined = pt.sum([pt.sum(factor) for factor in res.values()])\n\n    test_val_rng = np.random.RandomState(3238)\n\n    logp_vals_fn = pytensor.function([a_value_var, b_value_var], res_combined)\n\n    a_forward_fn = pytensor.function([a_value_var], transform.forward(a_value_var, *a.owner.inputs))\n    a_backward_fn = pytensor.function(\n        [a_value_var], transform.backward(a_value_var, *a.owner.inputs)\n    )\n    log_jac_fn = pytensor.function(\n        [a_value_var],\n        transform.log_jac_det(a_value_var, *a.owner.inputs),\n        on_unused_input="ignore",\n    )\n\n    for i in range(10):\n        a_dist = sp_dist(*dist_params)\n        a_val = a_dist.rvs(size=size, random_state=test_val_rng).astype(a_value_var.dtype)\n        b_dist = sp.stats.norm(a_val, 1.0)\n        b_val = b_dist.rvs(random_state=test_val_rng).astype(b_value_var.dtype)\n\n        a_trans_value = a_forward_fn(a_val)\n\n        if a_val.ndim > 0:\n\n            def jacobian_estimate_novec(value):\n                dim_diff = a_val.ndim - value.ndim\n                if dim_diff > 0:\n                    # Make sure the dimensions match the expected input\n                    # dimensions for the compiled backward transform function\n                    def a_backward_fn_(x):\n                        x_ = np.expand_dims(x, axis=list(range(dim_diff)))\n                        return a_backward_fn(x_).squeeze()\n\n                else:\n                    a_backward_fn_ = a_backward_fn\n\n                jacobian_val = Jacobian(a_backward_fn_)(value)\n\n                n_missing_dims = jacobian_val.shape[0] - jacobian_val.shape[1]\n                if n_missing_dims > 0:\n                    missing_bases = np.eye(jacobian_val.shape[0])[..., -n_missing_dims:]\n                    jacobian_val = np.concatenate([jacobian_val, missing_bases], axis=-1)\n\n                return np.linalg.slogdet(jacobian_val)[-1]\n\n            jacobian_estimate = np.vectorize(jacobian_estimate_novec, signature="(n)->()")\n\n            exp_log_jac_val = jacobian_estimate(a_trans_value)\n        else:\n            jacobian_val = np.atleast_2d(sp.misc.derivative(a_backward_fn, a_trans_value, dx=1e-6))\n            exp_log_jac_val = np.linalg.slogdet(jacobian_val)[-1]\n\n        log_jac_val = log_jac_fn(a_trans_value)\n        np.testing.assert_allclose(exp_log_jac_val, log_jac_val, rtol=1e-4, atol=1e-10)\n\n        exp_logprob_val = a_dist.logpdf(a_val).sum()\n        exp_logprob_val += exp_log_jac_val.sum()\n        exp_logprob_val += b_dist.logpdf(b_val).sum()\n\n        logprob_val = logp_vals_fn(a_trans_value, b_val)\n\n        np.testing.assert_allclose(exp_logprob_val, logprob_val, rtol=1e-4, atol=1e-10)\n\n\n@pytest.mark.parametrize("use_jacobian", [True, False])\ndef test_value_transform_logprob_nojac(use_jacobian):\n    X_rv = pt.random.halfnormal(0, 3, name="X")\n    x_vv = X_rv.clone()\n    x_vv.name = "x"\n\n    transform_rewrite = TransformValuesRewrite({x_vv: log})\n    tr_logp = conditional_logp(\n        {X_rv: x_vv}, extra_rewrites=transform_rewrite, use_jacobian=use_jacobian\n    )\n    tr_logp_combined = pt.sum([pt.sum(factor) for factor in tr_logp.values()])\n\n    np.testing.assert_allclose(\n        tr_logp_combined.eval({x_vv: np.log(2.5)}),\n        sp.stats.halfnorm(0, 3).logpdf(2.5) + (np.log(2.5) if use_jacobian else 0.0),\n    )\n\n\ndef test_hierarchical_value_transform():\n    """\n    This model requires rv-value replacements in the backward transformation of\n    the value var `x`\n    """\n\n    lower_rv = pt.random.uniform(0, 1, name="lower")\n    upper_rv = pt.random.uniform(9, 10, name="upper")\n    x_rv = pt.random.uniform(lower_rv, upper_rv, name="x")\n\n    lower = lower_rv.clone()\n    upper = upper_rv.clone()\n    x = x_rv.clone()\n\n    transform_rewrite = TransformValuesRewrite(\n        {\n            lower: _default_transform(lower_rv.owner.op, lower_rv),\n            upper: _default_transform(upper_rv.owner.op, upper_rv),\n            x: _default_transform(x_rv.owner.op, x_rv),\n        }\n    )\n    logp = conditional_logp(\n        {lower_rv: lower, upper_rv: upper, x_rv: x},\n        extra_rewrites=transform_rewrite,\n    )\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n\n    assert_no_rvs(logp_combined)\n    assert not np.isinf(logp_combined.eval({lower: -10, upper: 20, x: -20}))\n\n\ndef test_nondefault_value_transform():\n    loc_rv = pt.random.uniform(-10, 10, name="loc")\n    scale_rv = pt.random.uniform(-1, 1, name="scale")\n    x_rv = pt.random.normal(loc_rv, scale_rv, name="x")\n\n    loc = loc_rv.clone()\n    scale = scale_rv.clone()\n    x = x_rv.clone()\n\n    transform_rewrite = TransformValuesRewrite(\n        {\n            loc: None,\n            scale: LogOddsTransform(),\n            x: LogTransform(),\n        }\n    )\n\n    logp = conditional_logp(\n        {loc_rv: loc, scale_rv: scale, x_rv: x},\n        extra_rewrites=transform_rewrite,\n    )\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n\n    # Check numerical evaluation matches with expected transforms\n    loc_val = 0\n    scale_val_tr = -1\n    x_val_tr = -1\n\n    scale_val = sp.special.expit(scale_val_tr)\n    x_val = np.exp(x_val_tr)\n\n    exp_logp = 0\n    exp_logp += sp.stats.uniform(-10, 20).logpdf(loc_val)\n    exp_logp += sp.stats.uniform(-1, 2).logpdf(scale_val)\n    exp_logp += np.log(scale_val) + np.log1p(-scale_val)  # logodds log_jac_det\n    exp_logp += sp.stats.norm(loc_val, scale_val).logpdf(x_val)\n    exp_logp += x_val_tr  # log log_jac_det\n\n    np.testing.assert_allclose(\n        logp_combined.eval({loc: loc_val, scale: scale_val_tr, x: x_val_tr}),\n        exp_logp,\n    )\n\n\ndef test_no_value_transform_multiout_input():\n    r"""Make sure that `Op`\\s with multiple outputs are handled correctly."""\n\n    # This SVD value is necessarily `1`, but it\'s generated by an `Op` with\n    # multiple outputs and no default output.\n    sd = pt.linalg.svd(pt.eye(1))[1][0]\n    x_rv = pt.random.normal(0, sd, name="x")\n    x = x_rv.clone()\n\n    transform_rewrite = TransformValuesRewrite({x: None})\n\n    logp = conditional_logp(\n        {x_rv: x},\n        extra_rewrites=transform_rewrite,\n    )\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n\n    np.testing.assert_allclose(\n        logp_combined.eval({x: 1}),\n        sp.stats.norm(0, 1).logpdf(1),\n    )\n\n\n@pytest.mark.parametrize("transform_x", (True, False))\n@pytest.mark.parametrize("transform_y", (True, False))\ndef test_value_transform_multiout_op(transform_x, transform_y, multiout_measurable_op):\n    x, y = multiout_measurable_op(1, 2)\n    x.name = "x"\n    y.name = "y"\n    x_vv = x.clone()\n    y_vv = y.clone()\n\n    transform_rewrite = TransformValuesRewrite(\n        {\n            x_vv: LogTransform() if transform_x else None,\n            y_vv: ExpTransform() if transform_y else None,\n        }\n    )\n\n    logp = conditional_logp({x: x_vv, y: y_vv}, extra_rewrites=transform_rewrite)\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n\n    x_vv_test = np.random.normal()\n    y_vv_test = np.abs(np.random.normal())\n\n    expected_logp = 0\n    if not transform_x:\n        expected_logp += x_vv_test + 1\n    else:\n        expected_logp += np.exp(x_vv_test) + 1 + x_vv_test\n    # y logp\n    if not transform_y:\n        expected_logp += y_vv_test + 2\n    else:\n        expected_logp += np.log(y_vv_test) + 2 - np.log(y_vv_test)\n\n    np.testing.assert_allclose(\n        logp_combined.eval({x_vv: x_vv_test, y_vv: y_vv_test}), expected_logp\n    )\n\n\ndef test_transformed_rv_and_value():\n    y_rv = pt.random.halfnormal(-1, 1, name="base_rv") + 1\n    y_rv.name = "y"\n    y_vv = y_rv.clone()\n\n    transform_rewrite = TransformValuesRewrite({y_vv: LogTransform()})\n\n    logp = conditional_logp({y_rv: y_vv}, extra_rewrites=transform_rewrite)\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n    assert_no_rvs(logp_combined)\n    logp_fn = pytensor.function([y_vv], logp_combined)\n\n    y_test_val = -5\n\n    np.testing.assert_allclose(\n        logp_fn(y_test_val),\n        sp.stats.halfnorm(0, 1).logpdf(np.exp(y_test_val)) + y_test_val,\n    )\n\n\n@pytest.mark.filterwarnings("error")\ndef test_mixture_transform():\n    """Make sure that non-`RandomVariable` `MeasurableOp` variables can be transformed.\n\n    This test is specific to `MixtureRV`, which is derived from an `OpFromGraph`.\n    """\n\n    I_rv = pt.random.bernoulli(0.5, name="I")\n    Y_1_rv = pt.random.beta(100, 1, name="Y_1")\n    Y_2_rv = pt.random.beta(1, 100, name="Y_2")\n\n    # A `MixtureRV`, which is an `OpFromGraph` subclass, will replace this\n    # `pt.stack` in the graph\n    Y_rv = pt.stack([Y_1_rv, Y_2_rv])[I_rv]\n    Y_rv.name = "Y"\n\n    i_vv = I_rv.clone()\n    i_vv.name = "i"\n    y_vv = Y_rv.clone()\n    y_vv.name = "y"\n\n    logp_no_trans = conditional_logp(\n        {Y_rv: y_vv, I_rv: i_vv},\n    )\n    logp_no_trans_comb = pt.sum([pt.sum(factor) for factor in logp_no_trans.values()])\n\n    transform_rewrite = TransformValuesRewrite({y_vv: LogTransform()})\n\n    logp_trans = conditional_logp(\n        {Y_rv: y_vv, I_rv: i_vv},\n        extra_rewrites=transform_rewrite,\n        use_jacobian=False,\n    )\n    logp_trans_combined = pt.sum([pt.sum(factor) for factor in logp_trans.values()])\n\n    # The untransformed graph should be the same as the transformed graph after\n    # replacing the `Y_rv` value variable with a transformed version of itself\n    logp_nt_fg = FunctionGraph(outputs=[logp_no_trans_comb], clone=False)\n    y_trans = pt.exp(y_vv)\n    y_trans.name = "y_log"\n    logp_nt_fg.replace(y_vv, y_trans)\n    logp_nt = logp_nt_fg.outputs[0]\n\n    assert equal_computations([logp_nt], [logp_trans_combined])\n\n\ndef test_scan_transform():\n    """Test that Scan valued variables can be transformed"""\n\n    init = pt.random.beta(1, 1, name="init")\n    init_vv = init.clone()\n\n    def scan_step(prev_innov):\n        next_innov = pt.random.beta(prev_innov * 10, (1 - prev_innov) * 10)\n        update = {next_innov.owner.inputs[0]: next_innov.owner.outputs[0]}\n        return next_innov, update\n\n    innov, _ = scan(\n        fn=scan_step,\n        outputs_info=[init],\n        n_steps=4,\n    )\n    innov.name = "innov"\n    innov_vv = innov.clone()\n\n    tr = TransformValuesRewrite(\n        {\n            init_vv: LogOddsTransform(),\n            innov_vv: LogOddsTransform(),\n        }\n    )\n    logp = conditional_logp({init: init_vv, innov: innov_vv}, extra_rewrites=tr, use_jacobian=True)[\n        innov_vv\n    ]\n    logp_fn = pytensor.function([init_vv, innov_vv], logp, on_unused_input="ignore")\n\n    # Create an unrolled scan graph as reference\n    innov = []\n    prev_innov = init\n    for i in range(4):\n        next_innov = pt.random.beta(prev_innov * 10, (1 - prev_innov) * 10, name="innov[i]")\n        innov.append(next_innov)\n        prev_innov = next_innov\n    innov = pt.stack(innov)\n    innov.name = "innov"\n\n    tr = TransformValuesRewrite(\n        {\n            init_vv: LogOddsTransform(),\n            innov_vv: LogOddsTransform(),\n        }\n    )\n    ref_logp = conditional_logp(\n        {init: init_vv, innov: innov_vv}, extra_rewrites=tr, use_jacobian=True\n    )[innov_vv]\n    ref_logp_fn = pytensor.function([init_vv, innov_vv], ref_logp, on_unused_input="ignore")\n\n    test_point = {\n        "init": np.array(-0.5),\n        "innov": np.full((4,), -0.5),\n    }\n    np.testing.assert_allclose(logp_fn(**test_point), ref_logp_fn(**test_point))\n\n\ndef test_weakref_leak():\n    """Check that the rewrite does not have a growing memory footprint.\n\n    See #6990\n    """\n\n    def _growth(limit=10, peak_stats={}):\n        """Vendoring of objgraph.growth\n\n        Source: https://github.com/mgedmin/objgraph/blob/94b1ca61a11109547442701800292dcfc7f59fc8/objgraph.py#L253\n        """\n        gc.collect()\n        objects = gc.get_objects()\n\n        stats = {}\n        for o in objects:\n            n = type(o).__name__\n            stats[n] = stats.get(n, 0) + 1\n\n        deltas = {}\n        for name, count in stats.items():\n            old_count = peak_stats.get(name, 0)\n            if count > old_count:\n                deltas[name] = count - old_count\n                peak_stats[name] = count\n\n        deltas = sorted(deltas.items(), key=operator.itemgetter(1), reverse=True)\n\n        if limit:\n            deltas = deltas[:limit]\n\n        return [(name, stats[name], delta) for name, delta in deltas]\n\n    rvs_to_values = {pt.random.beta(1, 1, name=f"p_{i}"): pt.scalar(f"p_{i}") for i in range(30)}\n    tr = TransformValuesRewrite({v: logodds for v in rvs_to_values.values()})\n\n    for i in range(20):\n        conditional_logp(rvs_to_values, extra_rewrites=tr)\n        res = _growth()\n        # Only start checking after warmup\n        if i > 15:\n            assert not res, "Object counts are still growing"\n',
            'tests/sampling/test_mcmc.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport logging\nimport unittest.mock as mock\nimport warnings\n\nfrom contextlib import ExitStack as does_not_raise\n\nimport numpy as np\nimport numpy.testing as npt\nimport pytensor\nimport pytensor.tensor as pt\nimport pytest\nimport scipy.special\n\nfrom arviz import InferenceData\nfrom pytensor import shared\nfrom pytensor.compile.ops import as_op\n\nimport pymc as pm\n\nfrom pymc.backends.ndarray import NDArray\nfrom pymc.distributions import transforms\nfrom pymc.exceptions import SamplingError\nfrom pymc.sampling.mcmc import assign_step_methods\nfrom pymc.stats.convergence import SamplerWarning, WarningType\nfrom pymc.step_methods import (\n    NUTS,\n    BinaryGibbsMetropolis,\n    CategoricalGibbsMetropolis,\n    CompoundStep,\n    HamiltonianMC,\n    Metropolis,\n    Slice,\n)\nfrom pymc.testing import fast_unstable_sampling_mode\nfrom tests.models import simple_init\n\n\nclass TestInitNuts:\n    def setup_method(self):\n        self.model, self.start, self.step, _ = simple_init()\n\n    def test_checks_seeds_kwarg(self):\n        with self.model:\n            with pytest.raises(ValueError, match="Number of seeds"):\n                pm.sampling.mcmc.init_nuts(chains=2, random_seed=[1])\n\n\nclass TestSample:\n    def setup_method(self):\n        self.model, self.start, self.step, _ = simple_init()\n\n    @pytest.mark.parametrize("init", ("jitter+adapt_diag", "advi", "map"))\n    @pytest.mark.parametrize("cores", (1, 2))\n    @pytest.mark.parametrize(\n        "chains, seeds",\n        [\n            (1, None),\n            (1, 1),\n            (1, [1]),\n            (2, None),\n            (2, 1),\n            (2, [1, 2]),\n        ],\n    )\n    def test_random_seed(self, chains, seeds, cores, init):\n        with pm.Model():\n            x = pm.Normal("x", 0, 10, initval="prior")\n            tr1 = pm.sample(\n                chains=chains,\n                random_seed=seeds,\n                cores=cores,\n                init=init,\n                tune=0,\n                draws=10,\n                return_inferencedata=False,\n                compute_convergence_checks=False,\n            )\n            tr2 = pm.sample(\n                chains=chains,\n                random_seed=seeds,\n                cores=cores,\n                init=init,\n                tune=0,\n                draws=10,\n                return_inferencedata=False,\n                compute_convergence_checks=False,\n            )\n\n        allequal = np.all(tr1["x"] == tr2["x"])\n        if seeds is None:\n            assert not allequal\n        else:\n            assert allequal\n\n    @mock.patch("numpy.random.seed")\n    def test_default_sample_does_not_set_global_seed(self, mocked_seed):\n        # Test that when random_seed is None, `np.random.seed` is not called in the main\n        # process. Ideally it would never be called, but PyMC step samplers still rely\n        # on global seeding for reproducible behavior.\n        kwargs = {"tune": 2, "draws": 2, "random_seed": None}\n        with self.model:\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                pm.sample(chains=1, **kwargs)\n                pm.sample(chains=2, cores=1, **kwargs)\n                pm.sample(chains=2, cores=2, **kwargs)\n        mocked_seed.assert_not_called()\n\n    def test_sample_does_not_rely_on_external_global_seeding(self):\n        # Tests that sampling does not depend on exertenal global seeding\n        kwargs = {\n            "tune": 2,\n            "draws": 20,\n            "random_seed": None,\n            "return_inferencedata": False,\n        }\n        with self.model:\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                np.random.seed(1)\n                idata11 = pm.sample(chains=1, **kwargs)\n                np.random.seed(1)\n                idata12 = pm.sample(chains=2, cores=1, **kwargs)\n                np.random.seed(1)\n                idata13 = pm.sample(chains=2, cores=2, **kwargs)\n\n                np.random.seed(1)\n                idata21 = pm.sample(chains=1, **kwargs)\n                np.random.seed(1)\n                idata22 = pm.sample(chains=2, cores=1, **kwargs)\n                np.random.seed(1)\n                idata23 = pm.sample(chains=2, cores=2, **kwargs)\n\n        assert np.all(idata11["x"] != idata21["x"])\n        assert np.all(idata12["x"] != idata22["x"])\n        assert np.all(idata13["x"] != idata23["x"])\n\n    def test_sample_init(self):\n        with self.model:\n            for init in (\n                "advi",\n                "advi_map",\n                "map",\n                "adapt_diag",\n                "jitter+adapt_diag",\n                "jitter+adapt_diag_grad",\n                "adapt_full",\n                "jitter+adapt_full",\n            ):\n                kwargs = {\n                    "init": init,\n                    "tune": 120,\n                    "n_init": 1000,\n                    "draws": 50,\n                    "random_seed": 20160911,\n                }\n                with warnings.catch_warnings(record=True) as rec:\n                    warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                    if init.endswith("adapt_full"):\n                        with pytest.warns(UserWarning, match="experimental feature"):\n                            pm.sample(**kwargs)\n                    else:\n                        pm.sample(**kwargs)\n\n    def test_sample_args(self):\n        with self.model:\n            with pytest.raises(ValueError, match=r"\'foo\'"):\n                pm.sample(50, tune=0, chains=1, step=pm.Metropolis(), foo=1)\n\n            with pytest.raises(ValueError, match=r"\'foo\'") as excinfo:\n                pm.sample(50, tune=0, chains=1, step=pm.Metropolis(), foo={})\n\n    def test_parallel_start(self):\n        with self.model:\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                idata = pm.sample(\n                    0,\n                    tune=5,\n                    cores=2,\n                    discard_tuned_samples=False,\n                    initvals=[{"x": [10, 10]}, {"x": [-10, -10]}],\n                    random_seed=20160911,\n                )\n        assert idata.warmup_posterior["x"].sel(chain=0, draw=0).values[0] > 0\n        assert idata.warmup_posterior["x"].sel(chain=1, draw=0).values[0] < 0\n\n    def test_reset_tuning(self):\n        with self.model:\n            tune = 50\n            chains = 2\n            start, step = pm.sampling.mcmc.init_nuts(chains=chains, random_seed=[1, 2])\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                pm.sample(draws=2, tune=tune, chains=chains, step=step, initvals=start, cores=1)\n            assert step.potential._n_samples == tune\n            assert step.step_adapt._count == tune + 1\n\n    @pytest.mark.parametrize(\n        "start, error",\n        [\n            ({"x": 1}, ValueError),\n            ({"x": [1, 2, 3]}, ValueError),\n            ({"x": np.array([[1, 1], [1, 1]])}, ValueError),\n        ],\n    )\n    def test_sample_start_bad_shape(self, start, error):\n        with pytest.raises(error):\n            pm.sampling.mcmc._check_start_shape(self.model, start)\n\n    @pytest.mark.parametrize("start", [{"x": np.array([1, 1])}, {"x": [10, 10]}, {"x": [-10, -10]}])\n    def test_sample_start_good_shape(self, start):\n        pm.sampling.mcmc._check_start_shape(self.model, start)\n\n    def test_sample_callback(self):\n        callback = mock.Mock()\n        test_cores = [1, 2]\n        with self.model:\n            for cores in test_cores:\n                with warnings.catch_warnings():\n                    warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                    pm.sample(\n                        10,\n                        tune=0,\n                        chains=2,\n                        step=self.step,\n                        cores=cores,\n                        random_seed=20160911,\n                        callback=callback,\n                    )\n                assert callback.called\n\n    def test_callback_can_cancel(self):\n        trace_cancel_length = 5\n\n        def callback(trace, draw):\n            if len(trace) >= trace_cancel_length:\n                raise KeyboardInterrupt()\n\n        with self.model:\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                trace = pm.sample(\n                    10,\n                    tune=0,\n                    chains=1,\n                    step=self.step,\n                    cores=1,\n                    random_seed=2016911,\n                    callback=callback,\n                    return_inferencedata=False,\n                )\n            assert len(trace) == trace_cancel_length\n\n    def test_sequential_backend(self):\n        with self.model:\n            backend = NDArray()\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                pm.sample(10, tune=5, cores=1, chains=2, step=pm.Metropolis(), trace=backend)\n\n    @pytest.mark.parametrize("symbolic_rv", (False, True))\n    def test_deterministic_of_unobserved(self, symbolic_rv):\n        with pm.Model() as model:\n            if symbolic_rv:\n                x = pm.Censored(\n                    "x", pm.HalfNormal.dist(1), lower=None, upper=10, transform=transforms.log\n                )\n            else:\n                x = pm.HalfNormal("x", 1)\n            y = pm.Deterministic("y", x + 100)\n            idata = pm.sample(\n                chains=1,\n                tune=10,\n                draws=50,\n                compute_convergence_checks=False,\n            )\n\n        np.testing.assert_allclose(idata.posterior["y"], idata.posterior["x"] + 100)\n\n    @pytest.mark.parametrize("symbolic_rv", (False, True))\n    def test_transform_with_rv_dependency(self, symbolic_rv):\n        # Test that untransformed variables that depend on upstream variables are properly handled\n        with pm.Model() as m:\n            if symbolic_rv:\n                x = pm.Censored("x", pm.HalfNormal.dist(1), lower=0, upper=1, observed=1)\n            else:\n                x = pm.HalfNormal("x", observed=1)\n\n            transform = pm.distributions.transforms.Interval(\n                bounds_fn=lambda *inputs: (inputs[-2], inputs[-1])\n            )\n            y = pm.Uniform("y", lower=0, upper=x, transform=transform, default_transform=None)\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                trace = pm.sample(tune=10, draws=50, return_inferencedata=False, random_seed=336)\n\n        assert np.allclose(scipy.special.expit(trace["y_interval__"]), trace["y"])\n\n\nclass ApocalypticMetropolis(pm.Metropolis):\n    """A stepper that warns in every iteration."""\n\n    stats_dtypes_shapes = {\n        **pm.Metropolis.stats_dtypes_shapes,\n        "warning": (SamplerWarning, None),\n    }\n\n    def astep(self, q0):\n        draw, stats = super().astep(q0)\n        stats[0]["warning"] = SamplerWarning(\n            WarningType.BAD_ENERGY,\n            "Asteroid incoming!",\n            "warn",\n        )\n        return draw, stats\n\n\nclass TestSampleReturn:\n    """Tests related to kwargs that parametrize how `pm.sample` results are returned."""\n\n    def test_sample_return_lengths(self):\n        with pm.Model() as model:\n            pm.Normal("n")\n\n            # Get a MultiTrace with warmup\n            with pytest.warns(UserWarning, match="will be included"):\n                mtrace = pm.sample(\n                    draws=100,\n                    tune=50,\n                    cores=1,\n                    chains=3,\n                    step=pm.Metropolis(),\n                    return_inferencedata=False,\n                    discard_tuned_samples=False,\n                )\n                assert isinstance(mtrace, pm.backends.base.MultiTrace)\n                assert len(mtrace) == 150\n\n        # Now instead of running more MCMCs, we\'ll test the other return\n        # options using the basetraces inside the MultiTrace.\n        traces = list(mtrace._straces.values())\n        assert len(traces) == 3\n\n        # MultiTrace without warmup\n        mtrace_pst = pm.sampling.mcmc._sample_return(\n            run=None,\n            traces=traces,\n            tune=50,\n            t_sampling=123.4,\n            discard_tuned_samples=True,\n            return_inferencedata=False,\n            compute_convergence_checks=False,\n            keep_warning_stat=True,\n            idata_kwargs={},\n            model=model,\n        )\n        assert isinstance(mtrace_pst, pm.backends.base.MultiTrace)\n        assert len(mtrace_pst) == 100\n        assert mtrace_pst.report.t_sampling == 123.4\n        assert mtrace_pst.report.n_tune == 50\n        assert mtrace_pst.report.n_draws == 100\n\n        # InferenceData with warmup\n        idata_w = pm.sampling.mcmc._sample_return(\n            run=None,\n            traces=traces,\n            tune=50,\n            t_sampling=123.4,\n            discard_tuned_samples=False,\n            compute_convergence_checks=False,\n            return_inferencedata=True,\n            keep_warning_stat=True,\n            idata_kwargs={},\n            model=model,\n        )\n        assert isinstance(idata_w, InferenceData)\n        assert hasattr(idata_w, "warmup_posterior")\n        assert idata_w.warmup_posterior.sizes["draw"] == 50\n        assert idata_w.posterior.sizes["draw"] == 100\n        assert idata_w.posterior.sizes["chain"] == 3\n\n        # InferenceData without warmup\n        idata = pm.sampling.mcmc._sample_return(\n            run=None,\n            traces=traces,\n            tune=50,\n            t_sampling=123.4,\n            discard_tuned_samples=True,\n            compute_convergence_checks=False,\n            return_inferencedata=True,\n            keep_warning_stat=False,\n            idata_kwargs={},\n            model=model,\n        )\n        assert isinstance(idata, InferenceData)\n        assert not hasattr(idata, "warmup_posterior")\n        assert idata.posterior.sizes["draw"] == 100\n        assert idata.posterior.sizes["chain"] == 3\n\n    @pytest.mark.parametrize("cores", [1, 2])\n    def test_logs_sampler_warnings(self, caplog, cores):\n        """Asserts that "warning" sampler stats are logged during sampling."""\n        with pm.Model():\n            pm.Normal("n")\n            with caplog.at_level(logging.WARNING):\n                idata = pm.sample(\n                    tune=2,\n                    draws=3,\n                    cores=cores,\n                    chains=cores,\n                    step=ApocalypticMetropolis(),\n                    compute_convergence_checks=False,\n                    discard_tuned_samples=False,\n                    keep_warning_stat=True,\n                )\n\n        # Sampler warnings should be logged\n        nwarns = sum("Asteroid" in rec.message for rec in caplog.records)\n        assert nwarns == (2 + 3) * cores\n\n    @pytest.mark.parametrize("keep_warning_stat", [None, True])\n    def test_keep_warning_stat_setting(self, keep_warning_stat):\n        """The ``keep_warning_stat`` stat (aka "Adrian\'s kwarg) enables users\n        to keep the ``SamplerWarning`` objects from the ``sample_stats.warning`` group.\n        This breaks ``idata.to_netcdf()`` which is why it defaults to ``False``.\n        """\n        sample_kwargs = {\n            "tune": 2,\n            "draws": 3,\n            "chains": 1,\n            "compute_convergence_checks": False,\n            "discard_tuned_samples": False,\n            "keep_warning_stat": keep_warning_stat,\n        }\n        if keep_warning_stat:\n            sample_kwargs["keep_warning_stat"] = True\n        with pm.Model():\n            pm.Normal("n")\n            idata = pm.sample(step=ApocalypticMetropolis(), **sample_kwargs)\n\n        if keep_warning_stat:\n            assert "warning" in idata.warmup_sample_stats\n            assert "warning" in idata.sample_stats\n            # And end up in the InferenceData\n            assert "warning" in idata.sample_stats\n            # NOTE: The stats are squeezed by default but this does not always work.\n            #       This tests flattens so we don\'t have to be exact in accessing (non-)squeezed items.\n            #       Also see https://github.com/pymc-devs/pymc/issues/6207.\n            warn_objs = list(idata.sample_stats.warning.sel(chain=0).values.flatten())\n            assert warn_objs\n            if isinstance(warn_objs[0], np.ndarray):\n                # Squeeze warning stats. See https://github.com/pymc-devs/pymc/issues/6207\n                warn_objs = [a.tolist() for a in warn_objs]\n            assert any(isinstance(w, SamplerWarning) for w in warn_objs)\n            assert any("Asteroid" in w.message for w in warn_objs)\n        else:\n            assert "warning" not in idata.warmup_sample_stats\n            assert "warning" not in idata.sample_stats\n            assert "warning_dim_0" not in idata.warmup_sample_stats\n            assert "warning_dim_0" not in idata.sample_stats\n\n\ndef test_sample_find_MAP_does_not_modify_start():\n    # see https://github.com/pymc-devs/pymc/pull/4458\n    with pm.Model():\n        pm.LogNormal("untransformed")\n\n        # make sure find_Map does not modify the start dict\n        start = {"untransformed": 2}\n        pm.find_MAP(start=start)\n        assert start == {"untransformed": 2}\n\n        # make sure sample does not modify the start dict\n        start = {"untransformed": 0.2}\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            pm.sample(draws=10, step=pm.Metropolis(), tune=5, initvals=start, chains=3)\n        assert start == {"untransformed": 0.2}\n\n        # make sure sample does not modify the start when passes as list of dict\n        start = [{"untransformed": 2}, {"untransformed": 0.2}]\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            pm.sample(draws=10, step=pm.Metropolis(), tune=5, initvals=start, chains=2)\n        assert start == [{"untransformed": 2}, {"untransformed": 0.2}]\n\n\ndef test_empty_model():\n    with pm.Model():\n        pm.Normal("a", observed=1)\n        with pytest.raises(SamplingError) as error:\n            pm.sample()\n        error.match("any free variables")\n\n\ndef test_blas_cores():\n    with pm.Model():\n        pm.Normal("a")\n        pm.sample(blas_cores="auto", tune=10, cores=2, draws=10)\n        pm.sample(blas_cores=None, tune=10, cores=2, draws=10)\n        pm.sample(blas_cores=2, tune=10, cores=2, draws=10)\n\n\ndef test_partial_trace_with_trace_unsupported():\n    with pm.Model() as model:\n        a = pm.Normal("a", mu=0, sigma=1)\n        b = pm.Normal("b", mu=0, sigma=1)\n        with pytest.raises(ValueError, match="var_names"):\n            pm.sample(trace=[a])\n\n\n@pytest.mark.xfail(condition=(pytensor.config.floatX == "float32"), reason="Fails on float32")\nclass TestNamedSampling:\n    def test_shared_named(self):\n        G_var = shared(value=np.atleast_2d(1.0), shape=(1, None), name="G")\n\n        with pm.Model():\n            theta0 = pm.Normal(\n                "theta0",\n                mu=np.atleast_2d(0),\n                tau=np.atleast_2d(1e20),\n                size=(1, 1),\n                initval=np.atleast_2d(0),\n            )\n            theta = pm.Normal(\n                "theta", mu=pt.dot(G_var, theta0), tau=np.atleast_2d(1e20), size=(1, 1)\n            )\n            res = theta.eval()\n            assert np.isclose(res, 0.0)\n\n    def test_shared_unnamed(self):\n        G_var = shared(value=np.atleast_2d(1.0), shape=(1, None))\n        with pm.Model():\n            theta0 = pm.Normal(\n                "theta0",\n                mu=np.atleast_2d(0),\n                tau=np.atleast_2d(1e20),\n                size=(1, 1),\n                initval=np.atleast_2d(0),\n            )\n            theta = pm.Normal(\n                "theta", mu=pt.dot(G_var, theta0), tau=np.atleast_2d(1e20), size=(1, 1)\n            )\n            res = theta.eval()\n            assert np.isclose(res, 0.0)\n\n    def test_constant_named(self):\n        G_var = pt.constant(np.atleast_2d(1.0), name="G")\n        with pm.Model():\n            theta0 = pm.Normal(\n                "theta0",\n                mu=np.atleast_2d(0),\n                tau=np.atleast_2d(1e20),\n                size=(1, 1),\n                initval=np.atleast_2d(0),\n            )\n            theta = pm.Normal(\n                "theta", mu=pt.dot(G_var, theta0), tau=np.atleast_2d(1e20), size=(1, 1)\n            )\n\n            res = theta.eval()\n            assert np.isclose(res, 0.0)\n\n\ndef check_exec_nuts_init(method):\n    with pm.Model() as model:\n        pm.Normal("a", mu=0, sigma=1, size=2)\n        pm.HalfNormal("b", sigma=1)\n    with model:\n        start, _ = pm.init_nuts(init=method, n_init=10, random_seed=[1])\n        assert isinstance(start, list)\n        assert len(start) == 1\n        assert isinstance(start[0], dict)\n        assert set(start[0].keys()) == {v.name for v in model.value_vars}\n        start, _ = pm.init_nuts(init=method, n_init=10, chains=2, random_seed=[1, 2])\n        assert isinstance(start, list)\n        assert len(start) == 2\n        assert isinstance(start[0], dict)\n        assert set(start[0].keys()) == {v.name for v in model.value_vars}\n\n\n@pytest.mark.parametrize(\n    "method",\n    [\n        "advi",\n        "ADVI+adapt_diag",\n        "advi_map",\n        "jitter+adapt_diag",\n        "adapt_diag",\n        "map",\n        "adapt_full",\n        "jitter+adapt_full",\n    ],\n)\ndef test_exec_nuts_init(method):\n    if method.endswith("adapt_full"):\n        with pytest.warns(UserWarning, match="experimental feature"):\n            check_exec_nuts_init(method)\n    else:\n        check_exec_nuts_init(method)\n\n\n@pytest.mark.skip(reason="Test requires monkey patching of RandomGenerator")\n@pytest.mark.parametrize(\n    "initval, jitter_max_retries, expectation",\n    [\n        (0, 0, pytest.raises(SamplingError)),\n        (0, 1, pytest.raises(SamplingError)),\n        (0, 4, does_not_raise()),\n        (0, 10, does_not_raise()),\n        (1, 0, does_not_raise()),\n    ],\n)\ndef test_init_jitter(initval, jitter_max_retries, expectation):\n    with pm.Model() as m:\n        pm.HalfNormal("x", default_transform=None, initval=initval)\n\n    with expectation:\n        # Starting value is negative (invalid) when np.random.rand returns 0 (jitter = -1)\n        # and positive (valid) when it returns 1 (jitter = 1)\n        with mock.patch("numpy.random.Generator.uniform", side_effect=[-1, -1, -1, 1, -1]):\n            start = pm.sampling.mcmc._init_jitter(\n                model=m,\n                initvals=None,\n                seeds=[1],\n                jitter=True,\n                jitter_max_retries=jitter_max_retries,\n            )\n            m.check_start_vals(start)\n\n\ndef test_step_args():\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        idata0 = pm.sample(target_accept=0.5, random_seed=1410)\n        idata1 = pm.sample(nuts={"target_accept": 0.5}, random_seed=1410 * 2)\n        idata2 = pm.sample(target_accept=0.5, nuts={"max_treedepth": 10}, random_seed=1410)\n\n        with pytest.raises(ValueError, match="`target_accept` was defined twice."):\n            pm.sample(target_accept=0.5, nuts={"target_accept": 0.95}, random_seed=1410)\n\n    npt.assert_almost_equal(idata0.sample_stats.acceptance_rate.mean(), 0.5, decimal=1)\n    npt.assert_almost_equal(idata1.sample_stats.acceptance_rate.mean(), 0.5, decimal=1)\n    npt.assert_almost_equal(idata2.sample_stats.acceptance_rate.mean(), 0.5, decimal=1)\n\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        b = pm.Poisson("b", 1)\n        idata0 = pm.sample(target_accept=0.5, random_seed=1418)\n        with warnings.catch_warnings():\n            warnings.filterwarnings(\n                "ignore", "invalid value encountered in double_scalars", RuntimeWarning\n            )\n            idata1 = pm.sample(\n                nuts={"target_accept": 0.5}, metropolis={"scaling": 0}, random_seed=1418 * 2\n            )\n\n    npt.assert_almost_equal(idata0.sample_stats.acceptance_rate.mean(), 0.5, decimal=1)\n    npt.assert_almost_equal(idata1.sample_stats.acceptance_rate.mean(), 0.5, decimal=1)\n    npt.assert_allclose(idata1.sample_stats.scaling, 0)\n\n\ndef test_init_nuts(caplog):\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            pm.sample(10, tune=10)\n        assert "Initializing NUTS" in caplog.text\n\n\ndef test_no_init_nuts_step(caplog):\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            pm.sample(10, tune=10, step=pm.NUTS([a]))\n        assert "Initializing NUTS" not in caplog.text\n\n\ndef test_no_init_nuts_compound(caplog):\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        b = pm.Poisson("b", 1)\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            pm.sample(10, tune=10)\n        assert "Initializing NUTS" not in caplog.text\n\n\ndef test_sample_var_names():\n    # Generate data\n    seed = 1234\n    rng = np.random.default_rng(seed)\n\n    group = rng.choice(list("ABCD"), size=100)\n    x = rng.normal(size=100)\n    y = rng.normal(size=100)\n\n    group_values, group_idx = np.unique(group, return_inverse=True)\n\n    coords = {"group": group_values}\n\n    # Create model\n    with pm.Model(coords=coords) as model:\n        b_group = pm.Normal("b_group", dims="group")\n        b_x = pm.Normal("b_x")\n        mu = pm.Deterministic("mu", b_group[group_idx] + b_x * x)\n        sigma = pm.HalfNormal("sigma")\n        pm.Normal("y", mu=mu, sigma=sigma, observed=y)\n\n    # Sample with and without var_names, but always with the same seed\n    with model:\n        idata_1 = pm.sample(tune=100, draws=100, random_seed=seed)\n        idata_2 = pm.sample(\n            tune=100, draws=100, var_names=["b_group", "b_x", "sigma"], random_seed=seed\n        )\n\n    assert "mu" in idata_1.posterior\n    assert "mu" not in idata_2.posterior\n\n    assert np.all(idata_1.posterior["b_group"] == idata_2.posterior["b_group"]).item()\n    assert np.all(idata_1.posterior["b_x"] == idata_2.posterior["b_x"]).item()\n    assert np.all(idata_1.posterior["sigma"] == idata_2.posterior["sigma"]).item()\n\n\nclass TestAssignStepMethods:\n    def test_bernoulli(self):\n        """Test bernoulli distribution is assigned binary gibbs metropolis method"""\n        with pm.Model() as model:\n            x = pm.Bernoulli("x", 0.5)\n        _, selected_steps = assign_step_methods(model, [])\n        assert selected_steps == {BinaryGibbsMetropolis: [model.rvs_to_values[x]]}\n\n    def test_normal(self):\n        """Test normal distribution is assigned NUTS method"""\n        with pm.Model() as model:\n            x = pm.Normal("x", 0, 1)\n        _, selected_steps = assign_step_methods(model, [])\n        assert selected_steps == {NUTS: [model.rvs_to_values[x]]}\n\n    def test_categorical(self):\n        """Test categorical distribution is assigned categorical gibbs metropolis method"""\n        with pm.Model() as model:\n            x = pm.Categorical("x", np.array([0.25, 0.75]))\n        _, selected_steps = assign_step_methods(model, [])\n        assert selected_steps == {BinaryGibbsMetropolis: [model.rvs_to_values[x]]}\n\n        with pm.Model() as model:\n            y = pm.Categorical("y", np.array([0.25, 0.70, 0.05]))\n        _, selected_steps = assign_step_methods(model, [])\n        assert selected_steps == {CategoricalGibbsMetropolis: [model.rvs_to_values[y]]}\n\n    def test_binomial(self):\n        """Test binomial distribution is assigned metropolis method."""\n        with pm.Model() as model:\n            x = pm.Binomial("x", 10, 0.5)\n        _, selected_steps = assign_step_methods(model, [])\n        assert selected_steps == {Metropolis: [model.rvs_to_values[x]]}\n\n    def test_normal_nograd_op(self):\n        """Test normal distribution without an implemented gradient is assigned slice method"""\n        with pm.Model() as model:\n            x = pm.Normal("x", 0, 1)\n\n            # a custom PyTensor Op that does not have a grad:\n            is_64 = pytensor.config.floatX == "float64"\n            itypes = [pt.dscalar] if is_64 else [pt.fscalar]\n            otypes = [pt.dscalar] if is_64 else [pt.fscalar]\n\n            @as_op(itypes, otypes)\n            def kill_grad(x):\n                return x\n\n            data = np.random.normal(size=(100,))\n            y = pm.Normal(\n                "y", mu=kill_grad(x), sigma=1, observed=data.astype(pytensor.config.floatX)\n            )\n\n        _, selected_steps = assign_step_methods(model, [])\n        assert selected_steps == {Slice: [model.rvs_to_values[x]]}\n\n    @pytest.fixture\n    def step_methods(self):\n        """Make sure we reset the STEP_METHODS after the test is done."""\n        methods_copy = pm.STEP_METHODS.copy()\n        yield pm.STEP_METHODS\n        pm.STEP_METHODS.clear()\n        for method in methods_copy:\n            pm.STEP_METHODS.append(method)\n\n    def test_modify_step_methods(self, step_methods):\n        """Test step methods can be changed"""\n        step_methods.remove(NUTS)\n\n        with pm.Model() as model:\n            pm.Normal("x", 0, 1)\n\n        _, selected_steps = assign_step_methods(model, [])\n        assert NUTS not in selected_steps\n\n        # add back nuts\n        step_methods.append(NUTS)\n\n        with pm.Model() as model:\n            pm.Normal("x", 0, 1)\n\n        _, selected_steps = assign_step_methods(model, [])\n        assert NUTS in selected_steps\n\n    def test_step_vars_in_model(self):\n        """Test if error is raised if step variable is not found in model.value_vars"""\n        with pm.Model() as model:\n            c1 = pm.HalfNormal("c1")\n            c2 = pm.HalfNormal("c2")\n\n            with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n                step1 = NUTS([c1])\n                step2 = NUTS([c2])\n                step2.vars = [c2]\n                step = CompoundStep([step1, step2])\n                with pytest.raises(\n                    ValueError,\n                    match=r".* assigned to .* sampler is not a value variable in the model. You can use `util.get_value_vars_from_user_vars` to parse user provided variables.",\n                ):\n                    assign_step_methods(model, step)\n\n\nclass TestType:\n    samplers = (Metropolis, Slice, HamiltonianMC, NUTS)\n\n    @pytensor.config.change_flags(floatX="float64", warn_float64="ignore")\n    def test_float64(self):\n        with pm.Model() as model:\n            x = pm.Normal("x", initval=np.array(1.0, dtype="float64"))\n            obs = pm.Normal("obs", mu=x, sigma=1.0, observed=np.random.randn(5))\n\n        assert x.dtype == "float64"\n        assert obs.dtype == "float64"\n\n        for sampler in self.samplers:\n            with model:\n                with warnings.catch_warnings():\n                    warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                    pm.sample(draws=10, tune=10, chains=1, step=sampler())\n\n    @pytensor.config.change_flags(floatX="float32", warn_float64="warn")\n    def test_float32(self):\n        with pm.Model() as model:\n            x = pm.Normal("x", initval=np.array(1.0, dtype="float32"))\n            obs = pm.Normal("obs", mu=x, sigma=1.0, observed=np.random.randn(5).astype("float32"))\n\n        assert x.dtype == "float32"\n        assert obs.dtype == "float32"\n\n        for sampler in self.samplers:\n            with model:\n                with warnings.catch_warnings():\n                    warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                    pm.sample(draws=10, tune=10, chains=1, step=sampler())\n\n\nclass TestShared:\n    def test_sample(self, seeded_test):\n        x = np.random.normal(size=100)\n        y = x + np.random.normal(scale=1e-2, size=100)\n\n        x_pred = np.linspace(-3, 3, 200)\n\n        x_shared = pytensor.shared(x)\n\n        with pm.Model() as model:\n            b = pm.Normal("b", 0.0, 10.0)\n            pm.Normal("obs", b * x_shared, np.sqrt(1e-2), observed=y, shape=x_shared.shape)\n            prior_trace0 = pm.sample_prior_predictive(1000)\n\n            idata = pm.sample(1000, tune=1000, chains=1)\n            pp_trace0 = pm.sample_posterior_predictive(idata)\n\n            x_shared.set_value(x_pred)\n            prior_trace1 = pm.sample_prior_predictive(1000)\n            pp_trace1 = pm.sample_posterior_predictive(idata)\n\n        assert prior_trace0.prior["b"].shape == (1, 1000)\n        assert prior_trace0.prior_predictive["obs"].shape == (1, 1000, 100)\n        np.testing.assert_allclose(\n            x, pp_trace0.posterior_predictive["obs"].mean(("chain", "draw")), atol=1e-1\n        )\n\n        assert prior_trace1.prior["b"].shape == (1, 1000)\n        assert prior_trace1.prior_predictive["obs"].shape == (1, 1000, 200)\n        np.testing.assert_allclose(\n            x_pred, pp_trace1.posterior_predictive["obs"].mean(("chain", "draw")), atol=1e-1\n        )\n',
            'tests/sampling/test_parallel.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport multiprocessing\nimport os\nimport platform\nimport sys\nimport warnings\n\nimport cloudpickle\nimport numpy as np\nimport pytensor\nimport pytensor.tensor as pt\nimport pytest\n\nfrom pytensor.compile.ops import as_op\nfrom pytensor.tensor.type import TensorType\n\nimport pymc as pm\nimport pymc.sampling.parallel as ps\n\nfrom pymc.pytensorf import floatX\n\n\ndef test_context():\n    with pm.Model():\n        pm.Normal("x")\n        ctx = multiprocessing.get_context("spawn")\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            pm.sample(tune=2, draws=2, chains=2, cores=2, mp_ctx=ctx)\n\n\nclass NoUnpickle:\n    def __getstate__(self):\n        return self.__dict__.copy()\n\n    def __setstate__(self, state):\n        raise AttributeError("This fails")\n\n\ndef test_bad_unpickle():\n    with pm.Model() as model:\n        pm.Normal("x")\n\n    with model:\n        step = pm.NUTS()\n        step.no_unpickle = NoUnpickle()\n        with pytest.raises(Exception) as exc_info:\n            pm.sample(\n                tune=2,\n                draws=2,\n                mp_ctx="spawn",\n                step=step,\n                cores=2,\n                chains=2,\n                compute_convergence_checks=False,\n            )\n        assert "could not be unpickled" in str(exc_info.getrepr(style="short"))\n\n\nat_vector = TensorType(pytensor.config.floatX, [False])\n\n\n@as_op([at_vector, pt.iscalar], [at_vector])\ndef _crash_remote_process(a, master_pid):\n    if os.getpid() != master_pid:\n        sys.exit(0)\n    return 2 * np.array(a)\n\n\ndef test_remote_pipe_closed():\n    master_pid = os.getpid()\n    with pm.Model():\n        x = pm.Normal("x", shape=2, mu=0.1)\n        at_pid = pt.as_tensor_variable(np.array(master_pid, dtype="int32"))\n        pm.Normal("y", mu=_crash_remote_process(x, at_pid), shape=2)\n\n        step = pm.Metropolis()\n        with pytest.raises(ps.ParallelSamplingError, match="Chain [0-9] failed with") as ex:\n            pm.sample(step=step, mp_ctx="spawn", tune=2, draws=2, cores=2, chains=2)\n\n\n@pytest.mark.skip(reason="Unclear")\n@pytest.mark.parametrize("mp_start_method", ["spawn", "fork"])\ndef test_abort(mp_start_method):\n    with pm.Model() as model:\n        a = pm.Normal("a", shape=1)\n        b = pm.HalfNormal("b")\n        step1 = pm.NUTS([model.rvs_to_values[a]])\n        step2 = pm.Metropolis([model.rvs_to_values[b]])\n\n    step = pm.CompoundStep([step1, step2])\n\n    # on Windows we cannot fork\n    if platform.system() == "Windows" and mp_start_method == "fork":\n        return\n    if mp_start_method == "spawn":\n        step_method_pickled = cloudpickle.dumps(step, protocol=-1)\n    else:\n        step_method_pickled = None\n\n    for abort in [False, True]:\n        ctx = multiprocessing.get_context(mp_start_method)\n        proc = ps.ProcessAdapter(\n            10,\n            10,\n            step,\n            chain=3,\n            seed=1,\n            mp_ctx=ctx,\n            start={"a": floatX(np.array([1.0])), "b_log__": floatX(np.array(2.0))},\n            step_method_pickled=step_method_pickled,\n        )\n        proc.start()\n        while True:\n            proc.write_next()\n            out = ps.ProcessAdapter.recv_draw([proc])\n            if out[1]:\n                break\n        if abort:\n            proc.abort()\n        proc.join()\n\n\n@pytest.mark.parametrize("mp_start_method", ["spawn", "fork"])\ndef test_explicit_sample(mp_start_method):\n    with pm.Model() as model:\n        a = pm.Normal("a", shape=1)\n        b = pm.HalfNormal("b")\n        step1 = pm.NUTS([model.rvs_to_values[a]])\n        step2 = pm.Metropolis([model.rvs_to_values[b]])\n\n    step = pm.CompoundStep([step1, step2])\n\n    # on Windows we cannot fork\n    if platform.system() == "Windows" and mp_start_method == "fork":\n        return\n    if mp_start_method == "spawn":\n        step_method_pickled = cloudpickle.dumps(step, protocol=-1)\n    else:\n        step_method_pickled = None\n\n    ctx = multiprocessing.get_context(mp_start_method)\n    proc = ps.ProcessAdapter(\n        10,\n        10,\n        step,\n        chain=3,\n        rng=np.random.default_rng(1),\n        mp_ctx=ctx,\n        start={"a": floatX(np.array([1.0])), "b_log__": floatX(np.array(2.0))},\n        step_method_pickled=step_method_pickled,\n        blas_cores=None,\n    )\n    proc.start()\n    while True:\n        proc.write_next()\n        out = ps.ProcessAdapter.recv_draw([proc])\n        view = proc.shared_point_view\n        for name in view:\n            view[name].copy()\n        if out[1]:\n            break\n    proc.join()\n\n\ndef test_iterator():\n    with pm.Model() as model:\n        a = pm.Normal("a", shape=1)\n        b = pm.HalfNormal("b")\n        step1 = pm.NUTS([model.rvs_to_values[a]])\n        step2 = pm.Metropolis([model.rvs_to_values[b]])\n\n    step = pm.CompoundStep([step1, step2])\n\n    start = {"a": floatX(np.array([1.0])), "b_log__": floatX(np.array(2.0))}\n    sampler = ps.ParallelSampler(\n        draws=10,\n        tune=10,\n        chains=3,\n        cores=2,\n        rngs=np.random.default_rng(1).spawn(3),\n        start_points=[start] * 3,\n        step_method=step,\n        progressbar=False,\n        blas_cores=None,\n    )\n    with sampler:\n        for draw in sampler:\n            pass\n\n\ndef test_spawn_densitydist_function():\n    with pm.Model() as model:\n        mu = pm.Normal("mu", 0, 1)\n\n        def func(x):\n            return -2 * (x**2).sum()\n\n        obs = pm.CustomDist("density_dist", logp=func, observed=np.random.randn(100))\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            pm.sample(draws=10, tune=10, step=pm.Metropolis(), cores=2, mp_ctx="spawn")\n\n\ndef test_spawn_densitydist_bound_method():\n    N = 100\n    with pm.Model() as model:\n        mu = pm.Normal("mu", 0, 1)\n\n        def logp(x, mu):\n            normal_dist = pm.Normal.dist(mu, 1, size=N)\n            out = pm.logp(normal_dist, x)\n            return out\n\n        obs = pm.CustomDist("density_dist", mu, logp=logp, observed=np.random.randn(N), size=N)\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            pm.sample(draws=10, tune=10, step=pm.Metropolis(), cores=2, mp_ctx="spawn")\n',
            'tests/step_methods/test_metropolis.py': '#   Copyright 2024 The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\nimport warnings\n\nfrom copy import deepcopy\n\nimport arviz as az\nimport numpy as np\nimport numpy.testing as npt\nimport pytensor\nimport pytest\n\nfrom pytensor.compile.mode import Mode\n\nimport pymc as pm\n\nfrom pymc.step_methods.metropolis import (\n    BinaryGibbsMetropolis,\n    BinaryMetropolis,\n    CategoricalGibbsMetropolis,\n    DEMetropolis,\n    DEMetropolisZ,\n    Metropolis,\n    MultivariateNormalProposal,\n    NormalProposal,\n)\nfrom pymc.step_methods.state import equal_dataclass_values\nfrom pymc.testing import fast_unstable_sampling_mode\nfrom tests import sampler_fixtures as sf\nfrom tests.helpers import RVsAssignmentStepsTester, StepMethodTester, equal_sampling_states\nfrom tests.models import (\n    mv_simple,\n    mv_simple_discrete,\n    simple_binary,\n    simple_categorical,\n    simple_model,\n)\n\nSEED = sum(ord(c) for c in "test_metropolis")\n\n\nclass TestMetropolisUniform(sf.MetropolisFixture, sf.UniformFixture):\n    n_samples = 50000\n    tune = 10000\n    burn = 0\n    chains = 4\n    min_n_eff = 10000\n    rtol = 0.1\n    atol = 0.05\n    ks_thin = 10\n    step_args = {"rng": np.random.default_rng(SEED)}\n\n\nclass TestMetropolis:\n    def test_proposal_choice(self):\n        with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n            _, model, _ = mv_simple()\n            with model:\n                initial_point = model.initial_point()\n                initial_point_size = sum(initial_point[n.name].size for n in model.value_vars)\n\n                s = np.ones(initial_point_size)\n                sampler = Metropolis(S=s)\n                assert isinstance(sampler.proposal_dist, NormalProposal)\n                s = np.diag(s)\n                sampler = Metropolis(S=s)\n                assert isinstance(sampler.proposal_dist, MultivariateNormalProposal)\n                s[0, 0] = -s[0, 0]\n                with pytest.raises(np.linalg.LinAlgError):\n                    sampler = Metropolis(S=s)\n\n    def test_mv_proposal(self):\n        np.random.seed(42)\n        cov = np.random.randn(5, 5)\n        cov = cov.dot(cov.T)\n        prop = MultivariateNormalProposal(cov)\n        samples = np.array([prop() for _ in range(10000)])\n        npt.assert_allclose(np.cov(samples.T), cov, rtol=0.2)\n\n    def test_tuning_reset(self):\n        """Re-use of the step method instance with cores=1 must not leak tuning information between chains."""\n        with pm.Model() as pmodel:\n            D = 3\n            pm.Normal("n", 0, 2, size=(D,))\n            idata = pm.sample(\n                tune=600,\n                draws=500,\n                step=Metropolis(tune=True, scaling=0.1, rng=SEED),\n                cores=1,\n                chains=3,\n                discard_tuned_samples=False,\n            )\n        for c in idata.posterior.chain:\n            # check that the tuned settings changed and were reset\n            assert idata.warmup_sample_stats["scaling"].sel(chain=c).values[0] == 0.1\n            tuned = idata.warmup_sample_stats["scaling"].sel(chain=c).values[-1]\n            assert tuned != 0.1\n            np.testing.assert_array_equal(idata.sample_stats["scaling"].sel(chain=c).values, tuned)\n\n    @pytest.mark.parametrize(\n        "batched_dist",\n        (\n            pm.Binomial.dist(n=5, p=0.9),  # scalar case\n            pm.Binomial.dist(n=np.arange(40) + 1, p=np.linspace(0.1, 0.9, 40), shape=(40,)),\n            pm.Binomial.dist(\n                n=(np.arange(20) + 1)[::-1],\n                p=np.linspace(0.1, 0.9, 20),\n                shape=(\n                    2,\n                    20,\n                ),\n            ),\n            pm.Dirichlet.dist(a=np.ones(3) * (np.arange(40) + 1)[:, None], shape=(40, 3)),\n            pm.Dirichlet.dist(a=np.ones(3) * (np.arange(20) + 1)[:, None], shape=(2, 20, 3)),\n        ),\n    )\n    def test_elemwise_update(self, batched_dist):\n        with pm.Model() as m:\n            m.register_rv(batched_dist, name="batched_dist")\n            step = pm.Metropolis([batched_dist], rng=SEED)\n            assert step.elemwise_update == (batched_dist.ndim > 0)\n            trace = pm.sample(draws=1000, chains=2, step=step, random_seed=428)\n\n        assert az.rhat(trace).max()["batched_dist"].values < 1.1\n        assert az.ess(trace).min()["batched_dist"].values > 50\n\n    def test_elemwise_update_different_scales(self):\n        mu = [1, 2, 3, 4, 5, 100, 1_000, 10_000]\n        with pm.Model() as m:\n            x = pm.Poisson("x", mu=mu)\n            step = pm.Metropolis([x], rng=SEED)\n            trace = pm.sample(draws=1000, chains=2, step=step, random_seed=128).posterior\n\n        np.testing.assert_allclose(trace["x"].mean(("draw", "chain")), mu, rtol=0.1)\n        np.testing.assert_allclose(trace["x"].var(("draw", "chain")), mu, rtol=0.2)\n\n    def test_multinomial_no_elemwise_update(self):\n        with pm.Model() as m:\n            batched_dist = pm.Multinomial("batched_dist", n=5, p=np.ones(4) / 4, shape=(10, 4))\n            with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n                step = pm.Metropolis([batched_dist], rng=SEED)\n                assert not step.elemwise_update\n\n\nclass TestDEMetropolis:\n    def test_demcmc_tune_parameter(self):\n        """Tests that validity of the tune setting is checked"""\n        with pm.Model() as model:\n            pm.Normal("n", mu=0, sigma=1, size=(2, 3))\n\n            step = DEMetropolis()\n            assert step.tune == "scaling"\n\n            step = DEMetropolis(tune=None)\n            assert step.tune is None\n\n            step = DEMetropolis(tune="scaling")\n            assert step.tune == "scaling"\n\n            step = DEMetropolis(tune="lambda")\n            assert step.tune == "lambda"\n\n            with pytest.raises(ValueError):\n                DEMetropolis(tune="foo")\n\n\nclass TestDEMetropolisZ:\n    def test_tuning_lambda_sequential(self):\n        with pm.Model() as pmodel:\n            pm.Normal("n", 0, 2, size=(3,))\n            idata = pm.sample(\n                tune=1000,\n                draws=500,\n                step=DEMetropolisZ(tune="lambda", lamb=0.92, rng=SEED),\n                cores=1,\n                chains=3,\n                discard_tuned_samples=False,\n            )\n        for c in idata.posterior.chain:\n            # check that the tuned settings changed and were reset\n            assert idata.warmup_sample_stats["lambda"].sel(chain=c).values[0] == 0.92\n            tuned = idata.warmup_sample_stats["lambda"].sel(chain=c).values[-1]\n            assert tuned != 0.92\n            np.testing.assert_array_equal(idata.sample_stats["lambda"].sel(chain=c).values, tuned)\n\n    def test_tuning_epsilon_parallel(self):\n        with pm.Model() as pmodel:\n            pm.Normal("n", 0, 2, size=(3,))\n            idata = pm.sample(\n                tune=1000,\n                draws=500,\n                step=DEMetropolisZ(tune="scaling", scaling=0.002, rng=SEED),\n                cores=2,\n                chains=2,\n                discard_tuned_samples=False,\n            )\n        for c in idata.posterior.chain:\n            # check that the tuned settings changed and were reset\n            assert idata.warmup_sample_stats["scaling"].sel(chain=c).values[0] == 0.002\n            tuned = idata.warmup_sample_stats["scaling"].sel(chain=c).values[-1]\n            assert tuned != 0.002\n            np.testing.assert_array_equal(idata.sample_stats["scaling"].sel(chain=c).values, tuned)\n\n    def test_tuning_none(self):\n        with pm.Model() as pmodel:\n            pm.Normal("n", 0, 2, size=(3,))\n            idata = pm.sample(\n                tune=1000,\n                draws=500,\n                step=DEMetropolisZ(tune=None, rng=SEED),\n                cores=1,\n                chains=2,\n                discard_tuned_samples=False,\n            )\n        for c in idata.posterior.chain:\n            # check that all tunable parameters remained constant\n            assert len(set(idata.warmup_sample_stats["lambda"].sel(chain=c).values)) == 1\n            assert len(set(idata.warmup_sample_stats["scaling"].sel(chain=c).values)) == 1\n\n    def test_tuning_reset(self):\n        """Re-use of the step method instance with cores=1 must not leak tuning information between chains."""\n        with pm.Model() as pmodel:\n            D = 3\n            pm.Normal("n", 0, 2, size=(D,))\n            idata = pm.sample(\n                tune=1000,\n                draws=500,\n                step=DEMetropolisZ(tune="scaling", scaling=0.002, rng=SEED),\n                cores=1,\n                chains=3,\n                discard_tuned_samples=False,\n                random_seed=1,\n            )\n        for c in idata.posterior.chain:\n            # check that the tuned settings changed and were reset\n            warmup = idata.warmup_sample_stats["scaling"].sel(chain=c).values\n            assert warmup[0] == 0.002\n            assert warmup[-1] != 0.002\n            # check that the variance of the first 50 iterations is much lower than the last 100\n            samples = idata.warmup_posterior["n"].sel(chain=c).values\n            for d in range(D):\n                var_start = np.var(samples[:50, d])\n                var_end = np.var(samples[-100:, d])\n                assert var_start < 0.1 * var_end\n\n    def test_tune_drop_fraction(self):\n        tune = 300\n        tune_drop_fraction = 0.85\n        draws = 200\n        with pm.Model() as pmodel:\n            pm.Normal("n", 0, 2, size=(3,))\n            step = DEMetropolisZ(tune_drop_fraction=tune_drop_fraction, rng=SEED)\n            idata = pm.sample(\n                tune=tune, draws=draws, step=step, cores=1, chains=1, discard_tuned_samples=False\n            )\n            assert len(idata.warmup_posterior.draw) == tune\n            assert len(idata.posterior.draw) == draws\n            assert len(step._history) == (tune - tune * tune_drop_fraction) + draws\n\n    @pytest.mark.parametrize(\n        "variable,has_grad,outcome",\n        [("n", True, 1), ("n", False, 1), ("b", True, 0), ("b", False, 0)],\n    )\n    def test_competence(self, variable, has_grad, outcome):\n        with pm.Model() as pmodel:\n            pm.Normal("n", 0, 2, size=(3,))\n            pm.Binomial("b", n=2, p=0.3)\n        assert DEMetropolisZ.competence(pmodel[variable], has_grad=has_grad) == outcome\n\n    @pytest.mark.parametrize("tune_setting", ["foo", True, False])\n    def test_invalid_tune(self, tune_setting):\n        with pm.Model() as pmodel:\n            pm.Normal("n", 0, 2, size=(3,))\n            with pytest.raises(ValueError):\n                DEMetropolisZ(tune=tune_setting)\n\n    def test_custom_proposal_dist(self):\n        with pm.Model() as pmodel:\n            D = 3\n            pm.Normal("n", 0, 2, size=(D,))\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                trace = pm.sample(\n                    tune=100,\n                    draws=50,\n                    step=DEMetropolisZ(proposal_dist=NormalProposal),\n                    cores=1,\n                    chains=3,\n                    discard_tuned_samples=False,\n                )\n\n\nclass TestStepMetropolis(StepMethodTester):\n    def test_step_discrete(self):\n        start, model, (mu, C) = mv_simple_discrete()\n        unc = np.diag(C) ** 0.5\n        check = (("x", np.mean, mu, unc / 10.0), ("x", np.std, unc, unc / 10.0))\n        with model:\n            step = Metropolis(S=C, proposal_dist=MultivariateNormalProposal, rng=123456)\n            idata = pm.sample(\n                tune=1000,\n                draws=2000,\n                chains=1,\n                step=step,\n                initvals=start,\n                model=model,\n                random_seed=1,\n            )\n            self.check_stat(check, idata)\n            self.check_stat_dtype(idata, step)\n\n    @pytest.mark.parametrize("proposal", ["uniform", "proportional"])\n    def test_step_categorical(self, proposal):\n        start, model, (mu, C) = simple_categorical()\n        unc = C**0.5\n        check = (("x", np.mean, mu, unc / 10.0), ("x", np.std, unc, unc / 10.0))\n        with model:\n            step = CategoricalGibbsMetropolis([model.x], proposal=proposal, rng=SEED)\n            idata = pm.sample(\n                tune=1000,\n                draws=2000,\n                chains=1,\n                step=step,\n                initvals=start,\n                model=model,\n                random_seed=1,\n            )\n            self.check_stat(check, idata)\n            self.check_stat_dtype(idata, step)\n\n    @pytest.mark.parametrize(\n        "step_fn, draws",\n        [\n            (\n                lambda C, _: Metropolis(\n                    S=C, proposal_dist=MultivariateNormalProposal, blocked=True, rng=SEED\n                ),\n                4000,\n            ),\n        ],\n        ids=str,\n    )\n    def test_step_continuous(self, step_fn, draws):\n        self.step_continuous(step_fn, draws)\n\n\nclass TestRVsAssignmentMetropolis(RVsAssignmentStepsTester):\n    @pytest.mark.parametrize(\n        "step",\n        [\n            BinaryMetropolis,\n            BinaryGibbsMetropolis,\n            CategoricalGibbsMetropolis,\n        ],\n    )\n    def test_discrete_steps(self, step):\n        with pm.Model() as m:\n            d1 = pm.Bernoulli("d1", p=0.5)\n            d2 = pm.Bernoulli("d2", p=0.5)\n\n            # Test it can take initial_point, and compile_kwargs as a kwarg\n            step_kwargs = {\n                "initial_point": {\n                    "d1": np.array(0, dtype="int64"),\n                    "d2": np.array(1, dtype="int64"),\n                },\n                "compile_kwargs": {"mode": Mode(linker="py", optimizer=None)},\n            }\n            assert [m.rvs_to_values[d1]] == step([d1]).vars\n            assert {m.rvs_to_values[d1], m.rvs_to_values[d2]} == set(step([d1, d2]).vars)\n\n    @pytest.mark.parametrize(\n        "step, step_kwargs", [(Metropolis, {}), (DEMetropolis, {}), (DEMetropolisZ, {})]\n    )\n    def test_continuous_steps(self, step, step_kwargs):\n        self.continuous_steps(step, step_kwargs)\n\n\n@pytest.mark.parametrize(\n    ["step_method", "model_fn"],\n    [\n        [Metropolis, simple_model],\n        [BinaryMetropolis, simple_binary],\n        [BinaryGibbsMetropolis, simple_binary],\n        [CategoricalGibbsMetropolis, simple_categorical],\n        [DEMetropolis, simple_model],\n        [DEMetropolisZ, simple_model],\n    ],\n)\ndef test_sampling_state(step_method, model_fn):\n    with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n        initial_point, model, _ = model_fn()\n        with model:\n            sampler = step_method(model.value_vars)\n            if hasattr(sampler, "link_population"):\n                sampler.link_population([initial_point] * 100, 0)\n            sampler_orig = deepcopy(sampler)\n            state_orig = sampler_orig.sampling_state\n\n            sample1, stat1 = sampler.step(initial_point)\n            sampler.tune = False\n\n            final_state1 = sampler.sampling_state\n\n            assert not equal_sampling_states(final_state1, state_orig)\n\n            sampler.sampling_state = state_orig\n\n            assert equal_sampling_states(sampler.sampling_state, state_orig)\n\n            sample2, stat2 = sampler.step(initial_point)\n            sampler.tune = False\n\n            final_state2 = sampler.sampling_state\n\n            assert equal_sampling_states(final_state1, final_state2)\n            assert equal_dataclass_values(sample1, sample2)\n            assert equal_dataclass_values(stat1, stat2)\n',
        }
